function normalizeTamilOcrLookup(value: string): string {
  let s = String(value || "").toLowerCase();
  // Remove Unicode replacement characters
  s = s.replace(/\uFFFD/g, "");
  // Normalize separated vowel signs: move combining marks back to base character
  // Common Tamil vowel signs that get separated in OCR: ே  ோ  ை  ொ  ௌ  ௗ
  s = s.replace(/\u0BC7/g, "ே"); // keep as-is but ensure single char
  s = s.replace(/\u0BCB/g, "ோ");
  s = s.replace(/\u0BC8/g, "ை");
  s = s.replace(/\u0BCA/g, "ொ");
  s = s.replace(/\u0BCC/g, "ௌ");
  // Remove spaces between Tamil characters (common OCR artifact)
  s = s.replace(/([\u0B80-\u0BFF])\s+(?=[\u0B80-\u0BFF])/g, "$1");
  // Remove leading/trailing spaces around Tamil chars
  s = s.replace(/\s+([\u0B80-\u0BFF])/g, "$1");
  s = s.replace(/([\u0B80-\u0BFF])\s+/g, "$1");
  // Collapse multiple whitespace
  s = s.replace(/\s+/g, " ");
  // Remove all non-letter, non-number, non-Tamil characters
  s = s.replace(/[^\p{L}\p{N}]/gu, "");
  return s.trim();
}

function dedupeTamilTitles(values: string[] = []) {
  const seen = new Set<string>();
  return values.filter((value) => {
    const key = normalizeTamilOcrLookup(value || "");
    if (!key || seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}

function parseTamilAssessmentSectionsFromSource(sourceText: string) {
  const matches = Array.from(String(sourceText || "").matchAll(/section\s*[-–—]?\s*([a-e])\s*[-–—:]?\s*([^\n]+?)\s*(?:[-–—:]\s*)?(\d+)\s*marks/giu));
  const sections = matches.map((match, index) => {
    const rawTitle = String(match[2] || "").trim();
    const normalizedLabel = normalizeSourceText(rawTitle);
    const mapped = TAMIL_CBSE_SECTION_LABELS.find((candidate) =>
      candidate.aliases.some((alias) => normalizedLabel.includes(normalizeSourceText(alias)))
    );
    return {
      id: buildAssessmentSectionId(mapped?.title || rawTitle, index),
      title: mapped?.title || rawTitle,
      marks: Number(match[3] || 0),
      source: "assessment_framework" as const,
    };
  });
  return dedupeAssessmentSections(sections);
}

function isTamilIndexNoiseLine(line: string) {
  const normalized = normalizeSourceText(line || "");
  if (!normalized) return true;
  return (
    normalized === "viii" ||
    normalized === "ix" ||
    normalized.startsWith("page ") ||
    normalized.includes("மாதம்") ||
    normalized.includes("month") ||
    normalized.includes("june") ||
    normalized.includes("july") ||
    normalized.includes("august") ||
    normalized.includes("october") ||
    normalized.includes("january") ||
    normalized.includes("february")
  );
}

function parseTamilIndexUnitBlocks(indexText: string) {
  const lines = String(indexText || "")
    .split(/\r?\n/)
    .map((line) => line.trim())
    .filter(Boolean);
  const blocks: Array<{ unitNumber: number; lines: string[] }> = [];
  let current: { unitNumber: number; lines: string[] } | null = null;

  for (const line of lines) {
    if (isTamilIndexNoiseLine(line)) {
      continue;
    }
    const unitMatch = line.match(/^([1-7])\s+/);
    if (unitMatch) {
      if (current) blocks.push(current);
      current = {
        unitNumber: Number(unitMatch[1]),
        lines: [line],
      };
      continue;
    }
    if (current) {
      current.lines.push(line);
    }
  }

  if (current) blocks.push(current);
  return blocks;
}

function parseTamilIndexChaptersFromBlock(unitNumber: number, blockText: string) {
  const normalizedBlock = normalizeTamilOcrLookup(blockText);
  const template = TAMIL_IX_TEXTBOOK_INDEX_PATTERNS.find((item) => item.unitNumber === unitNumber);
  if (!template) return [];

  // First, try exact pattern matching as before
  const exactMatches = template.chapters
    .filter((chapter) => chapter.patterns.some((pattern) => normalizedBlock.includes(normalizeTamilOcrLookup(pattern))))
    .map((chapter) => chapter.title);

  if (exactMatches.length > 0) {
    return exactMatches;
  }

  // OCR-fallback: if no patterns matched but we know the unit number,
  // the OCR may be too corrupted to recognize specific chapter patterns.
  // Heuristic: if the cleaned text has at least some Tamil characters
  // but none of our patterns matched, emit all known chapters for this unit.
  // This ensures we don't return empty chapters for degraded OCR.
  const tamilCharCount = (normalizedBlock.match(/[\u0B80-\u0BFF]/g) || []).length;
  const totalChars = normalizedBlock.length;

  // If there's meaningful Tamil content (at least 3 Tamil chars or >20% of text)
  // but pattern matching failed, use OCR-fallback: return all known chapters
  if (tamilCharCount >= 3 || (totalChars > 0 && tamilCharCount / totalChars > 0.2)) {
    return template.chapters.map((chapter) => chapter.title);
  }

  return [];
}

function parseTamilTextbookIndexUnits(indexText: string, resolvedClassName: string) {
  const blocks = parseTamilIndexUnitBlocks(indexText);
  return blocks.map((block) => {
    const blockText = block.lines.join(" ");
    const mappedTheme =
      resolvedClassName === "Class IX"
        ? (TAMIL_IX_UNIT_THEME_MAP.get(block.unitNumber) || "")
        : "";
    const chapters = dedupeTamilTitles(parseTamilIndexChaptersFromBlock(block.unitNumber, blockText));
    const fallbackThemeCandidate = block.lines[0]
      .replace(/^([1-7])\s+/, "")
      .replace(/\d+.*$/, "")
      .trim();
    const theme = mappedTheme || fallbackThemeCandidate || `Iyal ${block.unitNumber}`;
    return {
      unitNumber: block.unitNumber,
      theme,
      chapters,
      rawBlockText: blockText,
    };
  }).filter((unit) => unit.unitNumber >= 1 && unit.unitNumber <= 7);
}

function extractAcademicYearFromCurriculumText(sourceText: string, fileName: string = "") {
  const sample = `${String(sourceText || "").slice(0, 4000)}\n${String(fileName || "")}`;
  const yearMatch = sample.match(/\b(20\d{2}\s*[-–]\s*(?:20)?\d{2,4})\b/);
  if (yearMatch?.[1]) {
    return yearMatch[1].replace(/\s+/g, " ").trim();
  }

  const singleYearMatch = sample.match(/\b(20\d{2})\b/);
  return singleYearMatch?.[1] || "";
}

function extractTamilBoardFromSource(sourceText: string) {
  const match = String(sourceText || "").match(/State Council of Educational Research and Training[^\n]*/i);
  if (match?.[0]) {
    return match[0].replace(/\s+/g, " ").trim();
  }

  if (/Tamilnadu Arasu|Tamil Nadu Arasu/i.test(sourceText || "")) {
    return "Tamil Nadu Arasu";
  }

  return "";
}

function getSupportingDocumentText(
  supportingDocuments: SupportingCurriculumDocument[] = [],
  roles: SupportingCurriculumDocumentRole[]
) {
  const allowed = new Set(roles);
  return supportingDocuments
    .filter((document) => allowed.has(document.role))
    .map((document) => document.text || "")
    .filter(Boolean)
    .join("\n\n");
}

function isLikelyTamilStructureNoiseLine(line: string) {
  const normalized = normalizeSourceText(line || "");
  if (!normalized) return true;
  return (
    normalized.startsWith("page ") ||
    normalized.includes("previewurl") ||
    normalized.includes("artifacturl") ||
    normalized.includes("mime type") ||
    normalized.includes("mimeType".toLowerCase()) ||
    normalized.includes("identifier") ||
    normalized.includes("content id") ||
    normalized === "tamil" ||
    normalized === "cbse"
  );
}

function parseTamilIyalNumberFromText(line: string): number | null {
  const match = String(line || "").match(/(?:^|\b)(?:iyal|இயல்)\s*[-:]?\s*([1-9]\d*)/i);
  return match?.[1] ? Number(match[1]) : null;
}

function buildTamilStructureDigest(
  structureText: string,
  options: { className: string; subject?: string; title?: string } = { className: "Class IX", subject: "Tamil", title: "Tamil Textbook Structure" }
): SunbirdStructureDigest | null {
  const lines = String(structureText || "")
    .split(/\r?\n/)
    .map((line) => line.trim())
    .filter((line) => line && !isLikelyTamilStructureNoiseLine(line));
  if (!lines.length) return null;

  const unit_candidates: SunbirdStructureDigest["unit_candidates"] = [];
  const chapter_candidates: SunbirdStructureDigest["chapter_candidates"] = [];
  const topic_candidates: SunbirdStructureDigest["topic_candidates"] = [];
  const subtopic_candidates: SunbirdStructureDigest["subtopic_candidates"] = [];
  const source_refs: string[] = [];
  let currentUnitNumber: number | null = null;
  let currentChapterName = "";
  let currentTopicName = "";

  for (const rawLine of lines) {
    const line = rawLine.replace(/\s+/g, " ").trim();
    if (!line) continue;
    const parsedUnitNumber = parseTamilIyalNumberFromText(line);
    if (parsedUnitNumber != null) {
      currentUnitNumber = parsedUnitNumber;
      currentChapterName = "";
      currentTopicName = "";
      unit_candidates.push({
        unit_name: line,
        unit_number: parsedUnitNumber,
        source_ref: line,
      });
      source_refs.push(line);
      continue;
    }

    if (/^(chapter|lesson|பாடம்|கவிதை|உரைநடை|இலக்கணம்|கட்டுரை)\s*[:\-]/i.test(line)) {
      const chapterName = line.replace(/^(chapter|lesson|பாடம்|கவிதை|உரைநடை|இலக்கணம்|கட்டுரை)\s*[:\-]\s*/i, "").trim();
      if (chapterName) {
        currentChapterName = chapterName;
        currentTopicName = "";
        chapter_candidates.push({
          chapter_name: chapterName,
          unit_number: currentUnitNumber,
          source_ref: line,
        });
        continue;
      }
    }

    if (/^(topic|heading|section|தலைப்பு|பிரிவு)\s*[:\-]/i.test(line)) {
      const topicName = line.replace(/^(topic|heading|section|தலைப்பு|பிரிவு)\s*[:\-]\s*/i, "").trim();
      if (topicName) {
        currentTopicName = topicName;
        topic_candidates.push({
          chapter_name: currentChapterName || undefined,
          topic_name: topicName,
          unit_number: currentUnitNumber,
          source_ref: line,
        });
        continue;
      }
    }

    if (/^(subtopic|sub-topic|sub heading|துணைத்தலைப்பு|உட்தலைப்பு)\s*[:\-]/i.test(line)) {
      const subtopicName = line.replace(/^(subtopic|sub-topic|sub heading|துணைத்தலைப்பு|உட்தலைப்பு)\s*[:\-]\s*/i, "").trim();
      if (subtopicName) {
        subtopic_candidates.push({
          chapter_name: currentChapterName || undefined,
          topic_name: currentTopicName || undefined,
          subtopic_name: subtopicName,
          unit_number: currentUnitNumber,
          source_ref: line,
        });
        continue;
      }
    }

    if (line.length <= 120 && /[அ-ஹ]/.test(line) && !currentChapterName) {
      currentChapterName = line;
      chapter_candidates.push({
        chapter_name: line,
        unit_number: currentUnitNumber,
        source_ref: line,
      });
      continue;
    }

    if (line.length <= 140 && currentChapterName && !currentTopicName) {
      currentTopicName = line;
      topic_candidates.push({
        chapter_name: currentChapterName,
        topic_name: line,
        unit_number: currentUnitNumber,
        source_ref: line,
      });
      continue;
    }

    if (line.length <= 160 && currentChapterName) {
      subtopic_candidates.push({
        chapter_name: currentChapterName,
        topic_name: currentTopicName || undefined,
        subtopic_name: line,
        unit_number: currentUnitNumber,
        source_ref: line,
      });
    }
  }

  return {
    class_name: options.className,
    subject: options.subject || "Tamil",
    title: options.title || "Tamil Textbook Structure",
    unit_candidates,
    chapter_candidates,
    topic_candidates,
    subtopic_candidates,
    source_refs: uniqueStrings(source_refs),
  };
}

function findTamilChapterBestMatch(chapterName: string, sourceCandidates: string[], _allowedUnitNumber?: number | null) {
  const normalizedTarget = normalizeTamilOcrLookup(chapterName);
  const exact = sourceCandidates.find((candidate) => normalizeTamilOcrLookup(candidate) === normalizedTarget);
  if (exact) {
    return { match: exact, confidence: "exact" as const };
  }

  const fuzzyCandidates = sourceCandidates.filter((candidate) => {
    const normalizedCandidate = normalizeTamilOcrLookup(candidate);
    return normalizedCandidate.includes(normalizedTarget) || normalizedTarget.includes(normalizedCandidate);
  });

  if (fuzzyCandidates.length === 1) {
    return { match: fuzzyCandidates[0], confidence: "fuzzy" as const };
  }

  return { match: "", confidence: "none" as const };
}

function enrichTamilStage1FactsWithStructure(
  stage1Facts: any,
  structureDocuments: SupportingCurriculumDocument[] = [],
  options: { className: string } = { className: "Class IX" }
) {
  const structureText = getSupportingDocumentText(structureDocuments, ["textbook_structure", "sunbird_textbook_structure"]);
  const digest = buildTamilStructureDigest(structureText, {
    className: options.className,
    subject: "Tamil",
    title: "Tamil Textbook Structure",
  });

  const metadata = {
    structureDigestGenerated: Boolean(digest),
    matchedChapters: 0,
    unmatchedChapters: [] as string[],
    topicAdds: 0,
    subtopicAdds: 0,
  };

  if (!digest) {
    return { stage1Facts, metadata, digest: null };
  }

  const nextStage1Facts = structuredClone(stage1Facts || {});
  const chapters = Array.isArray(nextStage1Facts?.chapters) ? nextStage1Facts.chapters : [];
  const chapterNames = chapters.map((chapter: any) => chapter.chapter_name || "").filter(Boolean);
  const chapterMap = new Map<string, any>();
  chapters.forEach((chapter: any) => {
    chapterMap.set(chapter.chapter_name, chapter);
    if (!Array.isArray(chapter.topics)) chapter.topics = [];
    if (!Array.isArray(chapter.subtopics)) chapter.subtopics = [];
    if (!Array.isArray(chapter.key_concepts)) chapter.key_concepts = [];
  });

  const topicChapterMap = new Map<string, string>();
  for (const candidate of digest.chapter_candidates) {
    const matched = findTamilChapterBestMatch(candidate.chapter_name, chapterNames, candidate.unit_number);
    if (!matched.match) {
      metadata.unmatchedChapters.push(candidate.chapter_name);
      continue;
    }
    metadata.matchedChapters += 1;
    topicChapterMap.set(candidate.chapter_name, matched.match);
  }

  for (const topicCandidate of digest.topic_candidates) {
    const targetChapterName =
      (topicCandidate.chapter_name && topicChapterMap.get(topicCandidate.chapter_name)) ||
      (topicCandidate.chapter_name && findTamilChapterBestMatch(topicCandidate.chapter_name, chapterNames, topicCandidate.unit_number).match) ||
      "";
    if (!targetChapterName) continue;
    const chapter = chapterMap.get(targetChapterName);
    if (!chapter) continue;
    chapter.topics = uniqueStrings([...(chapter.topics || []), topicCandidate.topic_name]);
    chapter.key_concepts = uniqueStrings([...(chapter.key_concepts || []), topicCandidate.topic_name]);
    metadata.topicAdds += 1;
  }

  for (const subtopicCandidate of digest.subtopic_candidates) {
    const targetChapterName =
      (subtopicCandidate.chapter_name && topicChapterMap.get(subtopicCandidate.chapter_name)) ||
      (subtopicCandidate.chapter_name && findTamilChapterBestMatch(subtopicCandidate.chapter_name, chapterNames, subtopicCandidate.unit_number).match) ||
      "";
    if (!targetChapterName) continue;
    const chapter = chapterMap.get(targetChapterName);
    if (!chapter) continue;
    if (subtopicCandidate.topic_name) {
      chapter.topics = uniqueStrings([...(chapter.topics || []), subtopicCandidate.topic_name]);
    }
    chapter.subtopics = uniqueStrings([...(chapter.subtopics || []), subtopicCandidate.subtopic_name]);
    metadata.subtopicAdds += 1;
  }

  const units = Array.isArray(nextStage1Facts?.units) ? nextStage1Facts.units : [];
  units.forEach((unit: any) => {
    const relatedChapters = chapters.filter((chapter: any) => chapter.unit_id === unit.unit_id);
    unit.topics = uniqueStrings(relatedChapters.flatMap((chapter: any) => chapter.topics || []));
    unit.subtopics = uniqueStrings(relatedChapters.flatMap((chapter: any) => chapter.subtopics || []));
    unit.key_concepts = uniqueStrings(relatedChapters.flatMap((chapter: any) => chapter.key_concepts || []));
  });

  return {
    stage1Facts: nextStage1Facts,
    metadata: {
      ...metadata,
      unmatchedChapters: uniqueStrings(metadata.unmatchedChapters),
    },
    digest,
  };
}

function buildTamilFastStage1Facts(
  primarySourceText: string,
  fileName: string,
  options: {
    selectedClassNames?: string[];
    supportingDocuments?: SupportingCurriculumDocument[];
  } = {}
) {
  const selectedClassName = canonicalizeClassName((options.selectedClassNames || [])[0] || "");
  const detectedPrimaryClasses = detectCurriculumClassSegmentsFromSource(primarySourceText || "")
    .map((segment) => canonicalizeClassName(segment.className || ""))
    .filter(Boolean);
  const resolvedClassName =
    selectedClassName ||
    detectedPrimaryClasses[0] ||
    "Class IX";
  const textbookIndexText = getSupportingDocumentText(options.supportingDocuments || [], ["textbook_index"]);
  const textbookUnits = parseTamilTextbookIndexUnits(textbookIndexText, resolvedClassName);
  const assessmentSections = parseTamilAssessmentSectionsFromSource(primarySourceText || "");

  if (!textbookUnits.length && !assessmentSections.length) {
    return null;
  }

  const marksDistribution = assessmentSections.map((section) => `${section.title} - ${section.marks} Marks`);
  // Map Iyal units to CBSE "Main Course Book" section
  const cbseSectionName = "Main Course Book";
  const units = textbookUnits.map((unit) => ({
    class_name: resolvedClassName,
    subject: "Tamil",
    part_or_section: cbseSectionName,
    unit_id: `U${unit.unitNumber}`,
    unit_name: `Iyal ${unit.unitNumber} - ${unit.theme}`,
    marks: null,
    topics: [],
    subtopics: [],
    key_concepts: [],
  }));
  const chapters = textbookUnits.flatMap((unit) =>
    unit.chapters.map((chapterName) => ({
      class_name: resolvedClassName,
      subject: "Tamil",
      part_or_section: cbseSectionName,
      unit_id: `U${unit.unitNumber}`,
      unit_name: `Iyal ${unit.unitNumber} - ${unit.theme}`,
      chapter_name: chapterName,
      marks: null,
      topics: [],
      subtopics: [],
      key_concepts: [],
    }))
  );

  const stage1Facts = {
    document_metadata: {
      board: extractTamilBoardFromSource(primarySourceText),
      subject: "Tamil",
      class: resolvedClassName,
      grade: resolvedClassName,
      stream: "",
      academic_year: extractAcademicYearFromCurriculumText(primarySourceText, fileName),
      total_pages: deriveDocumentPageCount(primarySourceText),
    },
    classes: [{
      class_name: resolvedClassName,
      subject: "Tamil",
      part_or_section: cbseSectionName,
    }],
    units,
    chapters,
    assessment_information: {
      marks_distribution: marksDistribution,
      cbse_sections: assessmentSections.map((section) => ({
        title: section.title,
        marks: section.marks,
      })),
      excluded_or_non_assessed_content: [],
      teacher_notes: [],
    },
  };

  return enrichTamilStage1FactsWithStructure(stage1Facts, options.supportingDocuments || [], {
    className: resolvedClassName,
  }).stage1Facts;
}

function hardenTamilStage1Facts(
  stage1Facts: any,
  options: {
    primarySourceText: string;
    selectedClassNames?: string[];
    supportingDocuments?: SupportingCurriculumDocument[];
  }
) {
  const selectedClassName = canonicalizeClassName((options.selectedClassNames || [])[0] || "");
  const detectedPrimaryClasses = detectCurriculumClassSegmentsFromSource(options.primarySourceText || "")
    .map((segment) => canonicalizeClassName(segment.className || ""))
    .filter(Boolean);
  const resolvedClassName =
    selectedClassName ||
    detectedPrimaryClasses[0] ||
    canonicalizeClassName(stage1Facts?.document_metadata?.class || "") ||
    canonicalizeClassName(stage1Facts?.classes?.[0]?.class_name || "") ||
    "Class IX";
  const textbookIndexText = getSupportingDocumentText(options.supportingDocuments || [], ["textbook_index"]);
  const textbookUnits = parseTamilTextbookIndexUnits(textbookIndexText, resolvedClassName);
  const assessmentSections = parseTamilAssessmentSectionsFromSource(options.primarySourceText || "");

  if (!textbookUnits.length && !assessmentSections.length) {
    return {
      stage1Facts,
      metadata: {
        tamilNormalizationApplied: false,
        resolvedClassName,
        recoveredTextbookUnitCount: 0,
        dedupedAssessmentSectionCount: 0,
      },
    };
  }

  const cbseSectionName = "Main Course Book";
  const units = textbookUnits.map((unit) => ({
    class_name: resolvedClassName,
    subject: "Tamil",
    part_or_section: cbseSectionName,
    unit_id: `U${unit.unitNumber}`,
    unit_name: `Iyal ${unit.unitNumber} - ${unit.theme}`,
    marks: null,
    topics: [],
    subtopics: [],
    key_concepts: [],
  }));
  const chapters = textbookUnits.flatMap((unit) =>
    unit.chapters.map((chapterName) => ({
      class_name: resolvedClassName,
      subject: "Tamil",
      part_or_section: cbseSectionName,
      unit_id: `U${unit.unitNumber}`,
      unit_name: `Iyal ${unit.unitNumber} - ${unit.theme}`,
      chapter_name: chapterName,
      marks: null,
      topics: [],
      subtopics: [],
      key_concepts: [],
    }))
  );

  let nextStage1Facts = {
    ...stage1Facts,
    document_metadata: {
      ...(stage1Facts?.document_metadata || {}),
      subject: "Tamil",
      class: resolvedClassName,
      grade: resolvedClassName,
    },
    classes: [{
      class_name: resolvedClassName,
      subject: "Tamil",
      part_or_section: cbseSectionName,
    }],
    units,
    chapters,
    assessment_information: {
      ...(stage1Facts?.assessment_information || {}),
      marks_distribution: assessmentSections.map((section) => `${section.title} - ${section.marks} Marks`),
      cbse_sections: assessmentSections.map((section) => ({
        title: section.title,
        marks: section.marks,
      })),
    },
  };
  const structureEnrichment = enrichTamilStage1FactsWithStructure(nextStage1Facts, options.supportingDocuments || [], {
    className: resolvedClassName,
  });
  nextStage1Facts = structureEnrichment.stage1Facts;

  return {
    stage1Facts: nextStage1Facts,
    metadata: {
      tamilNormalizationApplied: true,
      resolvedClassName,
      recoveredTextbookUnitCount: textbookUnits.length,
      dedupedAssessmentSectionCount: assessmentSections.length,
      structureDigestGenerated: structureEnrichment.metadata.structureDigestGenerated,
      structureMatchedChapters: structureEnrichment.metadata.matchedChapters,
      structureTopicAdds: structureEnrichment.metadata.topicAdds,
      structureSubtopicAdds: structureEnrichment.metadata.subtopicAdds,
      structureUnmatchedChapters: structureEnrichment.metadata.unmatchedChapters,
    },
  };
}

function inferSubjectIntelligenceContextFromReplacements(replacements: Record<string, string>) {
  return {
    subject: [
      replacements.SUBJECT,
      replacements.subject,
    ].filter(Boolean).join(" "),
    sourceText: [
      replacements.SOURCE_TEXT,
      replacements.SESSION_JSON,
      replacements.STAGE_PAYLOAD_JSON,
      replacements.RAW_CLASS_JSON,
      replacements.STRUCTURE_CLASS_JSON,
      replacements.NORMALIZED_STRUCTURE_JSON,
      replacements.COMPETENCIES_JSON,
      replacements.ASSESSMENT_JSON,
      replacements.OUTCOMES_JSON,
      replacements.ACTIVITIES_JSON,
      replacements.SELECTED_CHAPTERS_JSON,
      replacements.LEARNING_OUTCOMES_JSON,
    ].filter(Boolean).join("\n"),
    fileName: replacements.FILE_NAME || "",
  };
}

function buildSubjectIntelligenceLayers(
  replacements: Record<string, string>,
  options: {
    englishMode?: boolean;
    scienceMode?: boolean;
    stageLabel?: string;
    englishLayerText?: string;
  } = {}
) {
  const layers: string[] = [];
  if (options.englishMode) {
    layers.push([
      "# English Subject Intelligence Layer (Active)",
      options.stageLabel
        ? `Apply this English subject intelligence while completing: ${options.stageLabel}.`
        : "Apply this English subject intelligence while completing the task below.",
      "",
      options.englishLayerText || getEnglishIntelligenceLayerText(),
    ].join("\n"));
  }

  const inferredContext = inferSubjectIntelligenceContextFromReplacements(replacements);
  const scienceMode = typeof options.scienceMode === "boolean"
    ? options.scienceMode
    : shouldUseScienceIntelligence(inferredContext);
  if (scienceMode) {
    layers.push([
      "# Science Subject Intelligence Layer (Active)",
      options.stageLabel
        ? `Apply this Science subject intelligence while completing: ${options.stageLabel}.`
        : "Apply this Science subject intelligence while completing the task below.",
      "",
      getScienceIntelligenceLayerText(),
    ].join("\n"));
  }

  return layers;
}

function buildScienceArtifactGenerationLayer(
  promptName: string,
  replacements: Record<string, string>,
  options: {
    scienceMode?: boolean;
    stageLabel?: string;
  } = {}
) {
  const inferredContext = inferSubjectIntelligenceContextFromReplacements(replacements);
  const scienceMode = typeof options.scienceMode === "boolean"
    ? options.scienceMode
    : shouldUseScienceIntelligence(inferredContext);
  if (!scienceMode) {
    return "";
  }

  const metadata = buildScienceGenerationMetadata(promptName, replacements);
  if (!metadata) {
    return "";
  }

  const promptNameByArtifact: Record<ScienceGenerationArtifact, string> = {
    session_package: SCIENCE_GENERATION_SESSION_PROMPT_NAME,
    teacher_notes: SCIENCE_GENERATION_TEACHER_PROMPT_NAME,
    student_notes: SCIENCE_GENERATION_STUDENT_PROMPT_NAME,
    ppt_materials: UNIVERSAL_PPT_PROMPT_NAME,
    homework: SCIENCE_GENERATION_HOMEWORK_PROMPT_NAME,
    assessment: SCIENCE_GENERATION_ASSESSMENT_PROMPT_NAME,
  };

  return [
    "# Science Generation Policy Layer (Active)",
    options.stageLabel
      ? `Apply this science generation policy while completing: ${options.stageLabel}.`
      : "Apply this science generation policy while completing the task below.",
    "",
    "Science session profile:",
    JSON.stringify(metadata, null, 2),
    "",
    getScienceGenerationLayerText(SCIENCE_GENERATION_SHARED_PROMPT_NAME),
    "",
    getScienceGenerationLayerText(promptNameByArtifact[metadata.scienceArtifact]),
  ].join("\n");
}

function renderPromptWithEnglishIntelligence(
  promptName: string,
  replacements: Record<string, string>,
  options: { englishMode?: boolean; scienceMode?: boolean; stageLabel?: string } = {}
): string {
  const subjectIntelligenceLayers = buildSubjectIntelligenceLayers(replacements, {
    englishMode: options.englishMode,
    scienceMode: options.scienceMode,
    stageLabel: options.stageLabel,
    englishLayerText: getEnglishIntelligenceLayerText(),
  });
  const injectedLayerText = subjectIntelligenceLayers.join("\n\n");

  const rendered = renderPrompt(promptName, {
    ...replacements,
    ENGLISH_INTELLIGENCE_LAYER: injectedLayerText,
    SCIENCE_INTELLIGENCE_LAYER: injectedLayerText,
  });

  if (injectedLayerText && !rendered.includes(injectedLayerText)) {
    return `${injectedLayerText}\n\n${rendered}`;
  }

  return rendered;
}

function renderPromptWithEnglishDownstreamIntelligence(
  promptName: string,
  replacements: Record<string, string>,
  options: { englishMode?: boolean; scienceMode?: boolean; stageLabel?: string } = {}
): string {
  const subjectIntelligenceLayers = buildSubjectIntelligenceLayers(replacements, {
    englishMode: options.englishMode,
    scienceMode: options.scienceMode,
    stageLabel: options.stageLabel,
    englishLayerText: getEnglishDownstreamIntelligenceLayerText(),
  });
  const scienceArtifactLayer = buildScienceArtifactGenerationLayer(promptName, replacements, {
    scienceMode: options.scienceMode,
    stageLabel: options.stageLabel,
  });
  const injectedLayerText = [...subjectIntelligenceLayers, scienceArtifactLayer].filter(Boolean).join("\n\n");

  const rendered = renderPrompt(promptName, {
    ...replacements,
    ENGLISH_INTELLIGENCE_LAYER: injectedLayerText,
    SCIENCE_INTELLIGENCE_LAYER: injectedLayerText,
  });

  if (injectedLayerText && !rendered.includes(injectedLayerText)) {
    return `${injectedLayerText}\n\n${rendered}`;
  }

  return rendered;
}

function renderStage1PromptWithCurriculumIntelligence(
  promptName: string,
  replacements: Record<string, string>,
  options: { englishMode?: boolean; scienceMode?: boolean; tamilMode?: boolean; stageLabel?: string } = {}
): string {
  const rendered = renderPromptWithEnglishIntelligence(promptName, replacements, {
    englishMode: options.englishMode,
    scienceMode: options.scienceMode,
    stageLabel: options.stageLabel,
  });

  if (!options.tamilMode) {
    return rendered;
  }

  const tamilLayer = [
    "# Tamil Curriculum Multi-Source Intelligence Layer (Active)",
    options.stageLabel
      ? `Apply this Tamil curriculum intelligence while completing: ${options.stageLabel}.`
      : "Apply this Tamil curriculum intelligence while completing the task below.",
    "",
    getTamilCurriculumIntelligenceLayerText(),
  ].join("\n");

  return rendered.includes(tamilLayer)
    ? rendered
    : `${tamilLayer}\n\n${rendered}`;
}

function countWholeWordOccurrences(haystack: string, needle: string) {
  if (!haystack || !needle) return 0;
  const escapedNeedle = needle.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  const matches = haystack.match(new RegExp(`(^|\\s)${escapedNeedle}(?=\\s|$)`, "g"));
  return matches?.length || 0;
}

function detectSubjectFromNormalizedSamples(samples: string[]) {
  const normalizedSamples = samples
    .map((sample) => normalizeSourceText(sample || ""))
    .filter(Boolean);
  if (!normalizedSamples.length) return "";

  for (const sample of normalizedSamples) {
    const exactMatch = CURRICULUM_SUBJECT_ALIAS_GROUPS.find(({ aliases }) =>
      aliases.some((alias) => sample === alias || sample.startsWith(`${alias} `) || sample.includes(` ${alias} `))
    );
    if (exactMatch) {
      return exactMatch.subject;
    }
  }

  const combinedSample = normalizedSamples.join(" ");
  let bestMatch: { subject: string; score: number; aliasLength: number } | null = null;
  for (const group of CURRICULUM_SUBJECT_ALIAS_GROUPS) {
    const score = group.aliases.reduce((sum, alias) => sum + countWholeWordOccurrences(combinedSample, alias), 0);
    if (!score) continue;
    const aliasLength = Math.max(...group.aliases.map((alias) => alias.length));
    if (
      !bestMatch ||
      score > bestMatch.score ||
      (score === bestMatch.score && aliasLength > bestMatch.aliasLength)
    ) {
      bestMatch = {
        subject: group.subject,
        score,
        aliasLength,
      };
    }
  }

  return bestMatch?.subject || "";
}

function detectCurriculumSubjectFromInput(sourceText: string, fileName = ""): string {
  const sampleText = String(sourceText || "").slice(0, 12000);
  const sampleFileName = String(fileName || "");
  const explicitSubjectLine = sampleText.match(/^\s*subject\s*[:\-]\s*(.+)$/im)?.[1] || "";
  const normalizedSample = normalizeSourceText([sampleFileName, sampleText].join("\n"));
  const normalizedSubjectLine = normalizeSourceText(canonicalizeSubjectName(explicitSubjectLine));

  if (normalizedSubjectLine) {
    if (isEnglishSubject(normalizedSubjectLine)) return "English";
    const inferredIndicSubject = inferIndicFallbackSubject(normalizedSubjectLine, sampleFileName);
    if (inferredIndicSubject) return inferredIndicSubject;
    const subjectLineMatch = detectSubjectFromNormalizedSamples([normalizedSubjectLine]);
    if (subjectLineMatch) return subjectLineMatch;
    return canonicalizeSubjectName(explicitSubjectLine);
  }

  const leadingLines = sampleText
    .split(/\r?\n/)
    .map((line) => line.replace(/^#+\s*/, "").trim())
    .filter(Boolean)
    .slice(0, 20);
  const headingMatch = detectSubjectFromNormalizedSamples([
    sampleFileName,
    ...leadingLines,
  ]);
  if (headingMatch) {
    return headingMatch;
  }

  if (shouldUseEnglishIntelligence({ sourceText: sampleText, fileName: sampleFileName })) {
    return "English";
  }

  const inferredIndicSubject = inferIndicFallbackSubject(sampleText, sampleFileName);
  if (inferredIndicSubject) {
    return inferredIndicSubject;
  }

  return detectSubjectFromNormalizedSamples([normalizedSample]);
}

function requiresTamilTextbookIndexFromInput(sourceText: string, fileName = ""): boolean {
  return isTamilCurriculumSubject(detectCurriculumSubjectFromInput(sourceText, fileName));
}

function isEnglishExamSectionLabel(value: string): boolean {
  const normalized = normalizeSourceText(value || "");
  if (!normalized) return false;
  return ENGLISH_EXAM_SECTION_LABELS.some((candidate) => normalized.includes(candidate));
}

function isEnglishContainerLabel(value: string): boolean {
  const normalized = normalizeSourceText(value || "");
  if (!normalized) return false;
  return ENGLISH_CONTAINER_LABELS.some((candidate) => normalized === candidate || normalized.includes(candidate));
}

function isLikelyEnglishLessonTitleCandidate(value: string): boolean {
  const trimmed = String(value || "").trim();
  const normalized = normalizeSourceText(trimmed);
  if (!trimmed || trimmed.length < 4) return false;
  if (isEnglishExamSectionLabel(trimmed) || isEnglishContainerLabel(trimmed)) return false;
  if (/\b(class|section|unit|chapter|grammar|writing|reading|literature|assessment|question paper|marks)\b/i.test(normalized)) {
    return false;
  }
  return /[a-z]/i.test(trimmed);
}

function isEnglishAssessmentOnlyChapterLabel(value: string): boolean {
  const normalized = normalizeSourceText(value || "");
  if (!normalized) return false;
  return ENGLISH_ASSESSMENT_ONLY_CHAPTER_LABELS.some((candidate) => normalized === candidate || normalized.includes(candidate));
}

function buildEnglishPromotedChapter(
  chapterName: string,
  context: {
    partOrSection?: string;
    bookName?: string;
    categoryName?: string;
  }
) {
  const examSectionName = isEnglishExamSectionLabel(context.partOrSection || "") ? String(context.partOrSection || "").trim() : "";
  const bookName = !examSectionName ? String(context.bookName || "").trim() : String(context.bookName || "").trim();
  const categoryName = String(context.categoryName || "").trim();
  return {
    chapter_name: stripInternalParserLabel(chapterName),
    source_chapter_name: stripInternalParserLabel(chapterName),
    part_or_section: String(context.partOrSection || "").trim(),
    exam_section_name: examSectionName,
    book_name: bookName,
    category_name: categoryName,
    structure_role: "chapter",
    content_path: [examSectionName, bookName, categoryName, chapterName].filter(Boolean).join(" > "),
    topics: [],
    subtopics: [],
    key_concepts: [],
  };
}

function normalizeEnglishChapterDetailsForUnit({
  unitName,
  partOrSection,
  unitTopics,
  unitSubtopics,
  chapterDetails,
}: {
  unitName: string;
  partOrSection: string;
  unitTopics: string[];
  unitSubtopics: string[];
  chapterDetails: any[];
}) {
  const normalizedUnitName = String(unitName || "").trim();
  const normalizedPartOrSection = String(partOrSection || "").trim();
  const unitLooksLikeContainer = isEnglishContainerLabel(normalizedUnitName);
  const partLooksLikeExamSection = isEnglishExamSectionLabel(normalizedPartOrSection);
  const inferredBookName = !partLooksLikeExamSection && normalizedPartOrSection ? normalizedPartOrSection : "";

  if ((!chapterDetails || chapterDetails.length === 0) && unitLooksLikeContainer) {
    const promotedTitles = uniqueStrings([...(unitTopics || []), ...(unitSubtopics || [])]).filter(isLikelyEnglishLessonTitleCandidate);
    if (promotedTitles.length >= 2) {
      return promotedTitles.map((title) =>
        buildEnglishPromotedChapter(title, {
          partOrSection: normalizedPartOrSection,
          bookName: inferredBookName,
          categoryName: normalizedUnitName,
        })
      );
    }
  }

  if (!Array.isArray(chapterDetails) || chapterDetails.length === 0) {
    return chapterDetails;
  }

  const promotedChapterDetails: any[] = [];
  let promotedAnyChapter = false;

  for (const chapter of chapterDetails) {
    const chapterName = String(chapter?.chapter_name || chapter?.source_chapter_name || "").trim();
    const chapterTitles = uniqueStrings([...(chapter?.topics || []), ...(chapter?.subtopics || [])]).filter(isLikelyEnglishLessonTitleCandidate);
    if (isEnglishContainerLabel(chapterName) && chapterTitles.length > 0) {
      promotedAnyChapter = true;
      for (const title of chapterTitles) {
        promotedChapterDetails.push({
          ...buildEnglishPromotedChapter(title, {
            partOrSection: String(chapter?.part_or_section || normalizedPartOrSection || "").trim(),
            bookName: unitLooksLikeContainer ? inferredBookName : normalizedUnitName,
            categoryName: chapterName,
          }),
          key_concepts: uniqueStrings(chapter?.key_concepts || []),
        });
      }
      continue;
    }

    promotedChapterDetails.push({
      ...chapter,
      part_or_section: String(chapter?.part_or_section || normalizedPartOrSection || "").trim(),
      exam_section_name: isEnglishExamSectionLabel(chapter?.part_or_section || normalizedPartOrSection || "")
        ? String(chapter?.part_or_section || normalizedPartOrSection || "").trim()
        : "",
      book_name: unitLooksLikeContainer ? inferredBookName : normalizedUnitName,
      category_name: unitLooksLikeContainer ? normalizedUnitName : "",
      structure_role: isEnglishContainerLabel(chapterName) ? "category" : "chapter",
      content_path: [
        isEnglishExamSectionLabel(chapter?.part_or_section || normalizedPartOrSection || "")
          ? String(chapter?.part_or_section || normalizedPartOrSection || "").trim()
          : "",
        unitLooksLikeContainer ? inferredBookName : normalizedUnitName,
        unitLooksLikeContainer ? normalizedUnitName : "",
        chapterName,
      ].filter(Boolean).join(" > "),
    });
  }

  return promotedAnyChapter
    ? uniqueStrings(promotedChapterDetails.map((chapter: any) => chapter?.chapter_name || "")).map((chapterName) =>
        promotedChapterDetails.find((chapter: any) => String(chapter?.chapter_name || "") === chapterName)
      ).filter(Boolean)
    : promotedChapterDetails;
}

function deriveDocumentPageCount(sourceText: string): string {
  const pageNumbers = [
    ...Array.from(sourceText.matchAll(/(?:^|\n)\s*#*\s*page\s+(\d+)\b/gi)).map((match) => Number(match[1] || 0)),
    ...Array.from(sourceText.matchAll(/\bpage\s+\d+\s*(?:of|\/)\s*(\d+)\b/gi)).map((match) => Number(match[1] || 0)),
  ].filter((value) => Number.isFinite(value) && value > 0);
  if (!pageNumbers.length) return "";
  return String(Math.max(...pageNumbers));
}

function getChunkSignalText(text: string) {
  return String(text || "")
    .replace(/[^\p{L}\p{N}]+/gu, "")
    .trim();
}

function sanitizeCurriculumChunkText(text: string) {
  return String(text || "")
    .replace(/^(?:\s*[-=_*|]{3,}\s*$\n?)+/gim, "")
    .replace(/(?:\n?\s*[-=_*|]{3,}\s*$)+$/gim, "")
    .trim();
}

function isTrivialCurriculumChunk(text: string) {
  const normalized = sanitizeCurriculumChunkText(text);
  if (!normalized) return true;
  if (/^(?:---+\s*)?page\s+\d+(?:\s*(?:of|\/)\s*\d+)?(?:\s*---+)?$/i.test(normalized)) {
    return true;
  }
  if (/^[#=\-–—_*|.:;()[\]\s]+$/u.test(normalized)) {
    return true;
  }
  return getChunkSignalText(normalized).length < 3;
}

async function ensureImageDataUrl(imageUrl: string, fallbackMimeType = "image/png"): Promise<{ imageDataUrl: string; mimeType: string }> {
  const trimmed = String(imageUrl || "").trim();
  if (!trimmed) {
    throw new Error("Image generation returned an empty image URL.");
  }
  if (trimmed.startsWith("data:image/")) {
    return {
      imageDataUrl: trimmed,
      mimeType: trimmed.slice(5, trimmed.indexOf(";")),
    };
  }

  const fetched = await fetchBinaryAsset(trimmed);
  return {
    imageDataUrl: `data:${fetched.mimeType || fallbackMimeType};base64,${fetched.buffer.toString("base64")}`,
    mimeType: fetched.mimeType || fallbackMimeType,
  };
}

async function enrichStudentLessonNotesWithVisuals(
  requestId: string,
  debugDir: string,
  sessionPlan: any,
  context: {
    subject?: string;
    gradeLevel?: string;
    sessionTitle?: string;
  }
) {
  const sections = Array.isArray(sessionPlan?.studentLessonNotes?.sections)
    ? sessionPlan.studentLessonNotes.sections
    : [];
  if (!sections.length) return sessionPlan;

  let visualsGenerated = 0;
  const enrichedSections: any[] = [];
  for (let index = 0; index < sections.length; index += 1) {
    const section = sections[index];
    const visualSupport = Array.isArray(section?.visualSupport)
      ? section.visualSupport.map((item: any) => String(item || "").trim()).filter(Boolean)
      : [];
    if (!visualSupport.length || visualsGenerated >= MAX_STUDENT_NOTE_VISUALS) {
      enrichedSections.push(section);
      continue;
    }

    const existingAssets = Array.isArray(section?.visualAssets) ? section.visualAssets.filter(Boolean) : [];
    if (existingAssets.length > 0) {
      enrichedSections.push(section);
      continue;
    }

    const imagePrompt = [
      "Create a clean educational study-note illustration for school students.",
      `Subject: ${String(context.subject || "General Science")}.`,
      `Grade level: ${String(context.gradeLevel || "School level")}.`,
      `Session: ${String(context.sessionTitle || "Lesson session")}.`,
      `Concept: ${String(section?.heading || `Concept ${index + 1}`)}.`,
      `Visual requirement: ${visualSupport.join(" ")}`,
      "Style: textbook-friendly, scientific, diagram-like, clear, accurate, uncluttered, centered composition, white or light background, student-safe.",
      "Important: do not draw any words, letters, labels, captions, heading text, numbering, or watermark inside the image.",
      "Show the concept visually only. Keep all explanation outside the image.",
      "Prefer clean shapes, arrows without text, color-coded parts, and simple educational composition.",
    ].join(" ");

    enrichedSections.push({
      ...section,
      visualAssets: [
        {
          prompt: imagePrompt,
          alt: `${String(section?.heading || `Student note visual ${index + 1}`)} illustration`,
          model: "planned-visual",
        },
      ],
    });
  }

  return {
    ...sessionPlan,
    studentLessonNotes: {
      ...sessionPlan.studentLessonNotes,
      sections: enrichedSections,
    },
  };
}

