function normalizeSessionSections(value: unknown): SessionSectionKey[] {
  if (!Array.isArray(value)) {
    return [...ALL_SESSION_SECTIONS];
  }

  const allowed = new Set<string>(ALL_SESSION_SECTIONS);
  const sections = value
    .map((item) => String(item || "").trim())
    .filter((item): item is SessionSectionKey => allowed.has(item));

  return sections.length > 0 ? Array.from(new Set(sections)) : [...ALL_SESSION_SECTIONS];
}

function buildCompactMaterialsSessionPayload(sessionContextPayload: any) {
  return {
    sessionNumber: sessionContextPayload?.sessionNumber,
    sessionTitle: sessionContextPayload?.sessionTitle,
    subject: sessionContextPayload?.subject,
    gradeLevel: sessionContextPayload?.gradeLevel,
    selectedChapters: Array.isArray(sessionContextPayload?.selectedChapters)
      ? sessionContextPayload.selectedChapters
      : [],
    totalSessions: sessionContextPayload?.totalSessions,
    durationMinutes: sessionContextPayload?.durationMinutes,
    learningOutcomes: Array.isArray(sessionContextPayload?.learningOutcomes)
      ? sessionContextPayload.learningOutcomes
      : [],
    previousSessionContext: sessionContextPayload?.previousSessionContext || "",
    teachingStrategy: {
      pace: sessionContextPayload?.teachingStrategy?.pace || "",
      targetDifficulty: sessionContextPayload?.teachingStrategy?.targetDifficulty || "",
      teachingStyle: Array.isArray(sessionContextPayload?.teachingStrategy?.teachingStyle)
        ? sessionContextPayload.teachingStrategy.teachingStyle
        : [],
      teachingResources: Array.isArray(sessionContextPayload?.teachingStrategy?.teachingResources)
        ? sessionContextPayload.teachingStrategy.teachingResources
        : [],
    },
    sessionPlanningDefaults: {
      language: sessionContextPayload?.sessionPlanningDefaults?.language || "",
      readingLevel: sessionContextPayload?.sessionPlanningDefaults?.readingLevel || "",
      responseLength: sessionContextPayload?.sessionPlanningDefaults?.responseLength || "",
      creativity: sessionContextPayload?.sessionPlanningDefaults?.creativity || "",
    },
  };
}

function buildMaterialsAntiDriftInstructions(subject: string, selectedChapters: string[], sessionTitle: string) {
  const chapterText = limitStringList(selectedChapters, 4, 120).join(", ") || "the requested chapter";
  const normalizedSubject = canonicalizeSubjectName(subject || "") || String(subject || "").trim() || "the requested subject";
  const instructions = [
    "Subject-scope guardrails:",
    `- Treat the requested subject as authoritative: ${normalizedSubject}.`,
    `- Teach only the requested session: ${sessionTitle || "the current session"}.`,
    `- Teach only the requested chapter/topic focus: ${chapterText}.`,
    "- Use only the provided session JSON and chapter metadata.",
    "- Do not infer a different subject from generic examples, visuals, or prior model habits.",
    "- If the requested subject is Mathematics, never introduce Biology, Science process content, Photosynthesis, chlorophyll, stomata, leaves, plants, cells, or organelles.",
    "- Reject off-topic process/experiment content unless it is explicitly present in the provided session JSON.",
    "- If any field would drift off-subject, rewrite it to match the requested subject and chapter before returning JSON.",
  ];
  return instructions.join("\n");
}

function pickSessionSections(sessionPlan: any, selectedSections: SessionSectionKey[]) {
  const partial: Record<string, unknown> = {};
  for (const section of selectedSections) {
    if (section in (sessionPlan || {})) {
      partial[section] = sessionPlan[section];
    }
  }
  return partial;
}

function hasGeneratedSessionSectionValue(value: unknown): boolean {
  if (value == null) return false;
  if (typeof value === "string") return value.trim().length > 0;
  if (Array.isArray(value)) return value.length > 0;
  if (typeof value === "object") return Object.keys(value as Record<string, unknown>).length > 0;
  return true;
}

function mergeSessionPlanSections(basePlan: any, patchPlan: any, selectedSections: SessionSectionKey[]) {
  const merged = {
    ...(basePlan || {}),
  };

  const sessionSectionSet = new Set<string>(ALL_SESSION_SECTIONS);
  for (const [key, value] of Object.entries(patchPlan || {})) {
    if (!sessionSectionSet.has(key)) {
      merged[key] = value;
    }
  }

  for (const section of selectedSections) {
    if (section in (patchPlan || {}) && hasGeneratedSessionSectionValue(patchPlan[section])) {
      merged[section] = patchPlan[section];
    }
  }

  return merged;
}

function normalizeSessionIdentityText(value: any) {
  return String(value || "")
    .toLowerCase()
    .replace(/\s+/g, " ")
    .trim();
}

function normalizeLooseIdentityText(value: any) {
  return normalizeSessionIdentityText(value)
    .replace(/[()/:,&-]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function buildIdentityVariants(value: any) {
  const raw = String(value || "").trim();
  const normalized = normalizeSessionIdentityText(raw);
  const loose = normalizeLooseIdentityText(raw);
  const variants = new Set<string>();
  const push = (candidate: any) => {
    const exact = normalizeSessionIdentityText(candidate);
    const relaxed = normalizeLooseIdentityText(candidate);
    if (exact) variants.add(exact);
    if (relaxed) variants.add(relaxed);
  };

  push(raw);
  if (normalized.includes(":")) {
    normalized.split(":").forEach(push);
  }
  if (raw.includes("(") && raw.includes(")")) {
    push(raw.replace(/\([^)]*\)/g, " "));
    const parentheticalParts = (raw.match(/\(([^)]*)\)/g) || []) as string[];
    parentheticalParts.forEach((part) => push(part.replace(/[()]/g, "")));
  }
  if (loose.includes("  ")) {
    push(loose);
  }

  return Array.from(variants).filter(Boolean);
}

function buildGradeNeedles(gradeLevel: string) {
  const variants = new Set<string>();
  const push = (value: any) => {
    const normalized = normalizeSessionIdentityText(value);
    const loose = normalizeLooseIdentityText(value);
    if (normalized) variants.add(normalized);
    if (loose) variants.add(loose);
  };

  push(gradeLevel);
  const raw = String(gradeLevel || "");
  raw
    .split(/[\/,&]| and /i)
    .map((part) => part.trim())
    .filter(Boolean)
    .forEach((part) => {
      push(part);
      const romanMatch = part.match(/class\s+(ix|iv|v?i{0,3}|x)\b/i);
      if (romanMatch?.[1]) {
        const roman = romanMatch[1].toUpperCase();
        const arabicMap: Record<string, string> = { IX: "9", X: "10", VIII: "8", VII: "7", VI: "6", V: "5", IV: "4" };
        if (arabicMap[roman]) {
          push(`class ${arabicMap[roman]}`);
          push(arabicMap[roman]);
        }
        push(`class ${roman.toLowerCase()}`);
      }
      const arabicMatch = part.match(/class\s+(\d{1,2})\b/i);
      if (arabicMatch?.[1]) {
        const arabic = arabicMatch[1];
        const romanMap: Record<string, string> = { "4": "iv", "5": "v", "6": "vi", "7": "vii", "8": "viii", "9": "ix", "10": "x" };
        if (romanMap[arabic]) {
          push(`class ${romanMap[arabic]}`);
          push(romanMap[arabic]);
        }
        push(`class ${arabic}`);
      }
    });

  return Array.from(variants).filter(Boolean);
}

function slugifySessionIdentityPart(value: any) {
  return normalizeSessionIdentityText(value)
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 80);
}

function buildGeneratedSessionStorageKey(request: {
  roadmapSessionNumber: number;
  chapterName?: string;
  sessionTitle?: string;
}) {
  const topicSlug = slugifySessionIdentityPart(request.chapterName || request.sessionTitle || `session-${request.roadmapSessionNumber}`) || `session-${request.roadmapSessionNumber}`;
  return `session-${request.roadmapSessionNumber}__${topicSlug}`;
}

function collectSessionPlanMatchText(sessionPlan: any) {
  if (!sessionPlan || typeof sessionPlan !== "object") {
    return "";
  }

  const textParts = [
    sessionPlan.title,
    ...(Array.isArray(sessionPlan.topicCoverage) ? sessionPlan.topicCoverage : []),
    ...(Array.isArray(sessionPlan.learningOutcomes) ? sessionPlan.learningOutcomes : []),
    sessionPlan.introduction,
    sessionPlan?.theory?.overview,
    ...(Array.isArray(sessionPlan?.theory?.keyPoints) ? sessionPlan.theory.keyPoints : []),
    sessionPlan?.theory?.detailedContent,
    sessionPlan?.teacherLessonNotes?.sessionOverview,
    ...(Array.isArray(sessionPlan?.teacherLessonNotes?.learningOutcomes) ? sessionPlan.teacherLessonNotes.learningOutcomes : []),
    ...(Array.isArray(sessionPlan?.teacherLessonNotes?.lessonPurpose) ? sessionPlan.teacherLessonNotes.lessonPurpose : []),
    ...(Array.isArray(sessionPlan?.teacherLessonNotes?.teachingSequence) ? sessionPlan.teacherLessonNotes.teachingSequence : []),
    sessionPlan?.studentLessonNotes?.title,
    sessionPlan?.studentLessonNotes?.sessionOverview,
    sessionPlan?.studentLessonNotes?.introduction,
    ...(Array.isArray(sessionPlan?.studentLessonNotes?.keyTerms) ? sessionPlan.studentLessonNotes.keyTerms : []),
    ...(Array.isArray(sessionPlan?.studentLessonNotes?.summary) ? sessionPlan.studentLessonNotes.summary : []),
  ];

  return textParts.map(normalizeSessionIdentityText).filter(Boolean).join(" ");
}

function hasCrossSubjectSignals(subject: string, text: string) {
  const normalizedText = normalizeSessionIdentityText(text);
  if (!normalizedText) {
    return false;
  }

  if (isMathSubject(subject)) {
    return /\bscience\b|\bbiology\b|\bphotosynthesis\b|\bchlorophyll\b|\bstomata\b|\bleaf\b|\bleaves\b|\bplant\b|\bplants\b/.test(normalizedText);
  }

  const canonicalSubject = canonicalizeSubjectName(subject || "").toLowerCase();
  if (canonicalSubject.includes("science") || canonicalSubject.includes("biology")) {
    return /\bmathematics\b|\bmaths\b|\bnumber system\b|\brational number\b|\birrational number\b/.test(normalizedText);
  }

  return false;
}

function getEquivalentTopicNeedles(subject: string, chapterName: string, sessionTitle: string) {
  const needles = new Set<string>();
  const push = (value: any) => {
    buildIdentityVariants(value).forEach((variant) => needles.add(variant));
  };

  push(chapterName);
  push(sessionTitle);

  if (isMathSubject(subject)) {
    const combined = [chapterName, sessionTitle].map(normalizeSessionIdentityText).filter(Boolean).join(" ");
    if (/\bnumber system\b/.test(combined)) {
      [
        "real number",
        "real numbers",
        "rational number",
        "rational numbers",
        "irrational number",
        "irrational numbers",
        "number line",
        "decimal expansion",
        "terminating decimal",
        "non terminating non repeating",
        "square root",
        "sqrt 2",
        "root 2",
      ].forEach(push);
    }
  }

  return Array.from(needles);
}

function coverageMatchesAnyNeedle(coverage: string, needles: string[]) {
  if (!coverage) {
    return false;
  }
  const looseCoverage = normalizeLooseIdentityText(coverage);
  return needles.some((needle) => {
    if (!needle) return false;
    const looseNeedle = normalizeLooseIdentityText(needle);
    return coverage.includes(needle) || (looseNeedle && looseCoverage.includes(looseNeedle));
  });
}

function findMatchingCoverageNeedle(coverage: string, needles: string[]) {
  if (!coverage) {
    return "";
  }
  const looseCoverage = normalizeLooseIdentityText(coverage);
  return needles.find((needle) => {
    if (!needle) return false;
    const looseNeedle = normalizeLooseIdentityText(needle);
    return coverage.includes(needle) || (looseNeedle && looseCoverage.includes(looseNeedle));
  }) || "";
}

function findMatchingGeneratedSessionEntry(
  generatedSessions: Record<string, any>,
  request: {
    requestedSessionKey?: string;
    roadmapSessionNumber: number;
    chapterName: string;
    sessionTitle: string;
    subject: string;
    gradeLevel: string;
    sessionNumber: number;
  }
) {
  const preferredKey = String(request.requestedSessionKey || "").trim() || buildGeneratedSessionStorageKey({
    roadmapSessionNumber: request.roadmapSessionNumber,
    chapterName: request.chapterName,
    sessionTitle: request.sessionTitle,
  });
  const legacyKey = String(request.roadmapSessionNumber);
  const candidates: Array<[string, any]> = [];

  if (generatedSessions[preferredKey]) {
    return { key: preferredKey, sessionPlan: generatedSessions[preferredKey] };
  }
  if (generatedSessions[legacyKey]) {
    return { key: legacyKey, sessionPlan: generatedSessions[legacyKey] };
  }
  for (const [key, value] of Object.entries(generatedSessions || {})) {
    if (key !== preferredKey && key !== legacyKey) {
      candidates.push([key, value]);
    }
  }

  for (const [key, sessionPlan] of candidates) {
    if (sessionPlanMatchesRequest(sessionPlan, request)) {
      return { key, sessionPlan };
    }
  }

  const fuzzyTitleMatches = candidates
    .map(([key, sessionPlan]) => ({
      key,
      sessionPlan,
      score: scoreGeneratedSessionMatch(sessionPlan, request),
    }))
    .filter((candidate) => candidate.score >= 3)
    .sort((left, right) => right.score - left.score);

  if (fuzzyTitleMatches[0]) {
    return {
      key: fuzzyTitleMatches[0].key,
      sessionPlan: fuzzyTitleMatches[0].sessionPlan,
    };
  }

  return { key: preferredKey, sessionPlan: null };
}

function resolveStudentPublicationEntry(
  studentPublications: Record<string, Record<string, any>>,
  generatedSessionKey: string,
  session: any,
) {
  const exactKeys = [
    String(generatedSessionKey || "").trim(),
    String(session?.sessionKey || "").trim(),
    String(session?.id || "").trim(),
    String(session?.sessionNumber || "").trim(),
  ].filter(Boolean);

  for (const key of exactKeys) {
    const entry = studentPublications[key];
    if (entry && typeof entry === "object") {
      return entry;
    }
  }

  const sessionNumber = Number(session?.sessionNumber || 0);
  const generatedKeyPrefix = sessionNumber > 0 ? `session-${sessionNumber}__` : "";

  for (const [savedKey, entry] of Object.entries(studentPublications || {})) {
    const normalizedSavedKey = String(savedKey || "").trim();
    if (!normalizedSavedKey || !entry || typeof entry !== "object") {
      continue;
    }

    if (generatedKeyPrefix && normalizedSavedKey.startsWith(generatedKeyPrefix)) {
      return entry;
    }
  }

  return {};
}

function parseSessionNumberFromGeneratedSessionKey(value: unknown) {
  const candidate = String(value || "").trim();
  if (!candidate) {
    return 0;
  }

  const prefixedMatch = candidate.match(/session-(\d+)__/i) || candidate.match(/session-(\d+)/i);
  if (prefixedMatch?.[1]) {
    const parsed = Number(prefixedMatch[1]);
    if (Number.isFinite(parsed) && parsed > 0) {
      return parsed;
    }
  }

  const plainNumber = Number(candidate);
  return Number.isFinite(plainNumber) && plainNumber > 0 ? plainNumber : 0;
}

function resolvePublishedSessionNumber(session: any, generatedSessionKey?: string) {
  const candidates = [
    String(generatedSessionKey || "").trim(),
    String(session?.sessionKey || "").trim(),
    String(session?.id || "").trim(),
  ].filter(Boolean);

  for (const candidate of candidates) {
    const parsed = parseSessionNumberFromGeneratedSessionKey(candidate);
    if (parsed > 0) {
      return parsed;
    }
  }

  const directSessionNumber = Number(session?.sessionNumber || 0);
  if (Number.isFinite(directSessionNumber) && directSessionNumber > 0) {
    return directSessionNumber;
  }

  return 0;
}

function resolvePublicationTimestamp(
  publicationEntry: Record<string, boolean | { published?: boolean; publishedAt?: string | null }> | undefined,
  kind: string,
  workspace: any,
) {
  const entry = publicationEntry?.[kind];
  const entryPublishedAt =
    entry && typeof entry === "object"
      ? String((entry as { publishedAt?: string | null }).publishedAt || "").trim()
      : "";

  if (entryPublishedAt) {
    return new Date(entryPublishedAt).toISOString();
  }

  return new Date(workspace?.updatedAt || workspace?.createdAt || Date.now()).toISOString();
}

function normalizePublicationKind(kind: unknown) {
  const normalizedKind = String(kind || "").trim().toLowerCase();
  return ["notes", "homework", "assessments", "quizzes"].includes(normalizedKind)
    ? normalizedKind
    : "";
}

function normalizePublicationMetadata(
  value: any,
  fallback: {
    workspace: any;
    generatedSessionKey: string;
    session: any;
    kind: string;
  },
) {
  const kind = normalizePublicationKind(fallback.kind);
  const session = fallback.session || {};
  const workspace = fallback.workspace || {};
  const exactGeneratedSessionKey = String(fallback.generatedSessionKey || "").trim();
  const storedGeneratedSessionKey = String(value?.generatedSessionKey || "").trim();
  const resolvedGeneratedSessionKey =
    exactGeneratedSessionKey ||
    storedGeneratedSessionKey ||
    String(session?.sessionKey || session?.id || "").trim();
  const sessionNumberFromExactKey = parseSessionNumberFromGeneratedSessionKey(exactGeneratedSessionKey);
  const sessionNumberFromResolvedKey = parseSessionNumberFromGeneratedSessionKey(resolvedGeneratedSessionKey);
  const sessionNumberFromValue = Number(value?.sessionNumber || 0);
  const sessionNumberFromSession = Number(session?.sessionNumber || 0);
  const sessionNumber =
    (Number.isFinite(sessionNumberFromExactKey) && sessionNumberFromExactKey > 0 ? sessionNumberFromExactKey : 0) ||
    (Number.isFinite(sessionNumberFromResolvedKey) && sessionNumberFromResolvedKey > 0 ? sessionNumberFromResolvedKey : 0) ||
    (Number.isFinite(sessionNumberFromValue) && sessionNumberFromValue > 1 ? sessionNumberFromValue : 0) ||
    (Number.isFinite(sessionNumberFromSession) && sessionNumberFromSession > 1 ? sessionNumberFromSession : 0) ||
    (Number.isFinite(sessionNumberFromValue) && sessionNumberFromValue > 0 ? sessionNumberFromValue : 0) ||
    (Number.isFinite(sessionNumberFromSession) && sessionNumberFromSession > 0 ? sessionNumberFromSession : 0);
  const publishedAtRaw = String(value?.publishedAt || "").trim();
  const publishedAt = publishedAtRaw ? new Date(publishedAtRaw).toISOString() : "";
  const generatedSessionKey = resolvedGeneratedSessionKey;

  return {
    published: value === true || Boolean(value?.published),
    publishedAt,
    workspaceId: String(value?.workspaceId || workspace?._id || "").trim(),
    generatedSessionKey,
    sessionNumber,
    sessionTitle: String(value?.sessionTitle || session?.title || session?.sessionTitle || "").trim(),
    subjectId: String(value?.subjectId || workspace?.subjectId || "").trim(),
    subjectName: getCanonicalSubjectDisplayName(
      value?.subjectName || workspace?.academicConfig?.subject || workspace?.curriculumSnapshot?.subject || workspace?.subjectId || "",
    ),
    classId: String(value?.classId || workspace?.classId || workspace?.academicConfig?.className || workspace?.curriculumSnapshot?.gradeLevel || "").trim(),
    grade: String(value?.grade || workspace?.academicConfig?.className || workspace?.curriculumSnapshot?.gradeLevel || "").trim(),
    section: String(value?.section || workspace?.academicConfig?.section || workspace?.sectionId || "").trim(),
    termNumber: Number(value?.termNumber || workspace?.sessionAllocation?.selectedTermSummary?.termNumber || 0) || null,
    contentType: String(value?.contentType || kind).trim(),
  };
}

function buildCanonicalPublicationItem(input: {
  workspace: any;
  generatedSessionKey: string;
  session: any;
  student: any;
  publicationValue: any;
  kind: string;
  schoolId: string;
}) {
  const kind = normalizePublicationKind(input.kind);
  if (!kind) {
    return null;
  }

  const metadata = normalizePublicationMetadata(input.publicationValue, {
    workspace: input.workspace,
    generatedSessionKey: input.generatedSessionKey,
    session: input.session,
    kind,
  });

  if (!metadata.published || !metadata.publishedAt || metadata.sessionNumber <= 0) {
    return null;
  }

  let payload: Record<string, any> | null = null;
  if (kind === "notes" && input.session?.studentLessonNotes) {
    payload = { studentLessonNotes: input.session.studentLessonNotes };
  }
  if (kind === "homework" && input.session?.homework) {
    payload = { homework: input.session.homework };
  }
  if (kind === "assessments" && input.session?.assessment) {
    payload = { assessment: normalizeStudentAssessmentPayloadForResponse(input.session.assessment) };
  }

  if (!payload) {
    return null;
  }

  const teacherId = String(input.workspace?.teacherId || input.workspace?.createdBy || "").trim();
  const sessionTitle = metadata.sessionTitle || "Session";
  const classId = metadata.classId || String(input.student?.classId || "").trim();
  const className = metadata.grade || classId;
  const subjectName = metadata.subjectName || "General";
  const generatedSessionKey = metadata.generatedSessionKey;
  const sessionId = `${metadata.workspaceId}-${generatedSessionKey}`;
  const artifactId = `${kind}-${String(metadata.workspaceId || "workspace").trim().toLowerCase()}-${String(generatedSessionKey || `session-${metadata.sessionNumber}`).trim().toLowerCase().replace(/[^a-z0-9]+/g, "-")}`;

  return {
    id: artifactId,
    workspaceId: metadata.workspaceId,
    generatedSessionKey,
    sessionId,
    sessionNumber: metadata.sessionNumber,
    sessionTitle,
    teacherId,
    teacherName: "",
    classId,
    className,
    gradeLevel: metadata.grade || className,
    subject: subjectName,
    subjectId: metadata.subjectId,
    subjectName,
    section: metadata.section || String(input.student?.section || "").trim(),
    termNumber: metadata.termNumber,
    contentType: metadata.contentType || kind,
    kind,
    duration: Number(input.session?.duration || 0),
    schoolId: input.schoolId,
    publishedAt: metadata.publishedAt,
    payload,
    content: payload,
  };
}

function sessionPlanMatchesRequest(
  sessionPlan: any,
  request: {
    roadmapSessionNumber?: number;
    chapterName: string;
    sessionTitle: string;
    subject: string;
    gradeLevel: string;
    sessionNumber: number;
  }
) {
  if (!sessionPlan || typeof sessionPlan !== "object") {
    return false;
  }

  const chapterNeedle = normalizeSessionIdentityText(request.chapterName);
  const titleNeedle = normalizeSessionIdentityText(request.sessionTitle);
  const subjectNeedle = normalizeSessionIdentityText(request.subject);
  const gradeNeedles = buildGradeNeedles(request.gradeLevel);
  const topicNeedles = getEquivalentTopicNeedles(request.subject, request.chapterName, request.sessionTitle);
  const sessionTitle = normalizeSessionIdentityText(sessionPlan.title);
  const pptTitle = normalizeSessionIdentityText(sessionPlan?.materials?.ppt?.title || sessionPlan?.materials?.ppt?.presentationTitle);
  const topicCoverage = Array.isArray(sessionPlan?.materials?.ppt?.coverageSummary?.topicsCovered)
    ? sessionPlan.materials.ppt.coverageSummary.topicsCovered.map(normalizeSessionIdentityText).join(" ")
    : "";
  const audience = normalizeSessionIdentityText(sessionPlan?.materials?.ppt?.audience);
  const contentCoverage = collectSessionPlanMatchText(sessionPlan);
  const slideCoverage = Array.isArray(sessionPlan?.materials?.ppt?.slides)
    ? sessionPlan.materials.ppt.slides
        .flatMap((slide: any) => [
          ...(Array.isArray(slide?.topicCoverage) ? slide.topicCoverage : []),
          ...(Array.isArray(slide?.onSlideText) ? slide.onSlideText : []),
        ])
        .map(normalizeSessionIdentityText)
        .join(" ")
    : "";
  const allCoverage = [sessionTitle, pptTitle, topicCoverage, audience, slideCoverage, contentCoverage].filter(Boolean).join(" ");

  if (hasCrossSubjectSignals(request.subject, allCoverage)) {
    return false;
  }

  const titleOrTopicMatches =
    coverageMatchesAnyNeedle(allCoverage, topicNeedles) ||
    (chapterNeedle && allCoverage.includes(chapterNeedle)) ||
    (titleNeedle && allCoverage.includes(titleNeedle));

  const subjectMatches = !subjectNeedle || allCoverage.includes(subjectNeedle);
  const gradeMatches =
    gradeNeedles.length === 0 ||
    gradeNeedles.some((needle) => audience.includes(needle) || slideCoverage.includes(needle) || contentCoverage.includes(needle));
  const sessionMatches =
    Number(sessionPlan?.sessionNumber || 0) === Number(request.sessionNumber || 0) ||
    Number(sessionPlan?.sessionNumber || 0) === 0;
  const fuzzyTopicMatch =
    titleOrTopicMatches &&
    subjectMatches &&
    (
      sessionMatches ||
      coverageMatchesAnyNeedle(contentCoverage, topicNeedles) ||
      coverageMatchesAnyNeedle(slideCoverage, topicNeedles)
    );

  return Boolean((titleOrTopicMatches && subjectMatches && gradeMatches && sessionMatches) || fuzzyTopicMatch);
}

function scoreGeneratedSessionMatch(
  sessionPlan: any,
  request: {
    roadmapSessionNumber?: number;
    chapterName: string;
    sessionTitle: string;
    subject: string;
    gradeLevel: string;
    sessionNumber: number;
  }
) {
  if (!sessionPlan || typeof sessionPlan !== "object") {
    return 0;
  }

  const chapterNeedle = normalizeSessionIdentityText(request.chapterName);
  const titleNeedle = normalizeSessionIdentityText(request.sessionTitle);
  const subjectNeedle = normalizeSessionIdentityText(request.subject);
  const gradeNeedles = buildGradeNeedles(request.gradeLevel);
  const topicNeedles = getEquivalentTopicNeedles(request.subject, request.chapterName, request.sessionTitle);
  const sessionTitle = normalizeSessionIdentityText(sessionPlan.title);
  const pptTitle = normalizeSessionIdentityText(sessionPlan?.materials?.ppt?.title || sessionPlan?.materials?.ppt?.presentationTitle);
  const audience = normalizeSessionIdentityText(sessionPlan?.materials?.ppt?.audience);
  const contentCoverage = collectSessionPlanMatchText(sessionPlan);
  const slideCoverage = Array.isArray(sessionPlan?.materials?.ppt?.slides)
    ? sessionPlan.materials.ppt.slides
        .flatMap((slide: any) => [
          slide?.slideTitle,
          slide?.teachingBeat,
          slide?.teacherIntent,
          slide?.studentTakeaway,
          ...(Array.isArray(slide?.topicCoverage) ? slide.topicCoverage : []),
          ...(Array.isArray(slide?.mustTeach) ? slide.mustTeach : []),
        ])
        .map(normalizeSessionIdentityText)
        .join(" ")
    : "";
  const allCoverage = [sessionTitle, pptTitle, contentCoverage, slideCoverage].filter(Boolean).join(" ");

  if (!allCoverage || hasCrossSubjectSignals(request.subject, allCoverage)) {
    return 0;
  }

  let score = 0;
  if (chapterNeedle && allCoverage.includes(chapterNeedle)) score += 2;
  if (titleNeedle && allCoverage.includes(titleNeedle)) score += 2;
  if (coverageMatchesAnyNeedle(allCoverage, topicNeedles)) score += 2;
  if (!subjectNeedle || allCoverage.includes(subjectNeedle)) score += 1;
  if (
    gradeNeedles.length === 0 ||
    gradeNeedles.some((needle) => audience.includes(needle) || slideCoverage.includes(needle) || contentCoverage.includes(needle))
  ) {
    score += 1;
  }
  if (
    Number(sessionPlan?.sessionNumber || 0) === Number(request.sessionNumber || 0) ||
    Number(sessionPlan?.sessionNumber || 0) === Number(request.roadmapSessionNumber || 0)
  ) {
    score += 1;
  }

  return score;
}

function pptMatchesRequest(
  ppt: any,
  request: {
    chapterName: string;
    sessionTitle: string;
    subject: string;
    gradeLevel: string;
  }
) {
  if (!ppt || typeof ppt !== "object") {
    return false;
  }

  const chapterNeedle = normalizeSessionIdentityText(request.chapterName);
  const titleNeedle = normalizeSessionIdentityText(request.sessionTitle);
  const subjectNeedle = normalizeSessionIdentityText(request.subject);
  const gradeNeedles = buildGradeNeedles(request.gradeLevel);
  const topicNeedles = getEquivalentTopicNeedles(request.subject, request.chapterName, request.sessionTitle);

  const titleText = normalizeSessionIdentityText(ppt?.title || ppt?.presentationTitle);
  const audienceText = normalizeSessionIdentityText(ppt?.audience);
  const topicCoverage = Array.isArray(ppt?.coverageSummary?.topicsCovered)
    ? ppt.coverageSummary.topicsCovered.map(normalizeSessionIdentityText).join(" ")
    : "";
  const taughtConceptCoverage = Array.isArray(ppt?.coverageSummary?.taughtConceptsCovered)
    ? ppt.coverageSummary.taughtConceptsCovered.map(normalizeSessionIdentityText).join(" ")
    : "";
  const outcomeCoverage = Array.isArray(ppt?.coverageSummary?.learningOutcomesCovered)
    ? ppt.coverageSummary.learningOutcomesCovered.map(normalizeSessionIdentityText).join(" ")
    : "";
  const slideCoverage = Array.isArray(ppt?.slides)
    ? ppt.slides
        .flatMap((slide: any) => [
          slide?.slideTitle,
          slide?.teachingBeat,
          slide?.teacherIntent,
          slide?.studentTakeaway,
          ...(Array.isArray(slide?.topicCoverage) ? slide.topicCoverage : []),
          ...(Array.isArray(slide?.mustTeach) ? slide.mustTeach : []),
          ...(Array.isArray(slide?.bulletPoints) ? slide.bulletPoints : []),
          ...(Array.isArray(slide?.onSlideText) ? slide.onSlideText : []),
          ...(Array.isArray(slide?.speakerNotes) ? slide.speakerNotes : []),
        ])
        .map(normalizeSessionIdentityText)
        .join(" ")
    : "";
  const allCoverage = [
    titleText,
    audienceText,
    topicCoverage,
    taughtConceptCoverage,
    outcomeCoverage,
    slideCoverage,
  ].filter(Boolean).join(" ");

  if (hasCrossSubjectSignals(request.subject, allCoverage)) {
    return false;
  }

  const chapterOrTitleMatches =
    coverageMatchesAnyNeedle(allCoverage, topicNeedles) ||
    (chapterNeedle && allCoverage.includes(chapterNeedle)) ||
    (titleNeedle && allCoverage.includes(titleNeedle));
  const subjectMatches =
    !subjectNeedle ||
    allCoverage.includes(subjectNeedle) ||
    (chapterOrTitleMatches && !hasCrossSubjectSignals(request.subject, allCoverage));
  const strictGradeMatches =
    gradeNeedles.length === 0 ||
    gradeNeedles.some((needle) => audienceText.includes(needle) || slideCoverage.includes(needle));
  const genericAudienceMentionsGrade = /\bgrade\b|\bclass\b|\bstudents\b|\bclassroom\b/.test(audienceText);
  const gradeMatches =
    strictGradeMatches ||
    (chapterOrTitleMatches && subjectMatches && genericAudienceMentionsGrade);

  return Boolean(chapterOrTitleMatches && subjectMatches && gradeMatches);
}

function normalizeAssessmentCustomization(input: any): SessionAssessmentCustomization | null {
  if (!input || typeof input !== "object") {
    return null;
  }

  const questionTypes = Array.isArray(input.questionTypes)
    ? input.questionTypes
        .map((item: any): AssessmentQuestionTypeRequest => ({
          type: String(item?.type || "").trim() as AssessmentQuestionType,
          label: String(item?.label || "").trim() || undefined,
          questionCount: Math.max(0, toNumberOrZero(item?.questionCount)),
          marksEach: Math.max(0, toNumberOrZero(item?.marksEach)),
        }))
        .filter((item: AssessmentQuestionTypeRequest) => item.type && item.questionCount != null && item.marksEach != null)
    : [];

  const derivedTotalQuestions = questionTypes.reduce((sum: number, item: AssessmentQuestionTypeRequest) => sum + Number(item.questionCount || 0), 0);
  const derivedTotalMarks = questionTypes.reduce(
    (sum: number, item: AssessmentQuestionTypeRequest) => sum + Number(item.questionCount || 0) * Number(item.marksEach || 0),
    0
  );

  return {
    assessmentType: String(input.assessmentType || "").trim() || "Session assessment",
    difficulty: String(input.difficulty || "").trim() || "Balanced",
    paperObjective: String(input.paperObjective || "").trim(),
    totalMarks: Math.max(0, toNumberOrZero(input.totalMarks)) || derivedTotalMarks || null,
    totalQuestions: Math.max(0, toNumberOrZero(input.totalQuestions)) || derivedTotalQuestions || null,
    questionTypes,
  };
}

function buildAssessmentCustomizationSignature(customization: SessionAssessmentCustomization | null | undefined) {
  return JSON.stringify({
    assessmentType: String(customization?.assessmentType || "Session assessment"),
    difficulty: String(customization?.difficulty || "Balanced"),
    paperObjective: String(customization?.paperObjective || ""),
    totalMarks: Number(customization?.totalMarks || 0),
    totalQuestions: Number(customization?.totalQuestions || 0),
    questionTypes: Array.isArray(customization?.questionTypes)
      ? customization!.questionTypes!.map((item) => ({
          type: item.type,
          label: item.label || "",
          questionCount: Number(item.questionCount || 0),
          marksEach: Number(item.marksEach || 0),
        }))
      : [],
  });
}

function hasAssessmentCustomizationContent(customization: SessionAssessmentCustomization | null | undefined) {
  const questionTypes = Array.isArray(customization?.questionTypes) ? customization!.questionTypes! : [];
  const totalQuestions = questionTypes.reduce((sum, item) => sum + Number(item.questionCount || 0), 0);
  const totalMarks = questionTypes.reduce((sum, item) => sum + Number(item.questionCount || 0) * Number(item.marksEach || 0), 0);
  return totalQuestions > 0 && totalMarks > 0;
}

function hasAssessmentSourceContent(sessionPlan: any) {
  return Boolean(
    sessionPlan &&
    typeof sessionPlan === "object" &&
    (
      (Array.isArray(sessionPlan.learningOutcomes) && sessionPlan.learningOutcomes.length > 0) ||
      (typeof sessionPlan.introduction === "string" && sessionPlan.introduction.trim().length > 0) ||
      (sessionPlan.theory && (sessionPlan.theory.overview || sessionPlan.theory.detailedContent || sessionPlan.theory.keyPoints?.length)) ||
      (Array.isArray(sessionPlan.activities) && sessionPlan.activities.length > 0) ||
      sessionPlan.teacherLessonNotes ||
      sessionPlan.studentLessonNotes
    )
  );
}

function limitString(value: any, maxLength: number) {
  const text = String(value || "").trim();
  if (!text) return "";
  if (text.length <= maxLength) return text;
  return `${text.slice(0, Math.max(0, maxLength - 3)).trim()}...`;
}

function limitStringList(values: any, maxItems: number, maxLengthPerItem: number) {
  return (Array.isArray(values) ? values : [])
    .map((item: any) => limitString(item, maxLengthPerItem))
    .filter(Boolean)
    .slice(0, maxItems);
}

function compactTeacherLessonNotesForAssessment(notes: any) {
  if (!notes || typeof notes !== "object") return null;

  return {
    sessionOverview: limitString(notes.sessionOverview, 500),
    prerequisiteKnowledge: limitStringList(notes.prerequisiteKnowledge, 6, 180),
    previousSessionRecap: limitStringList(notes.previousSessionRecap, 6, 180),
    learningOutcomes: limitStringList(notes.learningOutcomes, 8, 220),
    lessonPurpose: limitStringList(notes.lessonPurpose, 6, 220),
    teachingSequence: limitStringList(notes.teachingSequence, 8, 220),
    guidedPractice: limitStringList(notes.guidedPractice, 6, 220),
    misconceptions: limitStringList(notes.misconceptions, 6, 180),
    formativeChecks: limitStringList(notes.formativeChecks, 8, 220),
    assessmentQuestions: limitStringList(notes.assessmentQuestions, 8, 220),
    sessionSummary: limitStringList(notes.sessionSummary, 6, 220),
    conceptFlow: (Array.isArray(notes.conceptFlow) ? notes.conceptFlow : []).slice(0, 6).map((item: any) => ({
      conceptName: limitString(item?.conceptName, 140),
      definition: limitString(item?.definition, 220),
      coreExplanation: limitString(item?.coreExplanation, 320),
      importance: limitString(item?.importance, 220),
      keywords: limitStringList(item?.keywords, 6, 80),
      examples: limitStringList(item?.examples, 4, 160),
    })),
    lessonBlocks: (Array.isArray(notes.lessonBlocks) ? notes.lessonBlocks : []).slice(0, 6).map((item: any) => ({
      title: limitString(item?.title, 140),
      durationMinutes: Number(item?.durationMinutes || 0) || undefined,
      teacherPrompt: limitStringList(item?.teacherPrompt, 3, 180),
      explanation: limitStringList(item?.explanation, 3, 220),
      examples: limitStringList(item?.examples, 3, 180),
      boardWork: limitStringList(item?.boardWork, 3, 180),
      boardSteps: limitStringList(item?.boardSteps, 3, 180),
      checkUnderstanding: limitStringList(item?.checkUnderstanding, 3, 180),
      expectedAnswers: limitStringList(item?.expectedAnswers, 3, 180),
      activity: limitStringList(item?.activity, 2, 180),
    })),
    classroomQuestions: (Array.isArray(notes.classroomQuestions) ? notes.classroomQuestions : []).slice(0, 6).map((item: any) => ({
      question: limitString(item?.question, 180),
      level: limitString(item?.level, 60),
      expectedResponse: limitString(item?.expectedResponse, 180),
      answerPoints: limitStringList(item?.answerPoints, 3, 140),
    })),
    commonMisconceptionsDetailed: (Array.isArray(notes.commonMisconceptionsDetailed) ? notes.commonMisconceptionsDetailed : []).slice(0, 5).map((item: any) => ({
      misconception: limitString(item?.misconception, 180),
      correction: limitString(item?.correction, 220),
    })),
    differentiation: notes.differentiation
      ? {
          slowLearners: limitStringList(notes.differentiation.slowLearners, 4, 180),
          averageLearners: limitStringList(notes.differentiation.averageLearners, 4, 180),
          advancedLearners: limitStringList(notes.differentiation.advancedLearners, 4, 180),
        }
      : null,
    teacherTips: limitStringList(notes.teacherTips, 6, 180),
    blackboardSummary: limitStringList(notes.blackboardSummary, 6, 180),
    nextSessionBridge: limitStringList(notes.nextSessionBridge, 4, 180),
    };
}

function compactStudentLessonNotesForAssessment(notes: any) {
  if (!notes || typeof notes !== "object") return null;

  return {
    title: limitString(notes.title, 220),
    sessionOverview: limitString(notes.sessionOverview, 500),
    introduction: limitString(notes.introduction, 500),
    learningObjectives: limitStringList(notes.learningObjectives, 8, 220),
    keyTerms: limitStringList(notes.keyTerms, 10, 100),
    quickSummary: limitStringList(notes.quickSummary, 6, 220),
    summary: limitStringList(notes.summary, 6, 220),
    rememberPoints: limitStringList(notes.rememberPoints, 8, 180),
    definitions: (Array.isArray(notes.definitions) ? notes.definitions : []).slice(0, 10).map((item: any) => ({
      term: limitString(item?.term, 100),
      definition: limitString(item?.definition, 220),
    })),
    sections: (Array.isArray(notes.sections) ? notes.sections : []).slice(0, 6).map((item: any) => ({
      heading: limitString(item?.heading, 160),
      explanation: limitString(item?.explanation, 320),
      keyPoints: limitStringList(item?.keyPoints, 5, 180),
      examples: limitStringList(item?.examples, 3, 180),
      importantNotes: limitStringList(item?.importantNotes, 4, 180),
      conceptSummary: limitStringList(item?.conceptSummary, 3, 180),
    })),
    workedExamples: (Array.isArray(notes.workedExamples) ? notes.workedExamples : []).slice(0, 4).map((item: any) => ({
      title: limitString(item?.title, 160),
      steps: limitStringList(item?.steps, 5, 180),
      explanation: limitString(item?.explanation, 260),
    })),
    selfCheckQuestions: limitStringList(notes.selfCheckQuestions, 8, 180),
    veryShortAnswerQuestions: (Array.isArray(notes.veryShortAnswerQuestions) ? notes.veryShortAnswerQuestions : []).slice(0, 6).map((item: any) => ({
      question: limitString(item?.question, 180),
      answer: limitString(item?.answer, 220),
    })),
    mcqQuestions: (Array.isArray(notes.mcqQuestions) ? notes.mcqQuestions : []).slice(0, 6).map((item: any) => ({
      question: limitString(item?.question, 180),
      answer: limitString(item?.answer, 140),
    })),
  };
}

