function buildRenderableList(values: any[], maxItems: number, maxLengthPerItem: number) {
  const seen = new Set<string>();
  const result: string[] = [];
  for (const value of values) {
    const limited = limitString(value, maxLengthPerItem);
    const normalized = normalizeSourceText(limited);
    if (!limited || !normalized || seen.has(normalized)) {
      continue;
    }
    seen.add(normalized);
    result.push(limited);
    if (result.length >= maxItems) break;
  }
  return result;
}

function buildTeacherDeliverySpeakerNotes(input: {
  purpose?: any;
  explanation?: any[];
  questions?: any[];
  expectedResponses?: any[];
  misconceptions?: any[];
  boardWork?: any[];
  transition?: any;
  timingMinutes?: number;
}) {
  const normalizeCue = (prefix: string, value: any) => {
    const text = limitString(value, 220);
    if (!text) return "";
    return /^(purpose|explain|ask|listen for|correct|board work|transition|timing):/i.test(text)
      ? text
      : `${prefix}: ${text}`;
  };

  const notes = buildRenderableList([
    normalizeCue("Purpose", input.purpose),
    ...(Array.isArray(input.explanation) ? input.explanation.map((item) => normalizeCue("Explain", item)) : []),
    ...(Array.isArray(input.questions) ? input.questions.map((item) => normalizeCue("Ask", item)) : []),
    ...(Array.isArray(input.expectedResponses) ? input.expectedResponses.map((item) => normalizeCue("Listen for", item)) : []),
    ...(Array.isArray(input.misconceptions) ? input.misconceptions.map((item) => normalizeCue("Correct", item)) : []),
    ...(Array.isArray(input.boardWork) ? input.boardWork.map((item) => normalizeCue("Board work", item)) : []),
    normalizeCue("Transition", input.transition),
    input.timingMinutes ? normalizeCue("Timing", `about ${input.timingMinutes} minute${input.timingMinutes === 1 ? "" : "s"}.`) : "",
  ], 7, 220);

  return notes.length ? notes : ["Purpose: Teach the slide clearly and keep the lesson moving."];
}

function buildSubjectAwareVisualPlan(subject: string, title: string, conceptHint: string, purpose: string) {
  const normalizedSubject = String(subject || "").toLowerCase();
  const titleText = String(title || "the concept").trim();
  const hint = String(conceptHint || titleText).trim();

  if (isMathSubject(subject)) {
    return `A clean step-by-step mathematical diagram or board-style visual for ${hint}, showing the reasoning path students should follow during ${purpose}.`;
  }
  if (/\b(science|biology|chemistry|physics)\b/.test(normalizedSubject)) {
    return `A labelled classroom diagram for ${hint} that makes the process or structure visible while the teacher explains ${purpose}.`;
  }
  if (/\b(history|geography|social|civics|economics|political)\b/.test(normalizedSubject)) {
    return `A map, timeline, or cause-effect classroom visual for ${hint} that helps students organize the idea during ${purpose}.`;
  }
  if (/\b(english|language|literature|hindi|tamil|marathi|urdu|sanskrit)\b/.test(normalizedSubject)) {
    return `A text-support visual for ${hint}, such as an annotated excerpt, vocabulary map, or comparison frame, to support ${purpose}.`;
  }
  if (/\b(computer|coding|programming|informatics|it)\b/.test(normalizedSubject)) {
    return `A flowchart or code-logic visual for ${hint} that supports teacher explanation during ${purpose}.`;
  }
  return `A classroom-safe explainer visual for ${hint} that helps the teacher make ${purpose} easier to understand.`;
}

function buildDefaultPptSpeakerNotes(slide: any) {
  const teacherIntent = renderableToExportPlainText(slide?.teacherIntent);
  const studentTakeaway = renderableToExportPlainText(slide?.studentTakeaway);
  const bullets = Array.isArray(slide?.bulletPoints) ? slide.bulletPoints : [];
  const notes = Array.isArray(slide?.speakerNotes) ? slide.speakerNotes : [];
  const visualPlan = renderableToExportPlainText(slide?.visualPlan);
  const explanation = buildRenderableList([
    ...notes,
    ...bullets.slice(0, 3).map((item: any) => item ? `Explain: ${renderableToExportPlainText(item)}` : ""),
    studentTakeaway ? `Student takeaway: ${studentTakeaway}` : "",
    visualPlan ? `Use the visual to reinforce ${visualPlan}` : "",
  ], 6, 220);

  return buildTeacherDeliverySpeakerNotes({
    purpose: teacherIntent || "Teach this part of the lesson clearly.",
    explanation,
    transition: "Link this slide naturally to the next step in the lesson.",
    timingMinutes: Number(slide?.timeEstimateMinutes || 0) || undefined,
  });
}

function normalizeRenderableComparisonKey(value: any) {
  return normalizeSourceText(renderableToExportPlainText(value));
}

function dedupeRenderableValues(values: any[]) {
  const seen = new Set<string>();
  const result: any[] = [];
  for (const value of Array.isArray(values) ? values : []) {
    const key = normalizeRenderableComparisonKey(value);
    if (!key || seen.has(key)) continue;
    seen.add(key);
    result.push(value);
  }
  return result;
}

function condenseRenderableSlideLine(value: any, maxLength: number) {
  if (value && typeof value === "object" && !Array.isArray(value) && ("text" in value || "latex" in value || "displayLatex" in value)) {
    return structuredClone(value);
  }
  const raw = renderableToExportPlainText(value).replace(/\s+/g, " ").trim();
  if (!raw) return "";
  if (raw.length <= maxLength) return raw;
  const segments = raw.split(/(?<=[.:;!?])\s+/).filter(Boolean);
  const firstFit = segments.find((segment) => segment.length <= maxLength);
  if (firstFit) return firstFit;
  const commaFit = raw.split(/,\s+/).find((segment) => segment.length <= maxLength);
  if (commaFit) return commaFit;
  return `${raw.slice(0, Math.max(0, maxLength - 3)).trim()}...`;
}

function choosePptSlideTemplateId(slide: any, visualResolved: boolean) {
  const purpose = String(slide?.slidePurpose || slide?.templateSlideKey || slide?.slideType || "").toLowerCase();
  if (visualResolved && ["lesson_hook", "hook", "visual-explanation", "core_concept_b_visual", "worked_example", "title_identity"].includes(purpose)) {
    return "visual-focus";
  }
  if (["quick_assessment", "summary", "learning_outcomes", "guided_practice"].includes(purpose)) {
    return "textbook-clean";
  }
  return String(slide?.templateId || "academic-split");
}

function buildLeanPresentationCopy(input: {
  slide: any;
  bulletPoints: any[];
  onSlideText: any[];
  speakerNotes: any[];
  visualResolved: boolean;
}) {
  const purpose = String(input.slide?.slidePurpose || input.slide?.templateSlideKey || input.slide?.slideType || "").toLowerCase();
  const rawBullets = dedupeRenderableValues(input.bulletPoints);
  const rawOnSlide = dedupeRenderableValues(input.onSlideText);
  const sourceLines = dedupeRenderableValues([...rawOnSlide, ...rawBullets]);
  const visualLed = input.visualResolved;
  const depthHeavyPurpose = [
    "topic_introduction",
    "core_concept",
    "core_concept_a",
    "core_concept_b_visual",
    "visual_explainer",
    "comparison",
    "worked_example",
    "worked-example",
    "board_derivation",
  ].includes(purpose);

  const chipLimit = depthHeavyPurpose ? (visualLed ? 3 : 2) : visualLed ? 2 : 1;
  const bulletLimit = ["learning_outcomes", "summary", "quick_assessment", "guided_practice"].includes(purpose)
    ? 3
    : depthHeavyPurpose
    ? visualLed
      ? 5
      : 6
    : visualLed
    ? 3
    : 4;
  const chipMaxLength = depthHeavyPurpose ? (visualLed ? 104 : 118) : visualLed ? 88 : 96;
  const bulletMaxLength = depthHeavyPurpose ? (visualLed ? 150 : 168) : visualLed ? 118 : 132;

  const condensedChips = dedupeRenderableValues(
    sourceLines.slice(0, chipLimit).map((item) => condenseRenderableSlideLine(item, chipMaxLength)).filter(Boolean)
  );
  const chipKeys = new Set(condensedChips.map((item) => normalizeRenderableComparisonKey(item)));

  const condensedBullets = dedupeRenderableValues(
    sourceLines
      .filter((item) => !chipKeys.has(normalizeRenderableComparisonKey(item)))
      .map((item) => condenseRenderableSlideLine(item, bulletMaxLength))
      .filter(Boolean)
      .slice(0, bulletLimit)
  );

  const consumedKeys = new Set([
    ...condensedChips.map((item) => normalizeRenderableComparisonKey(item)),
    ...condensedBullets.map((item) => normalizeRenderableComparisonKey(item)),
  ]);

  const overflowNotes = sourceLines
    .filter((item) => !consumedKeys.has(normalizeRenderableComparisonKey(item)))
    .slice(0, depthHeavyPurpose ? 6 : 4)
    .map((item) => `Explain: ${renderableToExportPlainText(item)}`);

  const qualityFlags = [];
  if (sourceLines.length > condensedChips.length + condensedBullets.length) {
    qualityFlags.push("text-compressed-for-presentation");
  }
  if (visualLed) {
    qualityFlags.push("visual-first-layout");
  }

  return {
    onSlideText: condensedChips,
    bulletPoints: condensedBullets,
    speakerNotes: dedupeRenderableValues([...(Array.isArray(input.speakerNotes) ? input.speakerNotes : []), ...overflowNotes]),
    qualityFlags,
  };
}

type ResolvedVisualAssetRef = {
  kind: "image" | "svg";
  assetId: string;
  fileName: string;
  url: string;
  mimeType: string;
};

type TeacherDeckSpec = {
  title: string;
  audience: string;
  gradeLevel: string;
  subject: string;
  deliveryMode: string;
  templateId: string;
  presentonTemplate: string;
  deckReadiness: string;
  coverageStatus: string;
  visualIntegrityStatus: string;
  exportIntegrityStatus: string;
  slides: Array<{
    slideNumber: number;
    slideTitle: string;
    slidePurpose: string;
    teachingBeat: string;
    mustTeach: string[];
    onSlideContent: string[];
    speakerNotes: string[];
    visualDecision: string;
    visualResolved: boolean;
    visualRelevanceStatus: string;
    layoutIntent: "text-light-visual-first" | "concept-split" | "board-worked-example" | "text-led-minimal";
    timeEstimate: number;
    presentonTemplateHint: string;
    presentonMarkdown: string;
    resolvedVisualAssetRefs: ResolvedVisualAssetRef[];
    sourceSlide: any;
  }>;
};

type RenderedPresentationResult = {
  presentationId: string;
  pptxPath: string;
  editPath: string;
  renderDiagnostics: Record<string, any>;
  buffer: Buffer;
};

function inferSlideLayoutIntent(slide: any) {
  const purpose = String(slide?.slidePurpose || slide?.templateSlideKey || slide?.slideType || "").toLowerCase();
  if (slide?.visualResolved && ["worked_example", "worked-example"].includes(purpose)) {
    return "board-worked-example" as const;
  }
  if (slide?.visualResolved && ["lesson_hook", "hook", "core_concept_b_visual", "visual-explanation", "title_identity", "topic_introduction"].includes(purpose)) {
    return "text-light-visual-first" as const;
  }
  if (slide?.visualResolved) {
    return "concept-split" as const;
  }
  return "text-led-minimal" as const;
}

function mapPresentonTemplateHint(slide: any) {
  switch (inferSlideLayoutIntent(slide)) {
    case "text-light-visual-first":
      return "visual-first";
    case "board-worked-example":
      return "board-example";
    case "concept-split":
      return "concept-split";
    default:
      return "text-light";
  }
}

function getPublicBackendBaseUrl() {
  refreshRuntimeEnv();
  return (
    process.env.PRESENTON_ASSET_BASE_URL ||
    process.env.PUBLIC_BACKEND_BASE_URL ||
    `http://host.docker.internal:${PORT}`
  ).replace(/\/+$/, "");
}

function getPresentonConfig() {
  refreshRuntimeEnv();
  return {
    enabled: String(process.env.PRESENTON_ENABLED || "true").trim().toLowerCase() !== "false",
    versionTag: String(process.env.PRESENTON_VERSION_TAG || "v0.8.6-beta").trim(),
    baseUrl: String(process.env.PRESENTON_BASE_URL || "http://127.0.0.1:5002").trim().replace(/\/+$/, ""),
    username: String(process.env.PRESENTON_AUTH_USERNAME || "admin").trim(),
    password: String(process.env.PRESENTON_AUTH_PASSWORD || "presenton").trim(),
    timeoutMs: Math.max(30000, Number(process.env.PRESENTON_TIMEOUT_MS) || 300000),
    assetBaseUrl: getPublicBackendBaseUrl(),
    defaultTemplate: String(process.env.PRESENTON_TEMPLATE_DEFAULT || "general").trim(),
    templateMap: {
      "text-light-visual-first": String(process.env.PRESENTON_TEMPLATE_VISUAL_FIRST || "general").trim(),
      "concept-split": String(process.env.PRESENTON_TEMPLATE_CONCEPT_SPLIT || "general").trim(),
      "board-worked-example": String(process.env.PRESENTON_TEMPLATE_BOARD || "general").trim(),
      "text-led-minimal": String(process.env.PRESENTON_TEMPLATE_TEXT_LIGHT || "general").trim(),
    } as Record<string, string>,
  };
}

function buildPresentonAuthHeader(config = getPresentonConfig()) {
  return `Basic ${Buffer.from(`${config.username}:${config.password}`).toString("base64")}`;
}

async function ensurePersistedSvgVisualAsset(svgCode: string) {
  const normalizedSvg = String(svgCode || "").trim();
  if (!normalizedSvg) return { assetId: "", fileName: "", storagePath: "" };
  await fs.mkdir(PPT_ASSET_STORAGE_DIR, { recursive: true });
  const promptHash = createHash("sha1").update(normalizedSvg).digest("hex");
  const fileName = `${promptHash}.svg`;
  const outputPath = path.join(PPT_ASSET_STORAGE_DIR, fileName);
  try {
    await fs.access(outputPath);
  } catch {
    await fs.writeFile(outputPath, normalizedSvg, "utf8");
  }
  return {
    assetId: promptHash,
    fileName,
    storagePath: outputPath,
  };
}

async function buildResolvedVisualAssetRefsForSlide(slide: any) {
  const config = getPresentonConfig();
  const refs: ResolvedVisualAssetRef[] = [];
  const primaryAsset = Array.isArray(slide?.assets) ? slide.assets.find((asset: any) => asset?.visualRelevanceStatus === "valid") : null;
  if (primaryAsset?.storagePath) {
    const fileName = path.basename(String(primaryAsset.storagePath));
    refs.push({
      kind: String(primaryAsset?.mimeType || "").includes("svg") ? "svg" : "image",
      assetId: String(primaryAsset.assetId || primaryAsset.promptHash || fileName),
      fileName,
      url: `${config.assetBaseUrl}/api/ppt-assets/${encodeURIComponent(fileName)}`,
      mimeType: String(primaryAsset.mimeType || "image/png"),
    });
  } else if (slide?.svgDiagram?.visualRelevanceStatus === "valid" && slide?.svgDiagram?.svgCode) {
    const persisted = await ensurePersistedSvgVisualAsset(String(slide.svgDiagram.svgCode));
    if (persisted.fileName) {
      refs.push({
        kind: "svg",
        assetId: persisted.assetId,
        fileName: persisted.fileName,
        url: `${config.assetBaseUrl}/api/ppt-assets/${encodeURIComponent(persisted.fileName)}`,
        mimeType: "image/svg+xml",
      });
    }
  }
  return refs;
}

function renderSpeakerNotesForPresenton(slide: any) {
  return (Array.isArray(slide?.speakerNotes) ? slide.speakerNotes : [])
    .map((note: any) => renderableToExportPlainText(note).trim())
    .filter(Boolean)
    .slice(0, 8);
}

function buildPresentonSlideMarkdown(slide: any) {
  const title = renderableToExportPlainText(slide?.slideTitle || `Slide ${slide?.slideNumber || ""}`).trim();
  const chips = (Array.isArray(slide?.onSlideText) ? slide.onSlideText : [])
    .map((item: any) => renderableToExportPlainText(item).trim())
    .filter(Boolean)
    .slice(0, 2);
  const bullets = (Array.isArray(slide?.bulletPoints) ? slide.bulletPoints : [])
    .map((item: any) => renderableToExportPlainText(item).trim())
    .filter(Boolean)
    .slice(0, slide?.visualResolved ? 3 : 4);
  const refs = Array.isArray(slide?.resolvedVisualAssetRefs) ? slide.resolvedVisualAssetRefs : [];
  const visual = refs[0];
  const noteLines = renderSpeakerNotesForPresenton(slide);
  const layoutHint = String(slide?.presentonTemplateHint || mapPresentonTemplateHint(slide));
  const markdownLines = [
    `# ${title}`,
    ...chips.map((chip: string) => `> ${chip}`),
    ...bullets.map((bullet: string) => `- ${bullet}`),
    visual?.url ? `![${title}](${visual.url})` : "",
    "",
    `<!-- layout: ${layoutHint} -->`,
    `<!-- purpose: ${renderableToExportPlainText(slide?.slidePurpose || "")} -->`,
    ...(noteLines.length ? ["", "<!-- speaker-notes", ...noteLines, "-->"] : []),
  ].filter((line, index, arr) => !(line === "" && arr[index - 1] === ""));
  return markdownLines.join("\n").trim();
}

async function buildTeacherDeckSpecFromNormalizedPpt(ppt: any, sessionContext: { subject?: string; gradeLevel?: string }) {
  const config = getPresentonConfig();
  const slides = Array.isArray(ppt?.slides) ? ppt.slides : [];
  const teacherDeckSlides = [];
  for (const slide of slides) {
    const resolvedVisualAssetRefs = await buildResolvedVisualAssetRefsForSlide(slide);
    const layoutIntent = inferSlideLayoutIntent(slide);
    const presentonTemplateHint = mapPresentonTemplateHint({ ...slide, layoutIntent });
    const enrichedSlide = {
      ...slide,
      layoutIntent,
      presentonTemplateHint,
      resolvedVisualAssetRefs,
    };
    const presentonMarkdown = buildPresentonSlideMarkdown(enrichedSlide);
    teacherDeckSlides.push({
      slideNumber: Number(slide?.slideNumber || teacherDeckSlides.length + 1),
      slideTitle: renderableToExportPlainText(slide?.slideTitle || `Slide ${teacherDeckSlides.length + 1}`),
      slidePurpose: renderableToExportPlainText(slide?.slidePurpose || slide?.templateSlideTitle || ""),
      teachingBeat: renderableToExportPlainText(slide?.teachingBeat || ""),
      mustTeach: (Array.isArray(slide?.mustTeach) ? slide.mustTeach : []).map((item: any) => renderableToExportPlainText(item)).filter(Boolean),
      onSlideContent: [
        ...(Array.isArray(slide?.onSlideText) ? slide.onSlideText : []),
        ...(Array.isArray(slide?.bulletPoints) ? slide.bulletPoints : []),
      ].map((item: any) => renderableToExportPlainText(item)).filter(Boolean),
      speakerNotes: renderSpeakerNotesForPresenton(slide),
      visualDecision: String(slide?.visualDecision || "none"),
      visualResolved: Boolean(slide?.visualResolved),
      visualRelevanceStatus: String(slide?.visualRelevanceStatus || "none"),
      layoutIntent,
      timeEstimate: Number(slide?.timeEstimateMinutes || 0) || 4,
      presentonTemplateHint,
      presentonMarkdown,
      resolvedVisualAssetRefs,
      sourceSlide: enrichedSlide,
    });
  }
  const templateId = String(ppt?.templateId || "academic-split");
  const leadLayoutIntent = teacherDeckSlides.find((slide) => slide.layoutIntent)?.layoutIntent || "text-light-visual-first";
  return {
    title: renderableToExportPlainText(ppt?.presentationTitle || ppt?.title || "Session Presentation"),
    audience: renderableToExportPlainText(ppt?.audience || `${sessionContext.gradeLevel || "Grade"} classroom`),
    gradeLevel: String(sessionContext.gradeLevel || ""),
    subject: String(sessionContext.subject || ""),
    deliveryMode: String(ppt?.deckMode || "teacher-delivery"),
    templateId,
    presentonTemplate: config.templateMap[leadLayoutIntent] || config.defaultTemplate,
    deckReadiness: String(ppt?.deckReadiness || "needs-review"),
    coverageStatus: String(ppt?.coverageStatus || "partial"),
    visualIntegrityStatus: String(ppt?.visualIntegrityStatus || "needs-review"),
    exportIntegrityStatus: String(ppt?.exportIntegrityStatus || "ready"),
    slides: teacherDeckSlides,
  } satisfies TeacherDeckSpec;
}

function buildPresentonGenerationInstructions(deckSpec: TeacherDeckSpec) {
  const slideInstructions = deckSpec.slides.map((slide) =>
    `Slide ${slide.slideNumber}: use ${slide.layoutIntent}; keep visible text concise; preserve slide order; prefer the provided image if markdown contains one; do not invent extra images; do not add stock imagery; keep classroom tone professional.`
  );
  return [
    "Render this as an editable classroom PPTX.",
    "Treat slides_markdown as the source of truth for slide order and visible content.",
    "Do not use web search.",
    "Do not invent new pedagogy or new sections.",
    "Keep the deck concise and teacher-ready.",
    "If an image is present in markdown, use it.",
    "Do not replace provided images with stock imagery.",
    "Favor low-density educational slide composition.",
    ...slideInstructions,
  ].join("\n");
}

async function fetchPresentonPptxBuffer(pathOrUrl: string, config = getPresentonConfig()) {
  const normalized = String(pathOrUrl || "").trim();
  if (!normalized) {
    throw new Error("Presenton did not return a PPTX path.");
  }
  const targetUrl = /^https?:\/\//i.test(normalized) ? normalized : `${config.baseUrl}${normalized.startsWith("/") ? "" : "/"}${normalized}`;
  const controller = new AbortController();
  const timeoutHandle = setTimeout(() => controller.abort(), config.timeoutMs);
  try {
    const response = await fetch(targetUrl, {
      headers: {
        Authorization: buildPresentonAuthHeader(config),
      },
      signal: controller.signal,
    } as any);
    if (!response.ok) {
      throw new Error(`Failed to fetch Presenton PPTX artifact: ${response.status}`);
    }
    const arrayBuffer = await response.arrayBuffer();
    return Buffer.from(arrayBuffer);
  } finally {
    clearTimeout(timeoutHandle);
  }
}

async function renderPptxWithPresenton(deckSpec: TeacherDeckSpec) {
  const config = getPresentonConfig();
  if (!config.enabled) {
    throw new Error("Presenton integration is disabled.");
  }
  const payload = {
    content: `${deckSpec.title}\nSubject: ${deckSpec.subject}\nAudience: ${deckSpec.audience}`,
    slides_markdown: deckSpec.slides.map((slide) => slide.presentonMarkdown),
    instructions: buildPresentonGenerationInstructions(deckSpec),
    tone: "educational",
    verbosity: "concise",
    web_search: false,
    n_slides: deckSpec.slides.length,
    language: "English",
    template: deckSpec.presentonTemplate,
    include_table_of_contents: false,
    include_title_slide: false,
    export_as: "pptx",
  };

  const controller = new AbortController();
  const timeoutHandle = setTimeout(() => controller.abort(), config.timeoutMs);
  try {
    const response = await fetch(`${config.baseUrl}/api/v1/ppt/presentation/generate`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: buildPresentonAuthHeader(config),
      },
      body: JSON.stringify(payload),
      signal: controller.signal,
    } as any);
    if (!response.ok) {
      const text = await response.text();
      throw new Error(`Presenton render failed: ${response.status} ${text}`);
    }
    const json = await response.json();
    const buffer = await fetchPresentonPptxBuffer(String(json?.path || ""), config);
    return {
      presentationId: String(json?.presentation_id || ""),
      pptxPath: String(json?.path || ""),
      editPath: String(json?.edit_path || ""),
      renderDiagnostics: {
        template: deckSpec.presentonTemplate,
        slideCount: deckSpec.slides.length,
        sidecarBaseUrl: config.baseUrl,
      },
      buffer,
    } satisfies RenderedPresentationResult;
  } finally {
    clearTimeout(timeoutHandle);
  }
}

async function checkPresentonHealth() {
  const config = getPresentonConfig();
  const controller = new AbortController();
  const timeoutHandle = setTimeout(() => controller.abort(), Math.min(config.timeoutMs, 15000));
  try {
    const response = await fetch(`${config.baseUrl}/openapi.json`, {
      signal: controller.signal,
    } as any);
    return {
      ok: response.ok,
      status: response.status,
      baseUrl: config.baseUrl,
      enabled: config.enabled,
    };
  } catch (error: any) {
    return {
      ok: false,
      status: 0,
      baseUrl: config.baseUrl,
      enabled: config.enabled,
      error: String(error?.message || error),
    };
  } finally {
    clearTimeout(timeoutHandle);
  }
}

function buildDeterministicMaterialsFromSessionPlan(
  sessionPlan: any,
  context: {
    subject: string;
    gradeLevel: string;
    sessionTitle: string;
    sessionNumber: number;
    durationMinutes: number;
    learningOutcomes: string[];
    selectedChapters: string[];
    generationOptions?: SessionPptGenerationOptions;
  }
) {
  const templatePreset = getPptTemplatePreset(context.generationOptions?.pptTemplateId);
  const themePreset = PPT_THEME_PRESETS[context.generationOptions?.pptThemeId || "cbse-academic-blue"] || PPT_THEME_PRESETS["cbse-academic-blue"];
  const learningOutcomes = limitStringList(
    Array.isArray(sessionPlan?.learningOutcomes) ? sessionPlan.learningOutcomes : context.learningOutcomes,
    6,
    180
  );
  const teacherNotes = sessionPlan?.teacherLessonNotes || {};
  const studentNotes = sessionPlan?.studentLessonNotes || {};
  const theory = sessionPlan?.theory || {};
  const activities = Array.isArray(sessionPlan?.activities) ? sessionPlan.activities : [];
  const conceptFlow = Array.isArray(teacherNotes?.conceptFlow) ? teacherNotes.conceptFlow : [];
  const lessonBlocks = Array.isArray(teacherNotes?.lessonBlocks) ? teacherNotes.lessonBlocks : [];
  const classroomQuestions = Array.isArray(teacherNotes?.classroomQuestions) ? teacherNotes.classroomQuestions : [];
  const detailedMisconceptions = Array.isArray(teacherNotes?.commonMisconceptionsDetailed) ? teacherNotes.commonMisconceptionsDetailed : [];
  const workedExamples = Array.isArray(studentNotes?.workedExamples) ? studentNotes.workedExamples : [];
  const quickChecks = limitStringList(
    teacherNotes?.assessmentQuestions || studentNotes?.selfCheckQuestions || [],
    5,
    180
  );
  const recapPoints = limitStringList(
    teacherNotes?.sessionSummary || studentNotes?.summary || theory?.keyPoints || [],
    5,
    180
  );
  const homeworkTask = limitString(sessionPlan?.homework?.task, 240);
  const title = String(sessionPlan?.title || context.sessionTitle || `Session ${context.sessionNumber}`);
  const chapterText = limitStringList(context.selectedChapters, 3, 120).join(", ");
  const blackboardSummary = limitStringList(teacherNotes?.blackboardSummary || [], 4, 180);
  const teacherTips = limitStringList(teacherNotes?.teacherTips || [], 4, 180);
  const nextBridge = limitStringList(teacherNotes?.nextSessionBridge || [], 4, 180);
  const misconceptions = buildRenderableList([
    ...(Array.isArray(teacherNotes?.misconceptions) ? teacherNotes.misconceptions : []),
    ...detailedMisconceptions.flatMap((item: any) => item?.misconception ? [`${item.misconception} -> ${item.correction || "clarify with a direct example"}`] : []),
  ], 4, 200);
  const differentiationSupport = buildRenderableList([
    ...(teacherNotes?.differentiation?.slowLearners || []).map((item: any) => `Support: ${item}`),
    ...(teacherNotes?.differentiation?.advancedLearners || []).map((item: any) => `Extend: ${item}`),
  ], 4, 200);

  const makeSlide = (index: number, overrides: Record<string, any>) => {
    const inferredKey = GENERIC_ADAPTIVE_SLIDE_KEYS[index] || `adaptive_slide_${index + 1}`;
    const inferredLabel = inferredKey
      .split("_")
      .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
      .join(" ");
    return {
      templateId: templatePreset.templateId,
      templateSlideKey: inferredKey,
      templateSlideTitle: inferredLabel,
      isOptionalSlotFilled: true,
      slideNumber: index + 1,
      slideType: inferredKey.replace(/_/g, "-"),
      slideTitle: inferredLabel,
      learningOutcomeIds: learningOutcomes.slice(0, 2),
      topicCoverage: context.selectedChapters,
      teacherIntent: "",
      studentTakeaway: "",
      layout: "Title + 2-column visual explainer",
      bulletPoints: [],
      onSlideText: [],
      speakerNotes: [],
      visualPlan: "",
      svgDiagram: null,
      assets: [],
      animationHints: [],
      timeEstimateMinutes: Math.max(2, Math.round(context.durationMinutes / 12)),
      ...overrides,
    };
  };

  const slides = [
    makeSlide(0, {
      slideTitle: title,
      bulletPoints: limitStringList([
        `${context.subject} | ${context.gradeLevel}`,
        chapterText || "Current lesson focus",
        `${context.durationMinutes} minute session`,
      ], 3, 80),
      onSlideText: limitStringList([title, chapterText, `${context.subject} | ${context.gradeLevel}`], 3, 80),
      teacherIntent: "Introduce the session and set the learning purpose.",
      studentTakeaway: "Understand what today’s lesson is about.",
      speakerNotes: buildTeacherDeliverySpeakerNotes({
        purpose: "Open the lesson, set expectations, and establish relevance.",
        explanation: [teacherNotes?.sessionOverview, ...(teacherNotes?.lessonPurpose || [])],
        questions: classroomQuestions.slice(0, 1).map((item: any) => item?.question),
        expectedResponses: classroomQuestions.slice(0, 1).map((item: any) => item?.expectedResponse),
        transition: "Move from the lesson purpose into the explicit learning outcomes.",
        timingMinutes: 3,
      }),
      visualPlan: buildSubjectAwareVisualPlan(context.subject, title, chapterText || title, "the opening hook"),
    }),
    makeSlide(1, {
      slideTitle: "What We Will Learn",
      bulletPoints: learningOutcomes,
      onSlideText: learningOutcomes,
      teacherIntent: "Share the learning outcomes clearly.",
      studentTakeaway: "Know what they should learn by the end of class.",
      speakerNotes: buildTeacherDeliverySpeakerNotes({
        purpose: "Translate each outcome into a student-friendly classroom target.",
        explanation: [...learningOutcomes, ...(teacherNotes?.learningOutcomes || [])],
        transition: "After setting the targets, connect them to prior knowledge.",
        timingMinutes: 3,
      }),
    }),
    makeSlide(2, {
      slideTitle: "Recall and Prepare",
      bulletPoints: limitStringList(teacherNotes?.prerequisiteKnowledge || studentNotes?.quickRecall || [], 5, 180),
      onSlideText: limitStringList(teacherNotes?.prerequisiteKnowledge || studentNotes?.quickRecall || [], 4, 120),
      teacherIntent: "Activate prior knowledge before new learning.",
      studentTakeaway: "Reconnect with ideas needed for today’s topic.",
      speakerNotes: buildTeacherDeliverySpeakerNotes({
        purpose: "Recover prerequisite understanding before introducing new ideas.",
        explanation: teacherNotes?.previousSessionRecap || teacherNotes?.prerequisiteKnowledge || [],
        questions: classroomQuestions.slice(0, 2).map((item: any) => item?.question),
        expectedResponses: classroomQuestions.slice(0, 2).map((item: any) => item?.expectedResponse),
        transition: "Use the recall responses to bridge into the lesson hook.",
        timingMinutes: 4,
      }),
    }),
    makeSlide(3, {
      slideTitle: "Hook and Curiosity",
      bulletPoints: limitStringList([sessionPlan?.introduction, teacherNotes?.sessionOverview], 3, 180),
      onSlideText: limitStringList([sessionPlan?.introduction], 2, 140),
      teacherIntent: "Create curiosity and bridge into the lesson.",
      studentTakeaway: "See why the topic matters.",
      speakerNotes: buildTeacherDeliverySpeakerNotes({
        purpose: "Use a hook to make the lesson meaningful and discussion-ready.",
        explanation: [sessionPlan?.introduction, ...(teacherNotes?.lessonPurpose || []), ...teacherTips],
        questions: classroomQuestions.slice(0, 1).map((item: any) => item?.question),
        expectedResponses: classroomQuestions.slice(0, 1).flatMap((item: any) => [item?.expectedResponse, ...(item?.answerPoints || [])]),
        transition: "Once curiosity is active, name the concept directly.",
        timingMinutes: 4,
      }),
      visualPlan: buildSubjectAwareVisualPlan(context.subject, title, title, "the curiosity hook"),
    }),
    makeSlide(4, {
      slideTitle: "Topic Introduction",
      bulletPoints: limitStringList([
        theory?.overview,
        studentNotes?.introduction,
        ...(Array.isArray(theory?.keyPoints) ? theory.keyPoints : []),
        ...(studentNotes?.definitions || []).map((item: any) => `${item.term}: ${item.definition}`),
      ], 6, 200),
      onSlideText: limitStringList([theory?.overview, studentNotes?.introduction, ...(Array.isArray(theory?.keyPoints) ? theory.keyPoints.slice(0, 2) : [])], 4, 150),
      teacherIntent: "Introduce the central idea and vocabulary.",
      studentTakeaway: "Understand the main concept and basic terms.",
      speakerNotes: buildTeacherDeliverySpeakerNotes({
        purpose: "Define the idea clearly before moving into deeper explanation.",
        explanation: [theory?.overview, studentNotes?.introduction, ...(studentNotes?.definitions || []).slice(0, 2).map((item: any) => `${item.term}: ${item.definition}`)],
        misconceptions: misconceptions.slice(0, 1),
        boardWork: blackboardSummary.slice(0, 2),
        transition: "Move from the definition into the first core concept.",
        timingMinutes: 4,
      }),
    }),
    makeSlide(5, {
      slideTitle: limitString(conceptFlow?.[0]?.conceptName || lessonBlocks?.[0]?.title || "Core Concept A", 80),
      bulletPoints: limitStringList([
        conceptFlow?.[0]?.definition,
        conceptFlow?.[0]?.coreExplanation,
        ...(conceptFlow?.[0]?.keywords || []),
        ...(conceptFlow?.[0]?.examples || []),
        ...(lessonBlocks?.[0]?.explanation || []),
        ...(lessonBlocks?.[0]?.examples || []),
      ], 6, 200),
      onSlideText: limitStringList([
        conceptFlow?.[0]?.definition,
        ...(conceptFlow?.[0]?.keywords || []),
        ...(conceptFlow?.[0]?.examples || []).slice(0, 1),
      ], 4, 130),
      teacherIntent: "Build the first core concept clearly.",
      studentTakeaway: "Grasp the first major idea of the lesson.",
      speakerNotes: buildTeacherDeliverySpeakerNotes({
        purpose: "Teach the first core idea with direct explanation and examples.",
        explanation: [
          conceptFlow?.[0]?.coreExplanation,
          ...(conceptFlow?.[0]?.examples || []),
          ...(lessonBlocks?.[0]?.explanation || []),
          ...(lessonBlocks?.[0]?.examples || []),
        ],
        questions: [...(lessonBlocks?.[0]?.checkUnderstanding || [])],
        expectedResponses: [...(lessonBlocks?.[0]?.expectedAnswers || [])],
        misconceptions: misconceptions.slice(0, 2),
        boardWork: [...(lessonBlocks?.[0]?.boardWork || []), ...(lessonBlocks?.[0]?.boardSteps || [])],
        transition: "Shift from explanation to a more visual or relational representation.",
        timingMinutes: 5,
      }),
    }),
    makeSlide(6, {
      slideTitle: limitString(conceptFlow?.[1]?.conceptName || "Visual Explanation", 80),
      bulletPoints: limitStringList([
        conceptFlow?.[1]?.definition,
        conceptFlow?.[1]?.coreExplanation,
        ...(conceptFlow?.[1]?.examples || []),
        ...(lessonBlocks?.[1]?.explanation || []),
      ], 5, 200),
      onSlideText: limitStringList([
        ...(conceptFlow?.[1]?.keywords || conceptFlow?.[0]?.keywords || []),
        ...(conceptFlow?.[1]?.examples || []).slice(0, 1),
      ], 4, 110),
      teacherIntent: "Explain the second concept with visual emphasis.",
      studentTakeaway: "See the idea in a more visual form.",
      speakerNotes: buildTeacherDeliverySpeakerNotes({
        purpose: "Use a visual to make the concept easier to see, compare, or trace.",
        explanation: [
          conceptFlow?.[1]?.coreExplanation,
          ...(conceptFlow?.[1]?.examples || []),
          ...(conceptFlow?.[1]?.keywords || []),
          ...(conceptFlow?.[1]?.visuals || []),
        ],
        misconceptions: misconceptions.slice(0, 2),
        transition: "After the visual explanation, model the idea in action.",
        timingMinutes: 5,
      }),
      visualPlan: buildSubjectAwareVisualPlan(
        context.subject,
        conceptFlow?.[1]?.conceptName || title,
        conceptFlow?.[1]?.coreExplanation || conceptFlow?.[1]?.conceptName || title,
        "the visual explanation"
      ),
    }),
    makeSlide(7, {
      slideTitle: limitString(workedExamples?.[0]?.title || "Worked Example", 80),
      bulletPoints: limitStringList([
        workedExamples?.[0]?.problem,
        ...(workedExamples?.[0]?.steps || []),
        ...(workedExamples?.[0]?.solutionSteps || []),
        ...(lessonBlocks?.[1]?.examples || []),
      ], 6, 200),
      onSlideText: limitStringList([
        workedExamples?.[0]?.title,
        workedExamples?.[0]?.problem,
        ...(workedExamples?.[0]?.steps || []).slice(0, 2),
      ], 4, 140),
      teacherIntent: "Model the thinking process step by step.",
      studentTakeaway: "See how the concept is applied.",
      speakerNotes: buildTeacherDeliverySpeakerNotes({
        purpose: "Model the process out loud and show how to think through the example.",
        explanation: [
          workedExamples?.[0]?.explanation,
          ...(workedExamples?.[0]?.reasoning || []),
          ...(teacherNotes?.guidedPractice || []),
        ],
        questions: [...(lessonBlocks?.[1]?.checkUnderstanding || [])],
        expectedResponses: [...(lessonBlocks?.[1]?.expectedAnswers || [])],
        boardWork: [...(workedExamples?.[0]?.solutionSteps || []), ...(lessonBlocks?.[1]?.boardSteps || [])],
        transition: "Invite students to try the process with teacher support.",
        timingMinutes: 5,
      }),
      visualPlan: workedExamples?.[0]?.diagramRef
        ? buildSubjectAwareVisualPlan(context.subject, workedExamples?.[0]?.title || "Worked Example", workedExamples?.[0]?.problem || title, "the worked demonstration")
        : "",
    }),
    makeSlide(8, {
      slideTitle: "Guided Practice",
      bulletPoints: limitStringList([
        activities?.[0]?.name,
        ...(activities?.[0]?.instructions || []),
        ...(lessonBlocks?.[0]?.activity || []),
        workedExamples?.[1]?.problem,
      ], 6, 200),
      onSlideText: limitStringList([
        activities?.[0]?.name,
        ...(activities?.[0]?.instructions || []),
        workedExamples?.[1]?.title,
      ], 4, 130),
      teacherIntent: "Help students practice with support.",
      studentTakeaway: "Try the skill with guidance.",
      speakerNotes: buildTeacherDeliverySpeakerNotes({
        purpose: "Coach students through a supported practice task.",
        explanation: [...(activities?.[0]?.instructions || []), ...(teacherNotes?.guidedPractice || [])],
        questions: [...(lessonBlocks?.[0]?.checkUnderstanding || []), ...(classroomQuestions.slice(0, 1).map((item: any) => item?.question))],
        expectedResponses: [...(lessonBlocks?.[0]?.expectedAnswers || [])],
        misconceptions: differentiationSupport,
        transition: "Use the guided practice responses to launch a quick understanding check.",
        timingMinutes: Math.max(4, Number(activities?.[0]?.durationMinutes || 0) || 4),
      }),
    }),
    makeSlide(9, {
      slideTitle: "Quick Check",
      bulletPoints: quickChecks,
      onSlideText: quickChecks,
      teacherIntent: "Check understanding during the lesson.",
      studentTakeaway: "Reflect on what they can already answer.",
      speakerNotes: buildTeacherDeliverySpeakerNotes({
        purpose: "Diagnose understanding before closing the lesson.",
        explanation: [...(teacherNotes?.formativeChecks || [])],
        questions: [
          ...(teacherNotes?.assessmentQuestions || []),
          ...classroomQuestions.slice(0, 2).map((item: any) => item?.question),
        ],
        expectedResponses: classroomQuestions.slice(0, 2).flatMap((item: any) => [item?.expectedResponse, ...(item?.answerPoints || [])]),
        misconceptions: misconceptions.slice(0, 2),
        transition: "Use the answers to reinforce the final takeaways.",
        timingMinutes: 4,
      }),
    }),
    makeSlide(10, {
      slideTitle: "Key Takeaways",
      bulletPoints: recapPoints,
      onSlideText: recapPoints,
      teacherIntent: "Summarize the important points clearly.",
      studentTakeaway: "Leave with the main ideas remembered.",
      speakerNotes: buildTeacherDeliverySpeakerNotes({
        purpose: "Synthesize the lesson and make the memory anchors explicit.",
        explanation: [
          ...(teacherNotes?.sessionSummary || []),
          ...(studentNotes?.rememberPoints || []),
          ...blackboardSummary,
        ],
        misconceptions: misconceptions.slice(0, 1),
        transition: "Close by assigning the follow-through task and pointing ahead.",
        timingMinutes: 3,
      }),
    }),
    makeSlide(11, {
      slideTitle: "Homework and Next Step",
      bulletPoints: limitStringList([
        homeworkTask,
        ...(teacherNotes?.nextSessionBridge || []),
      ], 4, 180),
      onSlideText: limitStringList([
        homeworkTask,
        ...(teacherNotes?.nextSessionBridge || []),
      ], 3, 120),
      teacherIntent: "Close the lesson and set up follow-through.",
      studentTakeaway: "Know the next task and how today connects forward.",
      speakerNotes: buildTeacherDeliverySpeakerNotes({
        purpose: "End the class with clear follow-through and future connection.",
        explanation: [homeworkTask, ...nextBridge],
        questions: ["Ask one student to restate the homework and one student to restate the main lesson idea."],
        expectedResponses: ["Students should state the task correctly and connect it to today’s concept."],
        transition: "End the session with a confident recap and preview of the next class.",
        timingMinutes: 3,
      }),
    }),
  ];

  return {
    materials: {
      ppt: {
        templateId: templatePreset.templateId,
        templateName: templatePreset.templateName,
        themeId: themePreset.themeId,
        title,
        presentationTitle: title,
        presentationGoal: limitString(teacherNotes?.sessionOverview || `Teach ${title} clearly in class.`, 220),
        audience: `${context.gradeLevel} classroom`,
        theme: themePreset.themeName,
        themeTokens: {
          fonts: themePreset.fonts,
          colors: themePreset.colors,
          visualStyle: themePreset.visualStyle,
        },
        coverageSummary: {
          learningOutcomesCovered: learningOutcomes,
          topicsCovered: context.selectedChapters,
          taughtConceptsCovered: limitStringList(conceptFlow.map((item: any) => item?.conceptName), 6, 140),
          omittedContent: [],
        },
        slides,
      },
      pdf: {
        documentTitle: `${title} - Student Revision Notes`,
        keyInformation: recapPoints.length ? recapPoints : learningOutcomes,
      },
      docx: {
        outlineTitle: `${title} - Teacher Lesson Outline`,
        sections: limitStringList([
          teacherNotes?.sessionOverview,
          theory?.overview,
          ...(teacherNotes?.teachingSequence || []),
        ], 6, 220),
      },
    },
  };
}

function buildAssessmentSectionId(title: string, index = 0) {
  const normalized = normalizeSourceText(title || "").replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, "");
  return normalized ? `section-${normalized}` : `section-${index + 1}`;
}

function normalizeAssessmentSectionTitle(value: any) {
  return String(value || "").replace(/\s+/g, " ").trim();
}

function dedupeAssessmentSections(sections: any[] = []) {
  const seen = new Set<string>();
  return sections.filter((section: any, index: number) => {
    const title = normalizeAssessmentSectionTitle(section?.title || "");
    if (!title) return false;
    const id = String(section?.id || buildAssessmentSectionId(title, index)).trim();
    const key = `${id}::${normalizeSourceText(title)}`;
    if (seen.has(key)) return false;
    seen.add(key);
    section.id = id;
    section.title = title;
    return true;
  });
}

function parseAssessmentSectionFromMarksLine(line: any, index: number, source: "assessment_framework") {
  const cleaned = String(line || "").replace(/^[•\-\u2022]\s*/, "").replace(/\s+/g, " ").trim();
  if (!cleaned) return null;
  const marksMatch = cleaned.match(/\(?\b(\d+(?:\.\d+)?)\s*marks?\b\)?/i);
  const title = normalizeAssessmentSectionTitle(
    cleaned
      .replace(/\(\s*\d+(?:\.\d+)?\s*marks?\s*\)/i, "")
      .replace(/\b\d+(?:\.\d+)?\s*marks?\b/i, "")
      .replace(/\s*[-–—:]\s*$/u, "")
  );
  if (!title) return null;
  return {
    id: buildAssessmentSectionId(title, index),
    title,
    marks: marksMatch ? Number(marksMatch[1]) : undefined,
    source,
  };
}

function doesAssessmentCandidateMatchSelectedChapters(candidates: any[], selectedKeys: Set<string>) {
  if (!selectedKeys.size) return false;
  const normalizedCandidates = uniqueStrings((candidates || []).map((value) => String(value || "")))
    .map((value) => normalizeSourceText(String(value || "")))
    .filter(Boolean);
  return normalizedCandidates.some((candidate) =>
    [...selectedKeys].some((selected) =>
      candidate === selected || candidate.includes(selected) || selected.includes(candidate)
    )
  );
}

function deriveAssessmentSectionsFromCurriculumStructure(
  curriculumStructure: any,
  selectedChapters: string[] = [],
  gradeLevel = ""
) {
  const normalizedStructure = getNormalizedStructureFromCurriculum(curriculumStructure);
  const selectedKeys = new Set(
    uniqueStrings(selectedChapters || [])
      .map((value) => normalizeSourceText(String(value || "")))
      .filter(Boolean)
  );
  if (!normalizedStructure?.classes?.length || !selectedKeys.size) {
    return [];
  }

  const targetGrade = canonicalizeClassName(gradeLevel || "");
  const classes = (normalizedStructure.classes || []).filter((cls: any) => {
    if (!targetGrade) return true;
    const className = canonicalizeClassName(cls?.class_name || "");
    return !className || className === targetGrade;
  });

  const matchedSections: any[] = [];
  classes.forEach((cls: any) => {
    (cls?.units || []).forEach((unit: any) => {
      const unitSectionTitle = normalizeAssessmentSectionTitle(unit?.part_or_section || "");
      const unitMatches = doesAssessmentCandidateMatchSelectedChapters([
        unit?.unit_name,
        ...(unit?.topics || []),
        ...(unit?.subtopics || []),
        ...(unit?.key_concepts || []),
      ], selectedKeys);
      if (unitMatches && unitSectionTitle) {
        matchedSections.push({
          id: buildAssessmentSectionId(unitSectionTitle, matchedSections.length),
          title: unitSectionTitle,
          source: "curriculum" as const,
        });
      }

      (unit?.chapters || []).forEach((chapter: any) => {
        const chapterSectionTitle = normalizeAssessmentSectionTitle(
          chapter?.part_or_section || chapter?.exam_section_name || unit?.part_or_section || ""
        );
        const chapterMatches = doesAssessmentCandidateMatchSelectedChapters([
          chapter?.chapter_name,
          chapter?.source_chapter_name,
          chapter?.content_path,
          ...(chapter?.topics || []),
          ...(chapter?.subtopics || []),
          ...(chapter?.key_concepts || []),
        ], selectedKeys);
        if (chapterMatches && chapterSectionTitle) {
          matchedSections.push({
            id: buildAssessmentSectionId(chapterSectionTitle, matchedSections.length),
            title: chapterSectionTitle,
            source: "curriculum" as const,
          });
        }
      });
    });
  });

  return dedupeAssessmentSections(matchedSections);
}

function deriveAssessmentSectionsFromFramework(curriculumStructure: any, gradeLevel = "") {
  const normalizedStructure = getNormalizedStructureFromCurriculum(curriculumStructure);
  if (!normalizedStructure) return [];

  const targetGrade = canonicalizeClassName(gradeLevel || "");
  const matchingClass = (normalizedStructure?.classes || []).find((cls: any) => {
    if (!targetGrade) return true;
    const className = canonicalizeClassName(cls?.class_name || "");
    return !className || className === targetGrade;
  });

  const assessmentInformation =
    normalizedStructure?.assessment_information ||
    matchingClass?.assessment_information ||
    matchingClass?.assessment_framework ||
    normalizedStructure?.assessment_framework ||
    {};
  const marksDistribution = Array.isArray(assessmentInformation?.marks_distribution)
    ? assessmentInformation.marks_distribution
    : [];

  return dedupeAssessmentSections(
    marksDistribution
      .map((line: any, index: number) => parseAssessmentSectionFromMarksLine(line, index, "assessment_framework"))
      .filter(Boolean)
  );
}

function deriveAssessmentSectionsForSession({
  curriculumStructure,
  selectedChapters = [],
  gradeLevel = "",
}: {
  curriculumStructure: any;
  selectedChapters?: string[];
  gradeLevel?: string;
}) {
  const matchedCurriculumSections = deriveAssessmentSectionsFromCurriculumStructure(
    curriculumStructure,
    selectedChapters,
    gradeLevel
  );
  if (matchedCurriculumSections.length) {
    return matchedCurriculumSections;
  }

  const assessmentFrameworkSections = deriveAssessmentSectionsFromFramework(curriculumStructure, gradeLevel);
  if (assessmentFrameworkSections.length) {
    return assessmentFrameworkSections;
  }

  return [{
    id: buildAssessmentSectionId("Assessment", 0),
    title: "Assessment",
    source: "fallback" as const,
  }];
}

function buildRequestedSubtypeSequence(
  customization: SessionAssessmentCustomization | null | undefined,
  target: "shortAnswer" | "longAnswer"
) {
  const sourceTypes = Array.isArray(customization?.questionTypes) ? customization!.questionTypes! : [];
  const includedTypes =
    target === "shortAnswer"
      ? (["veryShortAnswer", "shortAnswer"] as AssessmentRenderedSubtype[])
      : (["longAnswer", "caseStudy"] as AssessmentRenderedSubtype[]);

  return sourceTypes.flatMap((item) =>
    includedTypes.includes(item.type as AssessmentRenderedSubtype)
      ? Array.from({ length: Math.max(0, Number(item.questionCount || 0)) }, () => ({
          questionSubtype: item.type as AssessmentRenderedSubtype,
          marksEach: Number(item.marksEach || 0),
        }))
      : []
  );
}

function parseTopLevelJsonObjectMembers(objectText: string) {
  const source = String(objectText || "");
  if (!source.trim().startsWith("{")) return null;
  const members: Array<{ key: string; valueText: string }> = [];
  let index = 0;

  const skipWhitespace = () => {
    while (index < source.length && /\s/.test(source[index])) index += 1;
  };

  const readJsonStringToken = () => {
    if (source[index] !== "\"") return null;
    const start = index;
    index += 1;
    let escaped = false;
    while (index < source.length) {
      const char = source[index];
      if (!escaped && char === "\"") {
        index += 1;
        return source.slice(start, index);
      }
      escaped = !escaped && char === "\\";
      if (char !== "\\") escaped = false;
      index += 1;
    }
    return null;
  };

  const readBalancedValue = (openChar: string, closeChar: string) => {
    const start = index;
    let depth = 0;
    let inString = false;
    let escaped = false;
    while (index < source.length) {
      const char = source[index];
      if (inString) {
        escaped = !escaped && char === "\\";
        if (!escaped && char === "\"") inString = false;
        if (char !== "\\") escaped = false;
        index += 1;
        continue;
      }
      if (char === "\"") {
        inString = true;
        index += 1;
        continue;
      }
      if (char === openChar) depth += 1;
      if (char === closeChar) {
        depth -= 1;
        index += 1;
        if (depth === 0) {
          return source.slice(start, index);
        }
        continue;
      }
      index += 1;
    }
    return null;
  };

  const readPrimitiveValue = () => {
    const start = index;
    while (index < source.length && source[index] !== "," && source[index] !== "}") {
      index += 1;
    }
    return source.slice(start, index).trim();
  };

  skipWhitespace();
  if (source[index] !== "{") return null;
  index += 1;

  while (index < source.length) {
    skipWhitespace();
    if (source[index] === "}") {
      index += 1;
      break;
    }
    const keyToken = readJsonStringToken();
    if (!keyToken) return null;
    const key = JSON.parse(keyToken);
    skipWhitespace();
    if (source[index] !== ":") return null;
    index += 1;
    skipWhitespace();

    let valueText: string | null = null;
    const char = source[index];
    if (char === "\"") {
      valueText = readJsonStringToken();
    } else if (char === "{") {
      valueText = readBalancedValue("{", "}");
    } else if (char === "[") {
      valueText = readBalancedValue("[", "]");
    } else {
      valueText = readPrimitiveValue();
    }
    if (valueText == null) return null;
    members.push({ key, valueText });

    skipWhitespace();
    if (source[index] === ",") {
      index += 1;
      continue;
    }
    if (source[index] === "}") {
      index += 1;
      break;
    }
  }

  return members;
}

function mergeDuplicateArrayMembers(objectText: string, keysToMerge: string[]) {
  const members = parseTopLevelJsonObjectMembers(objectText);
  if (!members) return objectText;

  const mergeKeySet = new Set(keysToMerge);
  const mergedMembers: Array<{ key: string; valueText: string }> = [];
  const mergedIndexByKey = new Map<string, number>();

  const mergeArrayValueText = (left: string, right: string) => {
    const leftItems = left.trim().replace(/^\[/, "").replace(/\]$/, "").trim();
    const rightItems = right.trim().replace(/^\[/, "").replace(/\]$/, "").trim();
    if (!leftItems) return `[${rightItems}]`;
    if (!rightItems) return `[${leftItems}]`;
    return `[${leftItems},${rightItems}]`;
  };

  members.forEach((member) => {
    if (
      mergeKeySet.has(member.key) &&
      member.valueText.trim().startsWith("[") &&
      mergedIndexByKey.has(member.key)
    ) {
      const targetIndex = mergedIndexByKey.get(member.key)!;
      mergedMembers[targetIndex] = {
        ...mergedMembers[targetIndex],
        valueText: mergeArrayValueText(mergedMembers[targetIndex].valueText, member.valueText),
      };
      return;
    }

    if (mergeKeySet.has(member.key) && member.valueText.trim().startsWith("[")) {
      mergedIndexByKey.set(member.key, mergedMembers.length);
    }
    mergedMembers.push(member);
  });

  return `{\n${mergedMembers.map((member) => `  ${JSON.stringify(member.key)}: ${member.valueText}`).join(",\n")}\n}`;
}

function repairDuplicateAssessmentArrayKeys(rawJsonText: string) {
  const source = String(rawJsonText || "");
  const repairObjectProperty = (input: string, propertyName: string, keysToMerge: string[]) => {
    const propertyToken = `"${propertyName}"`;
    const propertyIndex = input.indexOf(propertyToken);
    if (propertyIndex === -1) return input;
    const colonIndex = input.indexOf(":", propertyIndex + propertyToken.length);
    if (colonIndex === -1) return input;
    const openBraceIndex = input.indexOf("{", colonIndex + 1);
    if (openBraceIndex === -1) return input;

    let index = openBraceIndex;
    let depth = 0;
    let inString = false;
    let escaped = false;
    while (index < input.length) {
      const char = input[index];
      if (inString) {
        escaped = !escaped && char === "\\";
        if (!escaped && char === "\"") inString = false;
        if (char !== "\\") escaped = false;
        index += 1;
        continue;
      }
      if (char === "\"") {
        inString = true;
        index += 1;
        continue;
      }
      if (char === "{") depth += 1;
      if (char === "}") {
        depth -= 1;
        index += 1;
        if (depth === 0) {
          const originalObjectText = input.slice(openBraceIndex, index);
          const repairedObjectText = mergeDuplicateArrayMembers(originalObjectText, keysToMerge);
          return `${input.slice(0, openBraceIndex)}${repairedObjectText}${input.slice(index)}`;
        }
        continue;
      }
      index += 1;
    }
    return input;
  };

  let repaired = repairObjectProperty(source, "assessment", ["mcq", "shortAnswer", "longAnswer"]);
  repaired = repairObjectProperty(repaired, "answerKey", ["mcq", "shortAnswer", "longAnswer", "generalMarkingGuidance"]);
  return repaired;
}

function repairAssessmentFrameworkStringArrays(rawJsonText: string) {
  let repaired = String(rawJsonText || "");
  const stringArrayFields = [
    "marks_distribution",
    "question_paper_design",
    "competency_weightage",
    "bloom_levels",
    "internal_assessment",
    "practical_assessment",
    "project_assessment",
  ];

  for (const fieldName of stringArrayFields) {
    const pattern = new RegExp(`("${fieldName}"\\s*:\\s*\\[)([\\s\\S]*?)(\\])`, "g");
    repaired = repaired.replace(pattern, (_match, prefix, body, suffix) => {
      const normalizedBody = String(body || "").replace(
        /"([^"\n]+?)"\s*:\s*"([^"\n]+?)"/g,
        (_inner, left, right) => JSON.stringify(`${left}: ${right}`)
      );
      return `${prefix}${normalizedBody}${suffix}`;
    });
  }

  return repaired;
}

function buildExpectedAssessmentQuestionSpecs(customization: SessionAssessmentCustomization) {
  const requestedQuestionTypes = Array.isArray(customization.questionTypes) ? customization.questionTypes : [];
  return requestedQuestionTypes.flatMap((item) =>
    Array.from({ length: Math.max(0, Number(item.questionCount || 0)) }, (_, index) => ({
      requestIndex: index,
      type: item.type === "mcq" ? "mcq" : item.type === "veryShortAnswer" || item.type === "shortAnswer" ? "shortAnswer" : "longAnswer",
      subtype: item.type as AssessmentRenderedSubtype,
      label: String(item.label || ""),
      marksEach: Number(item.marksEach || 0),
    }))
  );
}

function coerceLegacyAssessmentToCanonicalShape(assessment: any) {
  if (!assessment || typeof assessment !== "object") return {};
  if (assessment.paper && Array.isArray(assessment.paper.questions)) {
    return assessment;
  }

  const legacyMcq = Array.isArray(assessment.mcq) ? assessment.mcq : [];
  const legacyShortAnswer = Array.isArray(assessment.shortAnswer) ? assessment.shortAnswer : [];
  const legacyLongAnswer = Array.isArray(assessment.longAnswer) ? assessment.longAnswer : [];
  const legacySections = Array.isArray(assessment.sections) ? assessment.sections : [];
  const legacyAnswerKey = assessment.answerKey && typeof assessment.answerKey === "object" ? assessment.answerKey : {};

  const questions = [
    ...legacyMcq.map((item: any) => ({
      id: item?.id,
      questionNumber: undefined,
      sectionId: item?.sectionId,
      sectionTitle: item?.sectionTitle,
      type: "mcq" as const,
      subtype: "mcq" as const,
      prompt: item?.question || "",
      options: Array.isArray(item?.options) ? item.options : [],
      marks: Number(item?.marks || 0),
      expectedLength: undefined,
      learningOutcomeRefs: Array.isArray(item?.learningOutcomeIds) ? item.learningOutcomeIds : [],
      conceptRefs: [],
      topicCoverage: Array.isArray(item?.topicCoverage) ? item.topicCoverage : [],
      subtopicCoverage: [],
      bloomsLevel: item?.bloomsLevel || "",
      competencyTag: "",
      difficulty: item?.difficulty || "",
      sourceEvidence: [],
    })),
    ...legacyShortAnswer.map((item: any) => ({
      id: item?.id,
      questionNumber: undefined,
      sectionId: item?.sectionId,
      sectionTitle: item?.sectionTitle,
      type: "shortAnswer" as const,
      subtype: item?.questionSubtype || "shortAnswer",
      prompt: item?.question || "",
      options: [],
      marks: Number(item?.marks || 0),
      expectedLength: item?.expectedLength || "",
      learningOutcomeRefs: Array.isArray(item?.learningOutcomeIds) ? item.learningOutcomeIds : [],
      conceptRefs: [],
      topicCoverage: Array.isArray(item?.topicCoverage) ? item.topicCoverage : [],
      subtopicCoverage: [],
      bloomsLevel: item?.bloomsLevel || "",
      competencyTag: "",
      difficulty: item?.difficulty || "",
      sourceEvidence: [],
    })),
    ...legacyLongAnswer.map((item: any) => ({
      id: item?.id,
      questionNumber: undefined,
      sectionId: item?.sectionId,
      sectionTitle: item?.sectionTitle,
      type: "longAnswer" as const,
      subtype: item?.questionSubtype || "longAnswer",
      prompt: item?.question || "",
      options: [],
      marks: Number(item?.marks || 0),
      expectedLength: item?.expectedLength || "",
      learningOutcomeRefs: Array.isArray(item?.learningOutcomeIds) ? item.learningOutcomeIds : [],
      conceptRefs: [],
      topicCoverage: Array.isArray(item?.topicCoverage) ? item.topicCoverage : [],
      subtopicCoverage: [],
      bloomsLevel: item?.bloomsLevel || "",
      competencyTag: "",
      difficulty: item?.difficulty || "",
      sourceEvidence: [],
    })),
  ];

  const answerKeyItems = [
    ...(Array.isArray(legacyAnswerKey?.mcq) ? legacyAnswerKey.mcq : []).map((item: any) => ({
      questionId: item?.id,
      sectionId: item?.sectionId,
      sectionTitle: item?.sectionTitle,
      answer: item?.answer || "",
      explanation: item?.explanation || "",
      marks: Number(item?.marks || 0),
      subtype: item?.questionSubtype || "mcq",
    })),
    ...(Array.isArray(legacyAnswerKey?.shortAnswer) ? legacyAnswerKey.shortAnswer : []).map((item: any) => ({
      questionId: item?.id,
      sectionId: item?.sectionId,
      sectionTitle: item?.sectionTitle,
      answer: item?.answer || "",
      explanation: "",
      marks: Number(item?.marks || 0),
      subtype: item?.questionSubtype || "shortAnswer",
    })),
    ...(Array.isArray(legacyAnswerKey?.longAnswer) ? legacyAnswerKey.longAnswer : []).map((item: any) => ({
      questionId: item?.id,
      sectionId: item?.sectionId,
      sectionTitle: item?.sectionTitle,
      answer: item?.answer || "",
      explanation: "",
      marks: Number(item?.marks || 0),
      subtype: item?.questionSubtype || "longAnswer",
    })),
  ];

  const rubricsItems = [
    ...(Array.isArray(legacyAnswerKey?.shortAnswer) ? legacyAnswerKey.shortAnswer : []).map((item: any) => ({
      questionId: item?.id,
      totalMarks: Number(item?.marks || 0),
      criteria: uniqueStrings(item?.rubric || []).map((criterion: string) => ({ criterion, marks: undefined })),
      sampleAnswer: item?.answer || "",
    })),
    ...(Array.isArray(legacyAnswerKey?.longAnswer) ? legacyAnswerKey.longAnswer : []).map((item: any) => ({
      questionId: item?.id,
      totalMarks: Number(item?.marks || 0),
      criteria: uniqueStrings(item?.rubric || []).map((criterion: string) => ({ criterion, marks: undefined })),
      sampleAnswer: item?.answer || "",
    })),
  ];

  return {
    meta: {
      ...(assessment.assessmentMeta && typeof assessment.assessmentMeta === "object" ? assessment.assessmentMeta : {}),
    },
    sessionAnalysis: {
      assessedLearningOutcomes: [],
      assessedConcepts: [],
      conceptCoveragePriorities: [],
      misconceptionTargets: [],
      competencyFocus: [],
    },
    blueprint: {
      ...(assessment.blueprint && typeof assessment.blueprint === "object" ? assessment.blueprint : {}),
    },
    paper: {
      instructions: Array.isArray(assessment.assessmentMeta?.instructions) ? assessment.assessmentMeta.instructions : [],
      sections: legacySections,
      questions,
    },
    evaluation: {
      answerKey: { items: answerKeyItems },
      markingScheme: { items: [] },
      rubrics: { items: rubricsItems },
      generalInstructions: Array.isArray(legacyAnswerKey?.generalMarkingGuidance) ? legacyAnswerKey.generalMarkingGuidance : [],
      evaluatorInstructions: [],
      moderationNotes: [],
    },
    summary: assessment.summary && typeof assessment.summary === "object" ? assessment.summary : {},
    validation: assessment.validation && typeof assessment.validation === "object" ? assessment.validation : {},
  };
}

function deriveAssessmentMarkBreakdown(criteriaItems: any[] = [], totalMarks = 0) {
  const normalizedCriteria = uniqueStrings(criteriaItems || []).map((criterion) => String(criterion || "").trim()).filter(Boolean);
  if (!normalizedCriteria.length) {
    return totalMarks > 0
      ? [{ criterion: "Award marks for a complete correct response.", marks: totalMarks }]
      : [];
  }

  let remainingMarks = Math.max(0, Number(totalMarks || 0));
  const breakdown = normalizedCriteria.map((criterion, index) => {
    const explicitMatch = criterion.match(/(\d+(?:\.\d+)?)\s*marks?/i);
    const explicitMarks = explicitMatch ? Number(explicitMatch[1]) : undefined;
    const autoMarks =
      explicitMarks != null
        ? explicitMarks
        : remainingMarks > 0
        ? Math.max(1, Math.floor(remainingMarks / Math.max(1, normalizedCriteria.length - index)))
        : undefined;
    if (autoMarks != null) {
      remainingMarks = Math.max(0, remainingMarks - autoMarks);
    }
    return {
      criterion,
      marks: autoMarks,
    };
  });

  if (remainingMarks > 0 && breakdown.length) {
    breakdown[breakdown.length - 1].marks = Number(breakdown[breakdown.length - 1].marks || 0) + remainingMarks;
  }
  return breakdown;
}

function normalizeAssessmentResponseToCustomization(
  generatedAssessment: any,
  customization: SessionAssessmentCustomization,
  defaults: {
    durationMinutes: number;
    language: string;
    preferredDifficulty: string;
  },
  expectedSectionsInput: any[] = []
) {
  const assessment = coerceLegacyAssessmentToCanonicalShape(
    generatedAssessment && typeof generatedAssessment === "object" ? { ...generatedAssessment } : {}
  );
  const expectedSections = dedupeAssessmentSections(
    (Array.isArray(expectedSectionsInput) && expectedSectionsInput.length ? expectedSectionsInput : [{
      id: buildAssessmentSectionId("Assessment", 0),
      title: "Assessment",
      source: "fallback",
    }]).map((section: any, index: number) => ({
      id: String(section?.id || buildAssessmentSectionId(section?.title || "Assessment", index)).trim(),
      title: normalizeAssessmentSectionTitle(section?.title || "Assessment"),
      marks: section?.marks != null ? Number(section.marks) : undefined,
      source: section?.source || "fallback",
    }))
  );
  const expectedSectionsById = new Map(expectedSections.map((section: any) => [String(section.id || "").trim(), section]));
  const expectedSectionsByTitle = new Map(
    expectedSections.map((section: any) => [normalizeSourceText(section.title || ""), section])
  );
  const requestedQuestionTypes = Array.isArray(customization.questionTypes) ? customization.questionTypes : [];
  const expectedQuestionSpecs = buildExpectedAssessmentQuestionSpecs(customization);
  const rawQuestions = Array.isArray(assessment?.paper?.questions) ? assessment.paper.questions : [];
  if (rawQuestions.length !== expectedQuestionSpecs.length) {
    throw new Error(`Assessment generation did not match the requested total question count (${expectedQuestionSpecs.length}).`);
  }

  const legacyToNormalizedId = new Map<string, string>();
  const makeContinuousQuestionId = (questionNumber: number) => `q${questionNumber}`;
  const resolveQuestionSection = (item: any, label: string) => {
    const requestedId = String(item?.sectionId || "").trim();
    const requestedTitle = normalizeAssessmentSectionTitle(item?.sectionTitle || "");
    const matchedSection =
      expectedSectionsById.get(requestedId) ||
      expectedSectionsByTitle.get(normalizeSourceText(requestedTitle || "")) ||
      (expectedSections.length === 1 ? expectedSections[0] : null);
    if (!matchedSection) {
      throw new Error(`Assessment generation did not assign a valid section for ${label}.`);
    }
    return {
      sectionId: matchedSection.id,
      sectionTitle: matchedSection.title,
    };
  };

  const normalizedQuestions = rawQuestions.map((item: any, index: number) => {
    const expectedSpec = expectedQuestionSpecs[index];
    const normalizedId = makeContinuousQuestionId(index + 1);
    const sectionRef = resolveQuestionSection(item, `${expectedSpec.type} question ${index + 1}`);
    if (typeof item?.id === "string" && item.id.trim()) {
      legacyToNormalizedId.set(item.id.trim(), normalizedId);
    }
    return {
      id: normalizedId,
      questionNumber: index + 1,
      sectionId: sectionRef.sectionId,
      sectionTitle: sectionRef.sectionTitle,
      type: expectedSpec.type,
      subtype: expectedSpec.subtype,
      prompt: item?.prompt || item?.question || "",
      options: expectedSpec.type === "mcq" ? (Array.isArray(item?.options) ? item.options : []) : [],
      marks: Number(expectedSpec.marksEach || item?.marks || 0),
      expectedLength: item?.expectedLength || "",
      learningOutcomeRefs:
        Array.isArray(item?.learningOutcomeRefs) ? item.learningOutcomeRefs :
        Array.isArray(item?.learningOutcomeIds) ? item.learningOutcomeIds : [],
      conceptRefs: Array.isArray(item?.conceptRefs) ? item.conceptRefs : [],
      topicCoverage: Array.isArray(item?.topicCoverage) ? item.topicCoverage : [],
      subtopicCoverage: Array.isArray(item?.subtopicCoverage) ? item.subtopicCoverage : [],
      bloomsLevel: item?.bloomsLevel || "",
      competencyTag: item?.competencyTag || "",
      difficulty: item?.difficulty || "",
      sourceEvidence: Array.isArray(item?.sourceEvidence) ? item.sourceEvidence : [],
    };
  });

  const normalizedQuestionIds = new Set(normalizedQuestions.map((item: any) => item.id));
  const evaluationAnswerKeyItems = Array.isArray(assessment?.evaluation?.answerKey?.items) ? assessment.evaluation.answerKey.items : [];
  const evaluationRubricsItems = Array.isArray(assessment?.evaluation?.rubrics?.items) ? assessment.evaluation.rubrics.items : [];
  const evaluationMarkingItems = Array.isArray(assessment?.evaluation?.markingScheme?.items) ? assessment.evaluation.markingScheme.items : [];

  const answerKeyItems = normalizedQuestions.map((question: any, index: number) => {
    const explicitItem = evaluationAnswerKeyItems.find((item: any) =>
      item?.questionId === question.id ||
      legacyToNormalizedId.get(String(item?.questionId || "").trim()) === question.id
    ) || evaluationAnswerKeyItems[index];
    return {
      questionId: question.id,
      sectionId: question.sectionId,
      sectionTitle: question.sectionTitle,
      answer: explicitItem?.answer || "Answer not provided",
      explanation: explicitItem?.explanation || "",
      marks: Number(question.marks || explicitItem?.marks || 0),
      subtype: question.subtype,
    };
  });

  const rubricItems = normalizedQuestions
    .filter((question: any) => question.type !== "mcq")
    .map((question: any, index: number) => {
      const explicitItem = evaluationRubricsItems.find((item: any) =>
        item?.questionId === question.id ||
        legacyToNormalizedId.get(String(item?.questionId || "").trim()) === question.id
      ) || evaluationRubricsItems[index];
      const derivedCriteria = Array.isArray(explicitItem?.criteria)
        ? explicitItem.criteria.map((item: any) => ({
            criterion: item?.criterion || item?.text || "",
            marks: item?.marks != null ? Number(item.marks) : undefined,
          }))
        : deriveAssessmentMarkBreakdown([], Number(question.marks || 0));
      return {
        questionId: question.id,
        totalMarks: Number(question.marks || explicitItem?.totalMarks || 0),
        criteria: derivedCriteria,
        sampleAnswer: explicitItem?.sampleAnswer || answerKeyItems.find((item: any) => item.questionId === question.id)?.answer || "",
      };
    });

  const markingSchemeItems = normalizedQuestions.map((question: any, index: number) => {
    const explicitItem = evaluationMarkingItems.find((item: any) =>
      item?.questionId === question.id ||
      legacyToNormalizedId.get(String(item?.questionId || "").trim()) === question.id
    ) || evaluationMarkingItems[index];
    const matchingRubric = rubricItems.find((item: any) => item.questionId === question.id);
    const derivedBreakdown = Array.isArray(explicitItem?.markBreakdown) && explicitItem.markBreakdown.length > 0
      ? explicitItem.markBreakdown.map((item: any) => ({
          criterion: item?.criterion || item?.text || "",
          marks: item?.marks != null ? Number(item.marks) : undefined,
        }))
      : deriveAssessmentMarkBreakdown(
          Array.isArray(matchingRubric?.criteria) ? matchingRubric.criteria.map((item: any) => item?.criterion || "") : [],
          Number(question.marks || 0)
        );
    return {
      questionId: question.id,
      totalMarks: Number(question.marks || explicitItem?.totalMarks || 0),
      markBreakdown: derivedBreakdown,
      awardGuidance: Array.isArray(explicitItem?.awardGuidance) ? explicitItem.awardGuidance : [],
    };
  });

  const totalMarks = requestedQuestionTypes.reduce(
    (sum, item) => sum + Number(item.questionCount || 0) * Number(item.marksEach || 0),
    0
  );
  const totalQuestions = requestedQuestionTypes.reduce((sum, item) => sum + Number(item.questionCount || 0), 0);
  const allQuestions = normalizedQuestions;
  const providedSectionPlan = Array.isArray(assessment?.blueprint?.sectionPlan) ? assessment.blueprint.sectionPlan : [];
  const providedSectionFocus = new Map<string, any>();
  providedSectionPlan.forEach((item: any) => {
    const rawId = String(item?.sectionId || "").trim();
    const rawTitle = normalizeAssessmentSectionTitle(item?.title || "");
    if (rawId) {
      providedSectionFocus.set(rawId, item?.focus);
    }
    if (rawTitle) {
      providedSectionFocus.set(normalizeSourceText(rawTitle), item?.focus);
    }
  });
  const rebuiltSections = dedupeAssessmentSections(expectedSections
    .map((section: any) => {
      const questionRefs = allQuestions
        .filter((item: any) => item?.sectionId === section.id)
        .map((item: any) => item?.id)
        .filter(Boolean);
      if (!questionRefs.length) return null;
      const sectionMarks = allQuestions
        .filter((item: any) => item?.sectionId === section.id)
        .reduce((sum: number, item: any) => sum + Number(item?.marks || 0), 0);
      return {
        id: section.id,
        title: section.title,
        marks: sectionMarks,
        questionCount: questionRefs.length,
        questionRefs,
        source: section.source || "fallback",
      };
    })
    .filter(Boolean));
  const rebuiltSectionPlan = rebuiltSections.map((section: any) => ({
    sectionId: section.id,
    title: section.title,
    marks: section.marks,
    questionCount: section.questionCount,
    questionRefs: section.questionRefs,
    focus:
      providedSectionFocus.get(section.id) ||
      providedSectionFocus.get(normalizeSourceText(section.title || "")) ||
      undefined,
  }));

  const actualMarks = allQuestions.reduce((sum: number, item: any) => sum + Number(item?.marks || 0), 0);
  const actualQuestions = allQuestions.length;
  const questionDistribution = allQuestions.reduce((acc: Record<string, number>, question: any) => {
    const key = String(question?.subtype || question?.type || "question");
    acc[key] = (acc[key] || 0) + 1;
    return acc;
  }, {});
  const alignmentPassed =
    answerKeyItems.length === actualQuestions &&
    markingSchemeItems.length === actualQuestions &&
    answerKeyItems.every((item: any) => normalizedQuestionIds.has(item.questionId)) &&
    markingSchemeItems.every((item: any) => normalizedQuestionIds.has(item.questionId));
  const rubricLinkedQuestionIds = new Set(rubricItems.map((item: any) => item.questionId).filter(Boolean));

  return {
    meta: {
      ...(assessment?.meta && typeof assessment.meta === "object" ? assessment.meta : {}),
      assessmentType: customization.assessmentType || assessment?.meta?.assessmentType || "Session assessment",
      totalMarks,
      totalQuestions,
      durationMinutes: defaults.durationMinutes,
      preferredDifficulty: customization.difficulty || defaults.preferredDifficulty,
      language: defaults.language,
      paperObjective: customization.paperObjective || "",
      requestSignature: buildAssessmentCustomizationSignature(customization),
      requestedQuestionTypes,
    },
    sessionAnalysis: {
      assessedLearningOutcomes: uniqueStrings(
        Array.isArray(assessment?.sessionAnalysis?.assessedLearningOutcomes)
          ? assessment.sessionAnalysis.assessedLearningOutcomes
          : allQuestions.flatMap((question: any) => question.learningOutcomeRefs || [])
      ),
      assessedConcepts: uniqueStrings(
        Array.isArray(assessment?.sessionAnalysis?.assessedConcepts)
          ? assessment.sessionAnalysis.assessedConcepts
          : allQuestions.flatMap((question: any) => [...(question.conceptRefs || []), ...(question.topicCoverage || [])])
      ),
      conceptCoveragePriorities: uniqueStrings(assessment?.sessionAnalysis?.conceptCoveragePriorities || []),
      misconceptionTargets: uniqueStrings(assessment?.sessionAnalysis?.misconceptionTargets || []),
      competencyFocus: uniqueStrings(assessment?.sessionAnalysis?.competencyFocus || []),
    },
    blueprint: {
      ...(assessment?.blueprint && typeof assessment.blueprint === "object" ? assessment.blueprint : {}),
      learningOutcomeCoverage: Array.isArray(assessment?.blueprint?.learningOutcomeCoverage)
        ? assessment.blueprint.learningOutcomeCoverage.map((item: any) => ({
            ...item,
            questionRefs: Array.isArray(item?.questionRefs)
              ? item.questionRefs.map((ref: any) => {
                  const normalizedRef = typeof ref === "string" ? legacyToNormalizedId.get(ref.trim()) : undefined;
                  return normalizedRef || ref;
                })
              : [],
          }))
        : [],
      conceptDistribution: Array.isArray(assessment?.blueprint?.conceptDistribution)
        ? assessment.blueprint.conceptDistribution.map((item: any) => ({
            ...item,
            questionRefs: Array.isArray(item?.questionRefs)
              ? item.questionRefs.map((ref: any) => legacyToNormalizedId.get(String(ref || "").trim()) || ref)
              : [],
          }))
        : uniqueStrings(allQuestions.flatMap((question: any) => question.conceptRefs || question.topicCoverage || [])).map((concept: string) => ({
            concept,
            questionRefs: allQuestions
              .filter((question: any) =>
                [...(question.conceptRefs || []), ...(question.topicCoverage || [])].some((item: any) => normalizeSourceText(String(item || "")) === normalizeSourceText(concept))
              )
              .map((question: any) => question.id),
          })),
      sectionPlan: rebuiltSectionPlan,
      questionDistribution: {
        ...(assessment?.blueprint?.questionDistribution && typeof assessment.blueprint.questionDistribution === "object"
          ? assessment.blueprint.questionDistribution
          : {}),
        ...questionDistribution,
      },
    },
    paper: {
      instructions: Array.isArray(assessment?.paper?.instructions)
        ? assessment.paper.instructions
        : [
            "Answer all questions using only the concepts taught in this session.",
            "Follow the mark allocation shown for each question.",
          ],
      sections: rebuiltSections,
      questions: normalizedQuestions,
    },
    evaluation: {
      answerKey: {
        items: answerKeyItems,
      },
      markingScheme: {
        items: markingSchemeItems,
      },
      rubrics: {
        items: rubricItems,
      },
      generalInstructions: Array.isArray(assessment?.evaluation?.generalInstructions)
        ? assessment.evaluation.generalInstructions
        : [
            "Award marks exactly according to the requested question pattern.",
            "Accept equivalent correct wording when the concept taught in the session is preserved.",
            "Use the marking scheme and rubric point-wise for non-MCQ answers.",
          ],
      evaluatorInstructions: Array.isArray(assessment?.evaluation?.evaluatorInstructions)
        ? assessment.evaluation.evaluatorInstructions
        : [
            "Evaluate only the knowledge demonstrated from the taught session scope.",
            "Do not award extra credit for off-syllabus or future-session content.",
          ],
      moderationNotes: Array.isArray(assessment?.evaluation?.moderationNotes) ? assessment.evaluation.moderationNotes : [],
    },
    summary: {
      coverageSummary: Array.isArray(assessment?.summary?.coverageSummary)
        ? assessment.summary.coverageSummary
        : [
            `${actualQuestions} questions aligned to ${uniqueStrings(allQuestions.flatMap((question: any) => question.learningOutcomeRefs || [])).length} learning outcome reference(s).`,
            `${rebuiltSections.length} assessment section(s) included in the final paper.`,
          ],
      omittedContent: Array.isArray(assessment?.summary?.omittedContent) ? assessment.summary.omittedContent : [],
      balanceNotes: Array.isArray(assessment?.summary?.balanceNotes)
        ? assessment.summary.balanceNotes
        : [
            "Question order follows the requested paper pattern and section structure.",
            "Answer key, marking scheme, and rubrics are aligned one-to-one with the final ordered question list.",
          ],
    },
    validation: {
      exactPatternChecks: {
        passed: actualQuestions === totalQuestions,
        details: [
          `Requested questions: ${totalQuestions}`,
          `Generated questions: ${actualQuestions}`,
        ],
      },
      marksChecks: {
        passed: actualMarks === totalMarks,
        details: [
          `Requested marks: ${totalMarks}`,
          `Generated marks: ${actualMarks}`,
        ],
      },
      sectionChecks: {
        passed: rebuiltSections.length > 0 && allQuestions.every((question: any) => Boolean(question.sectionId)),
        details: rebuiltSections.map((section: any) => `${section.title}: ${section.questionCount} question(s), ${section.marks} mark(s)`),
      },
      alignmentChecks: {
        passed: alignmentPassed,
        details: [
          `Answer key items: ${answerKeyItems.length}`,
          `Marking scheme items: ${markingSchemeItems.length}`,
          `Rubric-linked questions: ${rubricLinkedQuestionIds.size}`,
        ],
      },
      scopeBoundaryChecks: {
        passed: assessment?.validation?.scopeBoundaryChecks?.passed ?? true,
        details: Array.isArray(assessment?.validation?.scopeBoundaryChecks?.details)
          ? assessment.validation.scopeBoundaryChecks.details
          : ["Assessment generation was constrained to the supplied session JSON and requested session scope."],
      },
    },
  };
}

function stripHtmlTags(value: string) {
  return String(value || "").replace(/<[^>]+>/g, " ").replace(/\s+/g, " ").trim();
}

function xmlEscape(value: string) {
  return String(value || "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&apos;");
}

function latexToExportPlainText(value: string) {
  return String(value || "")
    .replace(/\$\$/g, "")
    .replace(/\$/g, "")
    .replace(/\\\((.*?)\\\)/g, "$1")
    .replace(/\\\[(.*?)\\\]/g, "$1")
    .replace(/\\text\{([^{}]*)\}/g, "$1")
    .replace(/\\frac\{([^{}]+)\}\{([^{}]+)\}/g, "$1/$2")
    .replace(/\\sqrt\{([^{}]+)\}/g, "sqrt($1)")
    .replace(/\\cdot/g, "·")
    .replace(/\\times/g, "×")
    .replace(/\\div/g, "÷")
    .replace(/\\[a-zA-Z]+/g, " ")
    .replace(/[{}]/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function renderableToExportPlainText(value: any): string {
  if (value == null) return "";
  if (Array.isArray(value)) {
    return value.map((item: any) => renderableToExportPlainText(item)).filter(Boolean).join("; ");
  }
  if (typeof value === "string" || typeof value === "number" || typeof value === "boolean") {
    return String(value);
  }
  if (typeof value === "object") {
    const text = typeof value.text === "string" ? value.text.trim() : "";
    const latex = typeof value.displayLatex === "string" && value.displayLatex.trim()
      ? value.displayLatex.trim()
      : typeof value.latex === "string" ? value.latex.trim() : "";
    const readableLatex = latexToExportPlainText(latex);
    if (text && readableLatex) {
      return text.includes(readableLatex) ? text : `${text} ${readableLatex}`.trim();
    }
    if (text || readableLatex) {
      return text || readableLatex;
    }
  }
  return String(value);
}

function slugifyFileNamePart(value: string) {
  return String(value || "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "") || "item";
}

const pptAssetResolutionCache = new Map<string, any>();
const remoteBinaryAssetCache = new Map<string, { buffer: Buffer; mimeType: string }>();
const USE_REMOTE_PPT_ASSETS = true;
const WIKIMEDIA_REQUEST_MIN_INTERVAL_MS = Number(process.env.WIKIMEDIA_REQUEST_MIN_INTERVAL_MS) || 5000;
const WIKIMEDIA_MEDIA_REQUEST_MIN_INTERVAL_MS = Number(process.env.WIKIMEDIA_MEDIA_REQUEST_MIN_INTERVAL_MS) || 250;
const WIKIMEDIA_MAX_RETRIES = 2;
let lastWikimediaRequestAt = 0;
let lastWikimediaMediaRequestAt = 0;
let wikimediaGlobalCooldownUntil = 0;
let wikimediaMediaCooldownUntil = 0;
let wikimediaPreviewCooldownUntil = 0;
let wikimediaRequestQueue: Promise<void> = Promise.resolve();
let wikimediaMediaRequestQueue: Promise<void> = Promise.resolve();
type ReusablePptAsset = {
  sourceSite?: string;
  sourceUrl?: string;
  previewUrl?: string;
  licenseType?: string;
  attributionText?: string;
  altText?: string;
  mediaClass?: string;
  mimeType?: string;
  width?: number;
  height?: number;
  title?: string;
  metadataScore?: number;
  rerankScore?: number;
  rerankReason?: string;
  isTextHeavy?: boolean;
  isDiagramPage?: boolean;
  isChildFriendly?: boolean;
};

type RerankedVisualCandidate = ReusablePptAsset & {
  candidateIndex: number;
};

function classifyReusableAsset(asset: ReusablePptAsset) {
  const sourceUrl = String(asset.sourceUrl || "").toLowerCase();
  const previewUrl = String(asset.previewUrl || "").toLowerCase();
  const mimeType = String(asset.mimeType || "").toLowerCase();
  const text = [
    asset.altText,
    asset.attributionText,
    asset.title,
    asset.licenseType,
    asset.sourceSite,
  ]
    .filter(Boolean)
    .join(" ")
    .toLowerCase();

  const documentPattern = /\b(page|pages|cover title|bibliographic|journal|vol\.|volume|issue|paper no|digitized|scanned|scan|archive|proceedings|table of contents)\b/;
  const chemistryPositivePattern = /\b(acid|acids|base|bases|indicator|litmus|phenolphthalein|methyl orange|chemical|chemistry|laboratory|lab|reaction|solution|beaker|test tube|ph scale)\b/;
  const imageExtensionPattern = /\.(jpg|jpeg|png|webp|gif)(?:[?#]|$)/;
  const documentExtensionPattern = /\.(pdf|djvu|tif|tiff|svg)(?:[?#]|$)/;

  if (
    mimeType.includes("svg")
    || mimeType.includes("tiff")
    || documentExtensionPattern.test(sourceUrl)
    || documentExtensionPattern.test(previewUrl)
    || documentPattern.test(text)
  ) {
    return "document-scan";
  }
  if (chemistryPositivePattern.test(text)) {
    return "topic-relevant";
  }
  if (imageExtensionPattern.test(sourceUrl) || imageExtensionPattern.test(previewUrl)) {
    return "generic-image";
  }
  return "unknown";
}

function scoreReusableAsset(query: string, asset: ReusablePptAsset) {
  const queryTokens = String(query || "")
    .toLowerCase()
    .split(/[^a-z0-9]+/g)
    .filter((token) => token.length > 2);
  const haystack = [
    asset.altText,
    asset.attributionText,
    asset.title,
    asset.licenseType,
    asset.sourceSite,
  ]
    .filter(Boolean)
    .join(" ")
    .toLowerCase();

  let score = 0;
  const mediaClass = classifyReusableAsset(asset);
  for (const token of queryTokens) {
    if (haystack.includes(token)) {
      score += token.length > 6 ? 3 : 2;
    }
  }

  if (mediaClass === "document-scan") score -= 12;
  if (mediaClass === "topic-relevant") score += 5;
  if (mediaClass === "generic-image") score += 1;
  if (mediaClass === "unknown") score -= 2;
  if ((asset.width || 0) >= 1000) score += 3;
  if ((asset.width || 0) >= 1400) score += 1;
  if ((asset.height || 0) > 0 && (asset.width || 0) >= (asset.height || 0)) score += 3;
  if ((asset.height || 0) > 0 && (asset.width || 0) / Math.max(1, asset.height || 1) >= 1.2) score += 2;
  if ((asset.height || 0) > (asset.width || 0)) score -= 6;
  if (asset.previewUrl) score += 2;
  if (asset.sourceUrl) score += 1;
  if (String(asset.licenseType || "").toLowerCase().includes("cc")) score += 1;
  if (String(asset.sourceSite || "").toLowerCase().includes("wikimedia")) score += 1;

  return score;
}

function getMeaningfulQueryTokens(query: string) {
  const stopwords = new Set([
    "green", "blue", "red", "science", "classroom", "students", "student", "activity",
    "school", "clean", "simple", "field", "task", "tonight", "learning", "goals",
    "summary", "homework", "question", "quiz", "card", "layout", "experiment"
  ]);
  return String(query || "")
    .toLowerCase()
    .split(/[^a-z0-9]+/g)
    .filter((token) => token.length > 2 && !stopwords.has(token));
}

function isReusableAssetSemanticallyRelevant(query: string, asset: ReusablePptAsset) {
  const meaningfulTokens = getMeaningfulQueryTokens(query);
  if (meaningfulTokens.length === 0) return true;

  const haystack = [
    asset.altText,
    asset.attributionText,
    asset.title,
    asset.licenseType,
    asset.sourceSite,
  ]
    .filter(Boolean)
    .join(" ")
    .toLowerCase();

  const overlapCount = meaningfulTokens.filter((token) => haystack.includes(token)).length;
  if (overlapCount >= Math.min(2, meaningfulTokens.length)) {
    return true;
  }

  const mismatchPatterns: Array<{ query: RegExp; banned: RegExp }> = [
    { query: /\b(mitochondria|cell|respiration|lungs)\b/, banned: /\b(thoracic|vital capacity|reserve air|residual air|breathing air)\b/ },
    { query: /\b(plant|leaf|photosynthesis|autotroph)\b/, banned: /\b(building|architecture|office|campus|house|interior)\b/ },
    { query: /\b(cow|grazing|heterotroph|animal)\b/, banned: /\b(bug|beetle|shield bug|insect)\b/ },
  ];
  for (const rule of mismatchPatterns) {
    if (rule.query.test(query.toLowerCase()) && rule.banned.test(haystack)) {
      return false;
    }
  }

  return overlapCount >= 1 && meaningfulTokens.length <= 2;
}

function passesWikimediaMetadataPrefilter(asset: ReusablePptAsset) {
  const width = Number(asset.width || 0);
  const height = Number(asset.height || 0);
  const mimeType = String(asset.mimeType || "").toLowerCase();
  const sourceUrl = String(asset.sourceUrl || "").toLowerCase();
  const previewUrl = String(asset.previewUrl || "").toLowerCase();
  const bannedExtensionPattern = /\.(svg|tif|tiff)(?:[?#]|$)/;

  if (!asset.previewUrl && !asset.sourceUrl) return false;
  if (mimeType.includes("svg") || mimeType.includes("tiff")) return false;
  if (bannedExtensionPattern.test(sourceUrl) || bannedExtensionPattern.test(previewUrl)) return false;
  if (width > 0 && width < 1000) return false;
  if (width > 0 && height > 0 && height > width) return false;
  return true;
}

function buildWikimediaCandidateDebugRecord(asset: ReusablePptAsset, index: number) {
  return {
    candidateIndex: index,
    title: String(asset.title || ""),
    previewUrl: String(asset.previewUrl || ""),
    sourceUrl: String(asset.sourceUrl || ""),
    mimeType: String(asset.mimeType || ""),
    width: Number(asset.width || 0),
    height: Number(asset.height || 0),
    metadataScore: Number(asset.metadataScore || 0),
    rerankScore: Number(asset.rerankScore || 0),
    rerankReason: String(asset.rerankReason || ""),
    isTextHeavy: Boolean(asset.isTextHeavy),
    isDiagramPage: Boolean(asset.isDiagramPage),
    isChildFriendly: typeof asset.isChildFriendly === "boolean" ? asset.isChildFriendly : null,
    mediaClass: String(asset.mediaClass || ""),
  };
}

function shouldPreferMetadataOnlyForSlide(context: SlideVisualRerankContext) {
  const normalized = normalizeSourceText([
    context.slideTitle,
    context.teachingIntent,
    context.wikimediaSearchLabel,
  ].filter(Boolean).join(" "));
  return /\b(title|summary|homework|recap|classroom|students|task tonight|learning goals)\b/.test(normalized);
}

function isTopMetadataCandidateDominant(candidates: ReusablePptAsset[]) {
  if (candidates.length < 2) return true;
  const [first, second] = candidates;
  const firstScore = Number(first?.metadataScore || 0);
  const secondScore = Number(second?.metadataScore || 0);
  const firstAspectBonus = Number(first?.width || 0) >= Number(first?.height || 0) ? 1 : 0;
  const secondAspectBonus = Number(second?.width || 0) >= Number(second?.height || 0) ? 1 : 0;
  return (firstScore + firstAspectBonus) - (secondScore + secondAspectBonus) >= PPT_IMAGE_RERANK_METADATA_MARGIN;
}

function getReusableAssetIdentity(asset: ReusablePptAsset | null | undefined) {
  return String(asset?.sourceUrl || asset?.previewUrl || "").trim();
}

function filterUnusedVisualCandidates(
  candidates: ReusablePptAsset[],
  usedVisualUrls?: Set<string>
) {
  if (!usedVisualUrls?.size) {
    return candidates;
  }
  const unusedCandidates = candidates.filter((candidate) => {
    const identity = getReusableAssetIdentity(candidate);
    return !identity || !usedVisualUrls.has(identity);
  });
  return unusedCandidates.length ? unusedCandidates : candidates;
}

async function rerankWikimediaCandidatesWithQwen(
  candidates: ReusablePptAsset[],
  context: SlideVisualRerankContext
): Promise<{
  rankedCandidates: RerankedVisualCandidate[];
  modelOutput: any;
  fallbackReason?: string;
  previewFetchAttemptCount?: number;
  rerankInvoked?: boolean;
}> {
  if (!candidates.length) {
    return { rankedCandidates: [], modelOutput: { rankings: [] }, fallbackReason: "no-candidates", previewFetchAttemptCount: 0, rerankInvoked: false };
  }

  if (candidates.length < 2) {
    return {
      rankedCandidates: candidates.map((candidate, candidateIndex) => ({ ...candidate, candidateIndex })),
      modelOutput: { rankings: [] },
      fallbackReason: "single-candidate",
      previewFetchAttemptCount: 0,
      rerankInvoked: false,
    };
  }

  if (wikimediaPreviewCooldownUntil > Date.now()) {
    return {
      rankedCandidates: candidates.map((candidate, candidateIndex) => ({ ...candidate, candidateIndex })),
      modelOutput: { rankings: [] },
      fallbackReason: "cooldown-active",
      previewFetchAttemptCount: 0,
      rerankInvoked: false,
    };
  }

  if (shouldPreferMetadataOnlyForSlide(context) && isTopMetadataCandidateDominant(candidates)) {
    return {
      rankedCandidates: candidates.map((candidate, candidateIndex) => ({ ...candidate, candidateIndex })),
      modelOutput: { rankings: [] },
      fallbackReason: "top-candidate-dominant",
      previewFetchAttemptCount: 0,
      rerankInvoked: false,
    };
  }

  if (isTopMetadataCandidateDominant(candidates)) {
    return {
      rankedCandidates: candidates.map((candidate, candidateIndex) => ({ ...candidate, candidateIndex })),
      modelOutput: { rankings: [] },
      fallbackReason: "top-candidate-dominant",
      previewFetchAttemptCount: 0,
      rerankInvoked: false,
    };
  }

  const { baseUrl, model } = getOllamaVisionRerankConfig();
  const prompt = [
    "You are ranking slide image candidates for a school classroom PowerPoint.",
    "Return strict JSON only.",
    "Rank image candidates by how well they match the slide for children and classroom teaching.",
    "Prefer colorful, clear, natural-looking images that explain the concept simply for school children.",
    "Reject text-heavy images, scanned pages, poster-like diagrams, and images that are hard for children to understand.",
    "",
    `Slide title: ${String(context.slideTitle || "").trim() || "Untitled slide"}`,
    `Wikimedia label: ${String(context.wikimediaSearchLabel || "").trim() || "general classroom visual"}`,
    `Teaching intent: ${String(context.teachingIntent || "").trim() || "Support classroom explanation."}`,
    `Subject/grade: ${[context.subject, context.gradeLevel].filter(Boolean).join(" / ") || "school classroom"}`,
    "",
    "Return this JSON shape:",
    JSON.stringify({
      rankings: [
        {
          candidateIndex: 0,
          relevanceScore: 0,
          reason: "short reason",
          isTextHeavy: false,
          isDiagramPage: false,
          isChildFriendly: true,
        },
      ],
    }, null, 2),
  ].join("\n");

  const messageImages: string[] = [];
  const candidateRecords: any[] = [];
  let previewFetchAttemptCount = 0;
  for (let candidateIndex = 0; candidateIndex < Math.min(candidates.length, PPT_IMAGE_RERANK_FETCH_LIMIT); candidateIndex += 1) {
    const candidate = candidates[candidateIndex];
    try {
      previewFetchAttemptCount += 1;
      const imageData = await ensureImageDataUrl(String(candidate.previewUrl || candidate.sourceUrl || ""));
      messageImages.push(imageData.imageDataUrl.replace(/^data:[^,]+,/, ""));
      candidateRecords.push({
        candidateIndex,
        title: String(candidate.title || ""),
        altText: String(candidate.altText || ""),
        attributionText: String(candidate.attributionText || ""),
        width: Number(candidate.width || 0),
        height: Number(candidate.height || 0),
        mimeType: String(candidate.mimeType || ""),
        metadataScore: Number(candidate.metadataScore || 0),
      });
    } catch (error: any) {
      console.warn(
        `[PPT Assets] Skipping Qwen preview fetch for candidate ${candidateIndex} of "${String(context.wikimediaSearchLabel || context.slideTitle || "")}":`,
        error
      );
      if (String(error?.message || "").includes("429")) {
        wikimediaPreviewCooldownUntil = Math.max(
          wikimediaPreviewCooldownUntil,
          Date.now() + WIKIMEDIA_PREVIEW_COOLDOWN_MS
        );
        return {
          rankedCandidates: candidates.map((item, index) => ({ ...item, candidateIndex: index })),
          modelOutput: { rankings: [] },
          fallbackReason: "preview-fetch-429",
          previewFetchAttemptCount,
          rerankInvoked: false,
        };
      }
    }
  }

  if (candidateRecords.length === 0 || messageImages.length === 0) {
    return {
      rankedCandidates: candidates.map((candidate, candidateIndex) => ({
        ...candidate,
        candidateIndex,
      })),
      modelOutput: { rankings: [] },
      fallbackReason: "candidate-image-fetch-failed",
      previewFetchAttemptCount,
      rerankInvoked: false,
    };
  }

  const requestBody = {
    model,
    stream: false,
    think: false,
    format: "json",
    options: {
      temperature: 0,
      num_predict: 2048,
    },
    messages: [
      {
        role: "system",
        content: "Return only valid JSON. Do not include markdown.",
      },
      {
        role: "user",
        content: `${prompt}\n\nCandidates:\n${JSON.stringify(candidateRecords, null, 2)}`,
        images: messageImages,
      },
    ],
  };

  const controller = new AbortController();
  const timeoutHandle = setTimeout(() => controller.abort(), OLLAMA_VISION_RERANK_TIMEOUT_MS);
  try {
    const response = await fetch(`${baseUrl}/api/chat`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(requestBody),
      signal: controller.signal,
      dispatcher: OLLAMA_FETCH_DISPATCHER,
    } as any);
    if (!response.ok) {
      const errorText = await response.text().catch(() => "");
      throw new Error(`Qwen rerank failed with status ${response.status}: ${errorText}`);
    }
    const data = await response.json();
    const responseText = String(data?.message?.content || data?.response || "").trim();
    if (!responseText) {
      throw new Error("Qwen rerank returned empty content.");
    }
    const extracted = extractJsonText(responseText);
    const parsed = JSON.parse(extracted);
    const rankings = Array.isArray(parsed?.rankings) ? parsed.rankings : [];

    const rankedCandidates = candidates.map((candidate, candidateIndex) => {
      const ranking = rankings.find((item: any) => Number(item?.candidateIndex) === candidateIndex);
      return {
        ...candidate,
        candidateIndex,
        rerankScore: Math.max(0, Math.min(100, Number(ranking?.relevanceScore || 0))),
        rerankReason: String(ranking?.reason || ""),
        isTextHeavy: Boolean(ranking?.isTextHeavy),
        isDiagramPage: Boolean(ranking?.isDiagramPage),
        isChildFriendly: typeof ranking?.isChildFriendly === "boolean" ? ranking.isChildFriendly : true,
      };
    });

    return {
      rankedCandidates: rankedCandidates.sort((a, b) =>
        (Number(b.rerankScore || 0) - Number(a.rerankScore || 0))
        || (Number(b.width || 0) - Number(a.width || 0))
        || (Number(b.metadataScore || 0) - Number(a.metadataScore || 0))
      ),
      modelOutput: parsed,
      previewFetchAttemptCount,
      rerankInvoked: true,
    };
  } finally {
    clearTimeout(timeoutHandle);
  }
}
const pptAssetRateLimitCooldowns = new Map<string, number>();
const pptAssetResolutionInFlight = new Map<string, Promise<any>>();
const PPT_ASSET_RATE_LIMIT_COOLDOWN_MS = 15 * 60 * 1000;
const WIKIMEDIA_GLOBAL_RATE_LIMIT_COOLDOWN_MS = Number(process.env.WIKIMEDIA_GLOBAL_RATE_LIMIT_COOLDOWN_MS) || 120000;
const WIKIMEDIA_PREVIEW_COOLDOWN_MS = Number(process.env.WIKIMEDIA_PREVIEW_COOLDOWN_MS) || 180000;
const PPT_ASSET_MISS_CACHE_TTL_MS = Number(process.env.PPT_ASSET_MISS_CACHE_TTL_MS) || 10 * 60 * 1000;
const PPT_ASSET_METADATA_ONLY_CACHE_TTL_MS = Number(process.env.PPT_ASSET_METADATA_ONLY_CACHE_TTL_MS) || 5 * 60 * 1000;

function isHttpRateLimitError(error: unknown) {
  const message = String((error as any)?.message || "");
  return message.includes("429");
}

async function enqueueWikimediaRequest<T>(task: () => Promise<T>) {
  let release = () => {};
  const prior = wikimediaRequestQueue;
  wikimediaRequestQueue = new Promise<void>((resolve) => {
    release = resolve;
  });

  await prior;
  try {
    const now = Date.now();
    const waitMs = Math.max(
      0,
      lastWikimediaRequestAt + WIKIMEDIA_REQUEST_MIN_INTERVAL_MS - now,
      wikimediaGlobalCooldownUntil - now
    );
    if (waitMs > 0) {
      await new Promise((resolve) => setTimeout(resolve, waitMs));
    }
    lastWikimediaRequestAt = Date.now();
    return await task();
  } finally {
    release();
  }
}

async function enqueueWikimediaMediaRequest<T>(task: () => Promise<T>) {
  let release = () => {};
  const prior = wikimediaMediaRequestQueue;
  wikimediaMediaRequestQueue = new Promise<void>((resolve) => {
    release = resolve;
  });

  await prior;
  try {
    const now = Date.now();
    const waitMs = Math.max(
      0,
      lastWikimediaMediaRequestAt + WIKIMEDIA_MEDIA_REQUEST_MIN_INTERVAL_MS - now,
      wikimediaMediaCooldownUntil - now
    );
    if (waitMs > 0) {
      await new Promise((resolve) => setTimeout(resolve, waitMs));
    }
    lastWikimediaMediaRequestAt = Date.now();
    return await task();
  } finally {
    release();
  }
}

async function resolveOpenverseImage(query: string) {
  const url = `https://api.openverse.org/v1/images/?q=${encodeURIComponent(query)}&page_size=5`;
  const res = await fetch(url, {
    redirect: "follow",
    headers: {
      Accept: "application/json",
      "Accept-Encoding": "identity",
      "User-Agent": "LessonPlanGenerator/1.0",
    },
  });
  if (!res.ok) {
    const body = await res.text().catch(() => "");
    throw new Error(`Openverse lookup failed with status ${res.status}${body ? `: ${body.slice(0, 160)}` : ""}`);
  }
  const responseText = await res.text();
  let data: any = null;
  try {
    data = responseText ? JSON.parse(responseText) : null;
  } catch {
    throw new Error(`Openverse returned a non-JSON response: ${responseText.slice(0, 160)}`);
  }
  const items = Array.isArray(data?.results) ? data.results : [];
  if (!items.length) {
    return null;
  }
  const candidates: ReusablePptAsset[] = items.map((item: any) => ({
    sourceSite: "Openverse",
    sourceUrl: String(item.foreign_landing_url || item.url || ""),
    previewUrl: String(item.thumbnail || item.url || ""),
    licenseType: [item.license, item.license_version].filter(Boolean).join(" ").trim() || "Reusable",
    attributionText: [item.creator, item.title].filter(Boolean).join(" - "),
    altText: String(item.title || query),
  }));
  return candidates
    .sort((a, b) => scoreReusableAsset(query, b) - scoreReusableAsset(query, a))[0] || null;
}

async function resolveWikimediaImageCandidates(query: string) {
  for (let attempt = 0; attempt <= WIKIMEDIA_MAX_RETRIES; attempt += 1) {
    const retryDelay = attempt === 0 ? 0 : attempt * 2500;
    if (retryDelay > 0) {
      await new Promise((resolve) => setTimeout(resolve, retryDelay));
    }
    const url = `https://commons.wikimedia.org/w/api.php?action=query&generator=search&gsrsearch=${encodeURIComponent(query)}&gsrnamespace=6&gsrlimit=${PPT_IMAGE_METADATA_POOL_LIMIT}&prop=imageinfo&iiprop=url|extmetadata|size|mime&iiurlwidth=1600&format=json&formatversion=2`;
    const res = await enqueueWikimediaRequest(() => fetch(url, {
      redirect: "follow",
      headers: {
        Accept: "application/json",
        "Accept-Encoding": "identity",
        "User-Agent": "LessonPlanGenerator/1.0",
      },
    }));
    if (!res.ok) {
      const body = await res.text().catch(() => "");
      if (res.status === 429 && attempt < WIKIMEDIA_MAX_RETRIES) {
        wikimediaGlobalCooldownUntil = Math.max(
          wikimediaGlobalCooldownUntil,
          Date.now() + WIKIMEDIA_GLOBAL_RATE_LIMIT_COOLDOWN_MS * (attempt + 1)
        );
        continue;
      }
      if (res.status === 429) {
        wikimediaGlobalCooldownUntil = Math.max(
          wikimediaGlobalCooldownUntil,
          Date.now() + WIKIMEDIA_GLOBAL_RATE_LIMIT_COOLDOWN_MS * (attempt + 1)
        );
      }
      throw new Error(`Wikimedia lookup failed with status ${res.status}${body ? `: ${body.slice(0, 160)}` : ""}`);
    }
    const responseText = await res.text();
    let data: any = null;
    try {
      data = responseText ? JSON.parse(responseText) : null;
    } catch {
      throw new Error(`Wikimedia returned a non-JSON response: ${responseText.slice(0, 160)}`);
    }
    const pages = Object.values((data as any)?.query?.pages || {}) as any[];
    const candidates = pages
      .map((page: any) => {
        const info = page?.imageinfo?.[0];
        if (!info) return null;
        const meta = info.extmetadata || {};
        return {
          sourceSite: "Wikimedia Commons",
          sourceUrl: String(info.descriptionurl || info.url || ""),
          previewUrl: String(info.thumburl || info.url || ""),
          licenseType: stripHtmlTags(meta?.LicenseShortName?.value || meta?.UsageTerms?.value || "Reusable"),
          attributionText: stripHtmlTags(meta?.Artist?.value || meta?.Credit?.value || page?.title || query),
          altText: stripHtmlTags(meta?.ImageDescription?.value || page?.title || query),
          mimeType: String(info.mime || ""),
          width: Number(info.width || 0),
          height: Number(info.height || 0),
          title: String(page?.title || ""),
          mediaClass: "unknown",
        };
      })
      .filter(Boolean)
      .map((asset: any) => ({
        ...asset,
        mediaClass: classifyReusableAsset(asset),
      }))
      .filter((asset: any) => asset.mediaClass !== "document-scan")
      .filter((asset: any) => passesWikimediaMetadataPrefilter(asset))
      .map((asset: any) => ({
        ...asset,
        metadataScore: scoreReusableAsset(query, asset),
      }));
    if (!candidates.length) {
      return [];
    }
    return candidates
      .sort((a: any, b: any) => Number(b.metadataScore || 0) - Number(a.metadataScore || 0))
      .filter((asset: any) => isReusableAssetSemanticallyRelevant(query, asset))
      .slice(0, PPT_IMAGE_METADATA_POOL_LIMIT);
  }
  return [];
}

async function resolveReusableImageAsset(query: string, context: SlideVisualRerankContext = {}) {
  const normalizedQuery = String(query || "").trim();
  if (!normalizedQuery) {
    return null;
  }
  const cachedEntry = pptAssetResolutionCache.get(normalizedQuery);
  if (cachedEntry && typeof cachedEntry === "object" && "expiresAt" in cachedEntry) {
    if (Number(cachedEntry.expiresAt || 0) > Date.now()) {
      const cachedIdentity = getReusableAssetIdentity(cachedEntry.value as ReusablePptAsset | null);
      if (!cachedIdentity || !context.usedVisualUrls?.has(cachedIdentity)) {
        return cachedEntry.value ?? null;
      }
    }
    pptAssetResolutionCache.delete(normalizedQuery);
  }
  if (pptAssetResolutionCache.has(normalizedQuery)) {
    const cachedValue = pptAssetResolutionCache.get(normalizedQuery);
    const cachedIdentity = getReusableAssetIdentity(cachedValue as ReusablePptAsset | null);
    if (!cachedIdentity || !context.usedVisualUrls?.has(cachedIdentity)) {
      return cachedValue;
    }
    pptAssetResolutionCache.delete(normalizedQuery);
  }
  if (pptAssetResolutionInFlight.has(normalizedQuery)) {
    return pptAssetResolutionInFlight.get(normalizedQuery);
  }

  const cooldownUntil = pptAssetRateLimitCooldowns.get(normalizedQuery) || 0;
  if (cooldownUntil > Date.now()) {
    return null;
  }

  const resolutionPromise = (async () => {
    const candidates: ReusablePptAsset[] = [];
    const metadataRankedCandidates: ReusablePptAsset[] = [];
    const rerankDebug: Record<string, any> = {
      query: normalizedQuery,
      candidateCountBeforeFilter: 0,
      candidateCountAfterFilter: 0,
      candidateShortlistSize: 0,
      metadataPoolLimit: PPT_IMAGE_METADATA_POOL_LIMIT,
      qwenInputLimit: PPT_IMAGE_RERANK_MAX_CANDIDATES,
      metadataCandidates: [],
      qwenInputCandidates: [],
      qwenRankings: null,
      previewFetchAttemptCount: 0,
      rerankInvoked: false,
      rerankSkippedReason: "",
      selectionMode: "metadata-heuristic",
      fallbackReason: "",
      finalSelectedCandidate: null,
    };
    try {
      const wikimediaResults = await resolveWikimediaImageCandidates(normalizedQuery);
      rerankDebug.candidateCountBeforeFilter = wikimediaResults.length;
      candidates.push(...wikimediaResults);
      rerankDebug.candidateCountAfterFilter = candidates.length;
      metadataRankedCandidates.push(...filterUnusedVisualCandidates(candidates
        .slice()
        .sort((a, b) =>
          Number(b.metadataScore || scoreReusableAsset(normalizedQuery, b)) - Number(a.metadataScore || scoreReusableAsset(normalizedQuery, a))
        )
        .slice(0, PPT_IMAGE_RERANK_MAX_CANDIDATES), context.usedVisualUrls));
      rerankDebug.candidateShortlistSize = metadataRankedCandidates.length;
      rerankDebug.metadataCandidates = candidates.map((candidate, index) => buildWikimediaCandidateDebugRecord(candidate, index));
      rerankDebug.qwenInputCandidates = metadataRankedCandidates.map((candidate, index) => buildWikimediaCandidateDebugRecord(candidate, index));
    } catch (error) {
      if (isHttpRateLimitError(error)) {
        pptAssetRateLimitCooldowns.set(normalizedQuery, Date.now() + PPT_ASSET_RATE_LIMIT_COOLDOWN_MS);
      }
      console.warn(`[PPT Assets] Wikimedia lookup failed for "${normalizedQuery}":`, error);
    }

    let resolved: ReusablePptAsset | null = null;
    try {
      const reranked = await rerankWikimediaCandidatesWithQwen(metadataRankedCandidates, {
        ...context,
        wikimediaSearchLabel: context.wikimediaSearchLabel || normalizedQuery,
      });
      rerankDebug.previewFetchAttemptCount = Number(reranked.previewFetchAttemptCount || 0);
      rerankDebug.rerankInvoked = Boolean(reranked.rerankInvoked);
      rerankDebug.rerankSkippedReason = reranked.rerankInvoked ? "" : String(reranked.fallbackReason || "");
      rerankDebug.qwenRankings = reranked.rankedCandidates.map((candidate) => buildWikimediaCandidateDebugRecord(candidate, candidate.candidateIndex));
      rerankDebug.qwenRawOutput = reranked.modelOutput;
      rerankDebug.fallbackReason = reranked.fallbackReason || "";
      resolved = reranked.rankedCandidates.find((candidate) =>
        Number(candidate.rerankScore || 0) >= PPT_IMAGE_RERANK_MIN_SCORE
        && !candidate.isTextHeavy
        && !candidate.isDiagramPage
        && candidate.isChildFriendly !== false
        && (!getReusableAssetIdentity(candidate) || !context.usedVisualUrls?.has(getReusableAssetIdentity(candidate)))
      ) || null;
      if (!resolved) {
        rerankDebug.fallbackReason = rerankDebug.fallbackReason || "qwen-below-threshold";
      }
      if (resolved && reranked.rerankInvoked) {
        rerankDebug.selectionMode = "qwen-rerank";
      }
    } catch (error: any) {
      rerankDebug.fallbackReason = `qwen-error:${String(error?.message || error)}`;
      console.warn(`[PPT Assets] Qwen rerank failed for "${normalizedQuery}":`, error);
    }

    if (!resolved) {
      resolved = metadataRankedCandidates.length
        ? filterUnusedVisualCandidates(metadataRankedCandidates.slice().sort((a, b) =>
          Number(b.metadataScore || scoreReusableAsset(normalizedQuery, b)) - Number(a.metadataScore || scoreReusableAsset(normalizedQuery, a))
        ), context.usedVisualUrls)[0] || null
        : filterUnusedVisualCandidates(candidates.slice().sort((a, b) =>
        Number(b.metadataScore || scoreReusableAsset(normalizedQuery, b)) - Number(a.metadataScore || scoreReusableAsset(normalizedQuery, a))
      ), context.usedVisualUrls)[0] || null;
      rerankDebug.selectionMode = "metadata-heuristic";
      if (!rerankDebug.rerankSkippedReason) {
        rerankDebug.rerankSkippedReason = String(rerankDebug.fallbackReason || "metadata-only-fallback");
      }
      if (["cooldown-active", "preview-fetch-429", "top-candidate-dominant", "single-candidate", "candidate-image-fetch-failed"].includes(String(rerankDebug.rerankSkippedReason || ""))) {
        pptAssetResolutionCache.set(normalizedQuery, {
          value: resolved,
          expiresAt: Date.now() + PPT_ASSET_METADATA_ONLY_CACHE_TTL_MS,
        });
      }
    }

    rerankDebug.finalSelectedCandidate = resolved
      ? buildWikimediaCandidateDebugRecord(resolved, 0)
      : null;
    if (context.debugDir && context.requestId) {
      await writeDebugFile(
        context.debugDir,
        `wikimedia-rerank-${slugifyFileNamePart(`${context.slideTitle || normalizedQuery}`)}.json`,
        rerankDebug
      );
    }
    if (resolved && !["cooldown-active", "preview-fetch-429", "top-candidate-dominant", "single-candidate", "candidate-image-fetch-failed"].includes(String(rerankDebug.rerankSkippedReason || ""))) {
      pptAssetResolutionCache.set(normalizedQuery, resolved);
    } else if (!pptAssetResolutionCache.has(normalizedQuery)) {
      pptAssetResolutionCache.set(normalizedQuery, {
        value: null,
        expiresAt: Date.now() + PPT_ASSET_MISS_CACHE_TTL_MS,
      });
    }
    return resolved;
  })();

  pptAssetResolutionInFlight.set(normalizedQuery, resolutionPromise);
  try {
    return await resolutionPromise;
  } finally {
    pptAssetResolutionInFlight.delete(normalizedQuery);
  }
}

function inferTemplateSlideKey(slide: any, index: number) {
  const explicitKey = String(slide?.templateSlideKey || "").trim();
  if (explicitKey) {
    return explicitKey;
  }

  const normalizedTitle = `${String(slide?.slideTitle || slide?.title || "").toLowerCase()} ${String(slide?.slideType || "").toLowerCase()}`;
  const keywordMap: Array<{ key: string; patterns: string[] }> = [
    { key: "title_identity", patterns: ["title", "building blocks", "session identity", "topic name"] },
    { key: "learning_outcomes", patterns: ["learning outcome", "objective"] },
    { key: "prerequisite_knowledge", patterns: ["prerequisite", "before today", "recall", "prior knowledge"] },
    { key: "lesson_hook", patterns: ["hook", "opening", "story", "session opening", "bridge"] },
    { key: "topic_introduction", patterns: ["introduction", "definition", "topic introduction"] },
    { key: "core_concept_a", patterns: ["core concept a", "core concept", "concept", "key difference", "major organelle"] },
    { key: "core_concept_b_visual", patterns: ["core concept b", "visual explanation", "diagram", "labelled"] },
    { key: "worked_example", patterns: ["worked example", "demonstration", "example"] },
    { key: "guided_practice", patterns: ["guided practice", "activity"] },
    { key: "quick_assessment", patterns: ["assessment", "poll", "question", "formative"] },
    { key: "summary", patterns: ["summary", "takeaway", "recap", "key takeaway"] },
    { key: "homework_next_session", patterns: ["homework", "next session", "next class", "thank you"] },
  ];

  const matched = keywordMap.find((entry) => entry.patterns.some((pattern) => normalizedTitle.includes(pattern)));
  if (matched) {
    return matched.key;
  }

  return GENERIC_ADAPTIVE_SLIDE_KEYS[index] || `adaptive_slide_${index + 1}`;
}

function buildTemplateThemeTokens(ppt: any) {
  const requestedThemeId = String(ppt?.themeId || "").trim();
  const preset =
    (requestedThemeId && PPT_THEME_PRESETS[requestedThemeId]) ||
    PPT_THEME_PRESETS["cbse-academic-blue"];

  return {
    themeId: preset.themeId,
    themeName: String(ppt?.themeName || ppt?.theme || preset.themeName),
    fonts: {
      heading: String(ppt?.themeTokens?.fonts?.heading || preset.fonts.heading),
      body: String(ppt?.themeTokens?.fonts?.body || preset.fonts.body),
    },
    colors: {
      primary: String(ppt?.themeTokens?.colors?.primary || preset.colors.primary),
      secondary: String(ppt?.themeTokens?.colors?.secondary || preset.colors.secondary),
      accent: String(ppt?.themeTokens?.colors?.accent || preset.colors.accent),
      background: String(ppt?.themeTokens?.colors?.background || preset.colors.background),
      surface: String(ppt?.themeTokens?.colors?.surface || preset.colors.surface),
      text: String(ppt?.themeTokens?.colors?.text || preset.colors.text),
      mutedText: String(ppt?.themeTokens?.colors?.mutedText || preset.colors.mutedText),
    },
    visualStyle: {
      topBarStyle: String(ppt?.themeTokens?.visualStyle?.topBarStyle || preset.visualStyle.topBarStyle),
      cardStyle: String(ppt?.themeTokens?.visualStyle?.cardStyle || preset.visualStyle.cardStyle),
      visualFrameStyle: String(ppt?.themeTokens?.visualStyle?.visualFrameStyle || preset.visualStyle.visualFrameStyle),
    },
  };
}

function getPptTemplatePreset(templateId?: string | null) {
  const requestedTemplateId = String(templateId || "").trim();
  const normalizedTemplateId =
    !requestedTemplateId || requestedTemplateId === KAMALANIKETAN_TEMPLATE_ID
      ? "academic-split"
      : requestedTemplateId;
  return (
    (normalizedTemplateId && PPT_TEMPLATE_PRESETS[normalizedTemplateId as keyof typeof PPT_TEMPLATE_PRESETS]) ||
    PPT_TEMPLATE_PRESETS["academic-split"]
  );
}

function shouldPreferSvgVisual(slide: any) {
  return false;
}

function normalizeVisualSemanticText(slide: any) {
  return normalizeSourceText([
    slide?.slideTitle,
    slide?.teachingBeat,
    ...(Array.isArray(slide?.mustTeach) ? slide.mustTeach : []),
    ...(Array.isArray(slide?.bulletPoints) ? slide.bulletPoints : []),
    ...(Array.isArray(slide?.onSlideText) ? slide.onSlideText : []),
    ...(Array.isArray(slide?.topicCoverage) ? slide.topicCoverage : []),
    slide?.visualPlan,
    slide?.teacherIntent,
    slide?.studentTakeaway,
  ].map((item: any) => renderableToExportPlainText(item)).join(" "));
}

function inferSlideConceptKey(slide: any) {
  const normalized = normalizeVisualSemanticText(slide);
  const matches = (pattern: RegExp) => pattern.test(normalized);

  if (matches(/\btsa\b/) && matches(/\blsa\b|\bcsa\b|\blateral surface area\b|\bcurved surface area\b/)) return "tsa-vs-lsa";
  if (matches(/\bnet\b|\bunfold|\bopen out\b/)) {
    if (matches(/\bcube\b/) && !matches(/\bcuboid\b/)) return "cube-net";
    if (matches(/\bcuboid\b|\brectangular prism\b/)) return "cuboid-net";
    if (matches(/\bcylinder\b/)) return "cylinder-net";
    if (matches(/\bcone\b/)) return "cone-net";
    return "net-view";
  }
  if (matches(/\bcube\b/) && !matches(/\bcuboid\b/)) return "cube";
  if (matches(/\bcuboid\b|\brectangular prism\b/)) return "cuboid";
  if (matches(/\bcylinder\b/)) return "cylinder";
  if (matches(/\bcone\b/)) return "cone";
  if (matches(/\bsphere\b|\bhemisphere\b/)) return "sphere";
  if (matches(/\bworked example\b|\bexample\b|\bsolve\b|\bfind the\b|\bcalculate\b/)) return "worked-example";
  if (matches(/\bcompare\b|\bdifference\b|\bvs\b|\bbetween\b/)) return "comparison";
  if (matches(/\bpractice\b|\btry\b|\bquick check\b|\bexit ticket\b|\brecap\b|\bsummary\b/)) return "practice-or-recap";
  if (inferMathDiagramTypeFromText(normalized) === "numberLine") return "number-line";
  return "";
}

function slideNeedsTextAccurateVisual(slide: any) {
  const normalized = normalizeVisualSemanticText(slide);
  return Boolean(
    shouldPreferSvgVisual(slide) ||
    /\bformula\b|\bequation\b|\blabel(?:led)?\b|\bchart\b|\btable\b|\bcompare\b|\btsa\b|\blsa\b|\bcsa\b|\bnet\b|\bderivation\b|\bsubstitute\b/.test(normalized)
  );
}

function shouldRenderVisualForSlide(slide: any) {
  return Boolean(slide && typeof slide === "object");
}

function getVisualContentIdentity(slide: any) {
  const conceptKey = inferSlideConceptKey(slide) || "general";
  const title = renderableToExportPlainText(slide?.slideTitle || "").trim().toLowerCase();
  const beat = renderableToExportPlainText(slide?.teachingBeat || "").trim().toLowerCase();
  const mustTeach = (Array.isArray(slide?.mustTeach) ? slide.mustTeach : [])
    .map((item: any) => renderableToExportPlainText(item).trim().toLowerCase())
    .filter(Boolean)
    .join(" | ");
  const visualPlan = renderableToExportPlainText(slide?.visualPlan || "").trim().toLowerCase();
  return `${conceptKey}::${title}::${beat}::${mustTeach}::${visualPlan}`;
}

function buildSlideSpecificVisualQuery(
  slide: any,
  sessionContext: {
    subject?: string;
    gradeLevel?: string;
    sessionTitle?: string;
  }
) {
  const simplifyLabel = (value: any) =>
    renderableToExportPlainText(value)
      .replace(/\([^)]*\)/g, " ")
      .replace(/\b(generate|generated|create|created|render|rendered|illustration|hero|full-slide|full slide|cinematic|poster|dramatic|designed to|showing|with visible|background)\b/gi, " ")
      .replace(/\b(session|slide|lesson|introduction|review|recap|summary|understanding|check your understanding|quick check)\b/gi, " ")
      .replace(/\b(what|why|how|when|where)\b/gi, " ")
      .replace(/\b(definition|examples|example|raw materials|factors affecting|key concepts|content)\b/gi, " ")
      .replace(/\d+[\.\)]/g, " ")
      .replace(/[-–—]/g, " ")
      .replace(/[,:;]+/g, " ")
      .replace(/\s+/g, " ")
      .trim();

  const explicitLabel = simplifyLabel(slide?.searchQuery || "");
  if (explicitLabel) {
    return limitString(explicitLabel, 48);
  }

  const title = simplifyLabel(slide?.slideTitle || slide?.title || "");
  const mustTeach = (Array.isArray(slide?.mustTeach) ? slide.mustTeach : [])
    .map((item: any) => simplifyLabel(item))
    .filter(Boolean)
    .slice(0, 1);
  const topicCoverage = (Array.isArray(slide?.topicCoverage) ? slide.topicCoverage : [])
    .map((item: any) => simplifyLabel(item))
    .filter(Boolean)
    .slice(0, 1);

  const labelParts = [
    title,
    topicCoverage.join(" "),
    mustTeach.join(" "),
  ]
    .map((part) => String(part || "").trim())
    .filter(Boolean);

  const label = limitString(uniqueStrings(labelParts).join(" "), 48);

  if (label) {
    return label;
  }

  const conceptKey = inferSlideConceptKey(slide);
  const subjectHints = normalizeSourceText(String(sessionContext.subject || ""));
  if (conceptKey === "comparison" && /\bnutrition\b/.test(subjectHints + " " + normalizeVisualSemanticText(slide))) {
    return "autotroph heterotroph comparison";
  }
  if (/\bphotosynthesis\b/.test(normalizeVisualSemanticText(slide))) {
    return "photosynthesis plant leaf";
  }
  if (/\bstomata\b/.test(normalizeVisualSemanticText(slide))) {
    return "leaf stomata microscope";
  }
  if (/\blitmus\b/.test(normalizeVisualSemanticText(slide))) {
    return "blue red litmus paper";
  }
  if (/\bturmeric\b/.test(normalizeVisualSemanticText(slide))) {
    return "turmeric powder bowl";
  }
  if (/\bhibiscus\b|\bchina rose\b|\bgudhal\b/.test(normalizeVisualSemanticText(slide))) {
    return "hibiscus rosa-sinensis flower";
  }
  return limitString(simplifyLabel(sessionContext.subject || slide?.slideTitle || "classroom science"), 48);
}

function simplifyWikimediaLabel(label: string, fallback = "science classroom experiment") {
  const normalized = normalizeSourceText(String(label || ""))
    .replace(/\b(session|lesson|slide|chapter|unit|topic|summary|homework|worksheet|question|activity)\b/g, " ")
    .replace(/\b(generate|generated|create|created|render|rendered|illustration|poster|cinematic|vector|style|simple|colorful|beautiful|explainer|diagram)\b/g, " ")
    .replace(/[^\p{L}\p{N}\s-]/gu, " ")
    .replace(/[-–—]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
  const tokens = normalized
    .split(/\s+/)
    .filter(Boolean)
    .filter((token) => token.length > 1)
    .slice(0, 6);
  const collapsed = tokens.join(" ").trim();
  return collapsed || fallback;
}

function buildSubsetWikimediaLabelCandidates(label: string) {
  const normalized = simplifyWikimediaLabel(label, "").trim();
  if (!normalized) {
    return [];
  }
  const tokens = normalized.split(/\s+/).filter(Boolean);
  const unique = new Set<string>();
  const candidates: string[] = [];
  const push = (value: string) => {
    const simplified = simplifyWikimediaLabel(value, "").trim();
    if (!simplified || unique.has(simplified)) return;
    unique.add(simplified);
    candidates.push(simplified);
  };

  push(normalized);
  if (tokens.length >= 3) {
    push(tokens.slice(0, 3).join(" "));
    push(tokens.slice(-3).join(" "));
  }
  if (tokens.length >= 2) {
    push(tokens.slice(0, 2).join(" "));
    push(tokens.slice(-2).join(" "));
  }
  tokens.forEach((token) => push(token));
  return candidates;
}

function buildWikimediaLabelCandidates(
  slide: any,
  sessionContext: {
    subject?: string;
    gradeLevel?: string;
    sessionTitle?: string;
  },
  labels: Array<string | undefined | null>
) {
  const unique = new Set<string>();
  const candidates: string[] = [];

  const push = (value: string | undefined | null) => {
    const simplified = simplifyWikimediaLabel(String(value || ""), "");
    if (!simplified || unique.has(simplified)) return;
    unique.add(simplified);
    candidates.push(simplified);
  };

  labels.forEach((label) => {
    buildSubsetWikimediaLabelCandidates(String(label || "")).forEach(push);
  });

  return candidates.slice(0, 8);
}

function uniquifyWikimediaLabel(
  label: string,
  slide: any,
  usedLabels: Map<string, number>
) {
  if (!String(label || "").trim()) {
    return "";
  }
  const simplified = simplifyWikimediaLabel(label, "science classroom experiment");
  const priorCount = usedLabels.get(simplified) || 0;
  if (priorCount === 0) {
    usedLabels.set(simplified, 1);
    return simplified;
  }

  const conceptKey = inferSlideConceptKey(slide);
  const variants = [
    conceptKey === "comparison" ? `${simplified} chart` : "",
    /\btitle\b/.test(normalizeSourceText(renderableToExportPlainText(slide?.slidePurpose || ""))) ? "school science class" : "",
    /\bhook\b/.test(normalizeSourceText(renderableToExportPlainText(slide?.slidePurpose || ""))) ? "science lab activity" : "",
    /\bsummary\b|\bhomework\b|\bquick_assessment\b/.test(normalizeSourceText(renderableToExportPlainText(slide?.slidePurpose || ""))) ? "students science activity" : "",
    simplifyWikimediaLabel(renderableToExportPlainText(slide?.slideTitle || ""), ""),
  ].filter(Boolean);

  for (const variant of variants) {
    if (!usedLabels.has(variant)) {
      usedLabels.set(variant, 1);
      return variant;
    }
  }

  usedLabels.set(simplified, priorCount + 1);
  return simplified;
}

function deriveFallbackWikimediaLabel(
  slide: any,
  sessionContext: {
    subject?: string;
    gradeLevel?: string;
    sessionTitle?: string;
  }
) {
  const normalized = normalizeVisualSemanticText(slide);
  const purpose = normalizeSourceText(renderableToExportPlainText(slide?.slidePurpose || slide?.templateSlideKey || slide?.slideType || ""));
  const conceptKey = inferSlideConceptKey(slide);

  if (/\brefraction\b|\bbending of light\b/.test(normalized)) return "light refraction glass";
  if (/\breflection\b/.test(normalized)) return "light reflection mirror";
  if (/\bprism\b/.test(normalized)) return "glass prism rainbow";
  if (/\blens\b/.test(normalized) && /\bconvex\b/.test(normalized)) return "convex lens";
  if (/\blens\b/.test(normalized) && /\bconcave\b/.test(normalized)) return "concave lens";
  if (/\blight ray\b|\bray diagram\b|\bincident ray\b|\brefracted ray\b|\bnormal line\b/.test(normalized)) return "light ray";
  if (/\bphotosynthesis\b/.test(normalized)) return "green leaf sunlight";
  if (/\bstomata\b/.test(normalized)) return "leaf stomata microscope";
  if (/\brespiration\b/.test(normalized)) return "human lungs breathing";
  if (/\blitmus\b/.test(normalized)) return "litmus paper colors";
  if (/\bturmeric\b/.test(normalized)) return "turmeric powder bowl";
  if (/\bhibiscus\b|\bchina rose\b|\bgudhal\b/.test(normalized)) return "hibiscus flower";
  if (/\bonion\b/.test(normalized) || /\bvanilla\b/.test(normalized)) return "onion bulb vanilla";
  if (/\bneutralization\b/.test(normalized) || /\bacid\b/.test(normalized) && /\bbase\b/.test(normalized)) return "acid base beaker";
  if (/\bautotrophic\b/.test(normalized) || /\bheterotrophic\b/.test(normalized) || conceptKey === "comparison") return "plant leaf and cow";
  if (/\bnutrition\b/.test(normalized) && /\bplant\b/.test(normalized)) return "green plant leaf";
  if (/\bnutrition\b/.test(normalized) && /\banimal\b/.test(normalized)) return "animal eating food";
  if (purpose.includes("title") || purpose.includes("hook") || purpose.includes("summary") || purpose.includes("quick_assessment") || purpose.includes("homework")) {
    return "science classroom experiment";
  }

  return simplifyWikimediaLabel(buildSlideSpecificVisualQuery({
    ...slide,
    searchQuery: "",
  }, sessionContext));
}

function isBadWikimediaLabel(label: string) {
  const normalized = normalizeSourceText(String(label || ""));
  if (!normalized) return true;
  const tokenCount = normalized.split(/\s+/).filter(Boolean).length;
  if (tokenCount < 2 || tokenCount > 8) return true;
  if (normalized.length > 56) return true;

  return /\b(educational|illustration|render|generated|cinematic|poster|split screen|white background|classroom diagram|process diagram|flowchart|vector style|icon|icons|session|lesson|slide|summary|quick check|check your understanding|beautiful|colorful|labeled|labelled|simple vector|checklist|notebook|pencil)\b/.test(normalized);
}

function validateResolvedSlideVisual(
  slide: any,
  candidate: {
    svgCode?: string;
    sourceKind?: string;
    promptHash?: string;
    model?: string;
    imageDataUrl?: string;
  } | null | undefined
) {
  const conceptKey = inferSlideConceptKey(slide);
  const requiresVisual = shouldRenderVisualForSlide(slide);
  if (!requiresVisual) {
    return { visualResolved: false, visualRelevanceStatus: "none", conceptKey };
  }

  if (!candidate) {
    return { visualResolved: false, visualRelevanceStatus: "none", conceptKey };
  }

  const svgCode = String(candidate.svgCode || "").trim();
  const sourceKind = String(candidate.sourceKind || "").trim();
  const genericBannedPattern = /\breal numbers?\b|\brational\b|\birrational\b/;
  const slideNormalized = normalizeVisualSemanticText(slide);
  const candidateNormalized = normalizeSourceText([
    svgCode,
    sourceKind,
    candidate.model,
  ].filter(Boolean).join(" "));

  if (genericBannedPattern.test(candidateNormalized) && !genericBannedPattern.test(slideNormalized)) {
    return { visualResolved: false, visualRelevanceStatus: "generic", conceptKey };
  }

  if (sourceKind === "generated-image" && slideNeedsTextAccurateVisual(slide)) {
    return { visualResolved: false, visualRelevanceStatus: "mismatch", conceptKey };
  }

  if (svgCode) {
    if (!svgCode.startsWith("<svg") && !svgCode.startsWith("<?xml")) {
      return { visualResolved: false, visualRelevanceStatus: "none", conceptKey };
    }

    if (conceptKey === "cube" && !/\bs\b|cube/i.test(svgCode)) {
      return { visualResolved: false, visualRelevanceStatus: "mismatch", conceptKey };
    }
    if (conceptKey === "cuboid" && !/\bl\b|\bb\b|\bh\b|cuboid|rectangular prism/i.test(svgCode)) {
      return { visualResolved: false, visualRelevanceStatus: "mismatch", conceptKey };
    }
    if (conceptKey === "cylinder" && !/\bcylinder\b|\br\b|\bh\b/i.test(svgCode)) {
      return { visualResolved: false, visualRelevanceStatus: "mismatch", conceptKey };
    }
    if (conceptKey === "cone" && !/\bcone\b/i.test(svgCode)) {
      return { visualResolved: false, visualRelevanceStatus: "mismatch", conceptKey };
    }
    if (conceptKey === "sphere" && !/\bsphere\b/i.test(svgCode)) {
      return { visualResolved: false, visualRelevanceStatus: "mismatch", conceptKey };
    }
    if (conceptKey === "tsa-vs-lsa" && !/\btsa\b|\blsa\b|\bcsa\b|surface/i.test(svgCode)) {
      return { visualResolved: false, visualRelevanceStatus: "mismatch", conceptKey };
    }
  }

  if (!svgCode && !candidate.imageDataUrl && sourceKind !== "reusable-external") {
    return { visualResolved: false, visualRelevanceStatus: "none", conceptKey };
  }

  return { visualResolved: true, visualRelevanceStatus: "valid", conceptKey };
}

function buildSolid3DMathSvgDiagram(slide: any, themeTokens: any) {
  const title = xmlEscape(renderableToExportPlainText(slide?.slideTitle || "Solid shape"));
  const sourceText = [
    slide?.slideTitle,
    ...(Array.isArray(slide?.bulletPoints) ? slide.bulletPoints : []),
    ...(Array.isArray(slide?.onSlideText) ? slide.onSlideText : []),
    slide?.visualPlan,
  ].map((item: any) => renderableToExportPlainText(item)).join(" ");
  const normalized = normalizeSourceText(sourceText);
  const primary = String(themeTokens?.colors?.primary || "#1D4E89").replace("#", "");
  const accent = String(themeTokens?.colors?.accent || "#D97706").replace("#", "");
  const surface = String(themeTokens?.colors?.surface || "#FFFFFF").replace("#", "");
  const text = String(themeTokens?.colors?.text || "#1F2937").replace("#", "");
  const muted = String(themeTokens?.colors?.mutedText || "#6B7280").replace("#", "");
  const annotationLines = (Array.isArray(slide?.bulletPoints) ? slide.bulletPoints : [])
    .map((item: any) => renderableToExportPlainText(item).trim())
    .filter(Boolean)
    .slice(0, 3)
    .map((item) => xmlEscape(limitString(item, 64)));

  const buildSvgWrappedTextBlock = (
    x: number,
    y: number,
    width: number,
    height: number,
    lines: string[],
    options: {
      fontSize?: number;
      fontWeight?: number;
      color?: string;
      lineHeight?: number;
    } = {}
  ) => {
    const color = options.color || `#${text}`;
    const preferredFontSize = options.fontSize || 22;
    const fontWeight = options.fontWeight || 400;
    const lineHeight = options.lineHeight || 1.45;
    const minFontSize = Math.max(11, Math.floor(preferredFontSize * 0.62));
    const rawText = lines.map((line) => limitString(renderableToExportPlainText(line), 160)).filter(Boolean);

    const wrapWords = (fontSize: number) => {
      const approxCharWidth = Math.max(6.4, fontSize * 0.56);
      const maxCharsPerLine = Math.max(12, Math.floor((width - 8) / approxCharWidth));
      const wrapped: string[] = [];

      for (const paragraph of rawText) {
        const words = paragraph.split(/\s+/).filter(Boolean);
        let currentLine = "";
        for (const word of words) {
          if (!currentLine) {
            currentLine = word;
            continue;
          }
          const candidate = `${currentLine} ${word}`;
          if (candidate.length <= maxCharsPerLine) {
            currentLine = candidate;
          } else {
            wrapped.push(currentLine);
            currentLine = word;
          }
        }
        if (currentLine) {
          wrapped.push(currentLine);
        }
      }

      return wrapped.slice(0, 8);
    };

    let resolvedFontSize = preferredFontSize;
    let resolvedLines = wrapWords(resolvedFontSize);
    while (resolvedFontSize > minFontSize && resolvedLines.length * resolvedFontSize * lineHeight > height - 6) {
      resolvedFontSize -= 1;
      resolvedLines = wrapWords(resolvedFontSize);
    }

    const maxLines = Math.max(1, Math.floor((height - 6) / (resolvedFontSize * lineHeight)));
    const fittedLines = resolvedLines.slice(0, maxLines).map((line, index, arr) => {
      if (index !== arr.length - 1 || resolvedLines.length <= maxLines) {
        return line;
      }
      return line.length > 3 ? `${line.slice(0, Math.max(0, line.length - 3)).trim()}...` : line;
    });
    const content = fittedLines.map((line) => `<div>${xmlEscape(line)}</div>`).join("");

    return `<foreignObject x="${x}" y="${y}" width="${width}" height="${height}">
      <div xmlns="http://www.w3.org/1999/xhtml" style="font-family: Arial, sans-serif; font-size: ${resolvedFontSize}px; font-weight: ${fontWeight}; line-height: ${lineHeight}; color: ${color}; width: ${width}px; height: ${height}px; overflow: hidden; overflow-wrap: anywhere; word-break: break-word; display: flex; flex-direction: column; justify-content: flex-start;">
        ${content}
      </div>
    </foreignObject>`;
  };

  const annotationText = annotationLines.length
    ? buildSvgWrappedTextBlock(560, 248, 248, 92, annotationLines, {
        fontSize: 20,
        color: `#${text}`,
        lineHeight: 1.35,
      })
    : "";

  if (/\bcylinder\b/.test(normalized)) {
    return `<?xml version="1.0" encoding="UTF-8"?>
<svg xmlns="http://www.w3.org/2000/svg" width="960" height="720" viewBox="0 0 960 720" role="img" aria-label="${title}">
  <rect width="960" height="720" fill="#F8FBFD"/>
  <rect x="60" y="52" width="840" height="90" rx="24" fill="#${primary}"/>
  <text x="90" y="108" font-family="Arial, sans-serif" font-weight="700" font-size="34" fill="#FFFFFF">${title}</text>
  <ellipse cx="280" cy="220" rx="120" ry="42" fill="#EAF2FB" stroke="#${primary}" stroke-width="4"/>
  <rect x="160" y="220" width="240" height="280" fill="#FFFFFF" stroke="#${primary}" stroke-width="4"/>
  <ellipse cx="280" cy="500" rx="120" ry="42" fill="#DFF3F2" stroke="#${primary}" stroke-width="4"/>
  <ellipse cx="280" cy="220" rx="120" ry="42" fill="none" stroke="#${primary}" stroke-width="4"/>
  <line x1="280" y1="220" x2="400" y2="220" stroke="#${accent}" stroke-width="4"/>
  <text x="330" y="205" font-family="Arial, sans-serif" font-size="22" font-weight="700" fill="#${accent}">r</text>
  <line x1="430" y1="220" x2="430" y2="500" stroke="#${accent}" stroke-width="4"/>
  <text x="444" y="370" font-family="Arial, sans-serif" font-size="22" font-weight="700" fill="#${accent}">h</text>
  <rect x="520" y="178" width="320" height="170" rx="24" fill="#${surface}" stroke="#${primary}" stroke-width="4"/>
  <text x="560" y="220" font-family="Arial, sans-serif" font-size="26" font-weight="700" fill="#${primary}">Cylinder Visual Guide</text>
  ${annotationText || buildSvgWrappedTextBlock(560, 248, 248, 92, ["Use r for radius and h for height."], { fontSize: 20, color: `#${text}`, lineHeight: 1.35 })}
  <rect x="520" y="390" width="320" height="160" rx="24" fill="#FFF7ED" stroke="#${accent}" stroke-width="4"/>
  <text x="560" y="432" font-family="Arial, sans-serif" font-size="24" font-weight="700" fill="#${accent}">Teaching Focus</text>
  ${buildSvgWrappedTextBlock(560, 462, 248, 64, ["Separate curved surface from the two circular bases."], { fontSize: 19, color: `#${text}`, lineHeight: 1.3 })}
  <text x="560" y="564" font-family="Arial, sans-serif" font-size="18" fill="#${muted}">All labels stay editable in PPT text overlays.</text>
</svg>`;
  }

  if (/\bcube\b/.test(normalized) && !/\bcuboid\b/.test(normalized)) {
    return `<?xml version="1.0" encoding="UTF-8"?>
<svg xmlns="http://www.w3.org/2000/svg" width="960" height="720" viewBox="0 0 960 720" role="img" aria-label="${title}">
  <rect width="960" height="720" fill="#F8FBFD"/>
  <rect x="60" y="52" width="840" height="90" rx="24" fill="#${primary}"/>
  <text x="90" y="108" font-family="Arial, sans-serif" font-weight="700" font-size="34" fill="#FFFFFF">${title}</text>
  <polygon points="190,470 340,470 340,300 190,300" fill="#FFFFFF" stroke="#${primary}" stroke-width="4"/>
  <polygon points="340,470 430,410 430,240 340,300" fill="#EAF2FB" stroke="#${primary}" stroke-width="4"/>
  <polygon points="190,300 340,300 430,240 280,240" fill="#DFF3F2" stroke="#${primary}" stroke-width="4"/>
  <line x1="190" y1="470" x2="280" y2="410" stroke="#${primary}" stroke-width="4"/>
  <line x1="280" y1="410" x2="430" y2="410" stroke="#${primary}" stroke-width="4"/>
  <line x1="280" y1="410" x2="280" y2="240" stroke="#${primary}" stroke-width="4"/>
  <line x1="205" y1="488" x2="325" y2="488" stroke="#${accent}" stroke-width="4"/>
  <text x="258" y="516" font-family="Arial, sans-serif" font-size="22" font-weight="700" fill="#${accent}">s</text>
  <rect x="520" y="178" width="320" height="170" rx="24" fill="#${surface}" stroke="#${primary}" stroke-width="4"/>
  <text x="560" y="220" font-family="Arial, sans-serif" font-size="26" font-weight="700" fill="#${primary}">Cube Visual Guide</text>
  ${annotationText || buildSvgWrappedTextBlock(560, 248, 248, 92, ["All 6 faces are congruent squares."], { fontSize: 20, color: `#${text}`, lineHeight: 1.35 })}
  <rect x="520" y="390" width="320" height="160" rx="24" fill="#FFF7ED" stroke="#${accent}" stroke-width="4"/>
  <text x="560" y="432" font-family="Arial, sans-serif" font-size="24" font-weight="700" fill="#${accent}">Teaching Focus</text>
  ${buildSvgWrappedTextBlock(560, 462, 248, 64, ["Show how identical square faces lead to repeated area reasoning."], { fontSize: 19, color: `#${text}`, lineHeight: 1.3 })}
</svg>`;
  }

  if (/\bcuboid\b/.test(normalized) || /\brectangular prism\b/.test(normalized)) {
    return `<?xml version="1.0" encoding="UTF-8"?>
<svg xmlns="http://www.w3.org/2000/svg" width="960" height="720" viewBox="0 0 960 720" role="img" aria-label="${title}">
  <rect width="960" height="720" fill="#F8FBFD"/>
  <rect x="60" y="52" width="840" height="90" rx="24" fill="#${primary}"/>
  <text x="90" y="108" font-family="Arial, sans-serif" font-weight="700" font-size="34" fill="#FFFFFF">${title}</text>
  <polygon points="130,520 340,520 340,330 130,330" fill="#FFFFFF" stroke="#${primary}" stroke-width="4"/>
  <polygon points="340,520 450,450 450,260 340,330" fill="#EAF2FB" stroke="#${primary}" stroke-width="4"/>
  <polygon points="130,330 340,330 450,260 240,260" fill="#DFF3F2" stroke="#${primary}" stroke-width="4"/>
  <line x1="130" y1="520" x2="240" y2="450" stroke="#${primary}" stroke-width="4"/>
  <line x1="240" y1="450" x2="450" y2="450" stroke="#${primary}" stroke-width="4"/>
  <line x1="240" y1="450" x2="240" y2="260" stroke="#${primary}" stroke-width="4"/>
  <line x1="150" y1="542" x2="320" y2="542" stroke="#${accent}" stroke-width="4"/>
  <text x="230" y="575" font-family="Arial, sans-serif" font-size="24" font-weight="700" fill="#${accent}">l</text>
  <line x1="360" y1="540" x2="435" y2="492" stroke="#${accent}" stroke-width="4"/>
  <text x="430" y="548" font-family="Arial, sans-serif" font-size="24" font-weight="700" fill="#${accent}">b</text>
  <line x1="475" y1="260" x2="475" y2="450" stroke="#${accent}" stroke-width="4"/>
  <text x="492" y="364" font-family="Arial, sans-serif" font-size="24" font-weight="700" fill="#${accent}">h</text>
  <rect x="540" y="164" width="330" height="186" rx="24" fill="#${surface}" stroke="#${primary}" stroke-width="4"/>
  <text x="570" y="208" font-family="Arial, sans-serif" font-size="24" font-weight="700" fill="#${primary}">Cuboid Visual Guide</text>
  ${annotationText || buildSvgWrappedTextBlock(570, 230, 270, 104, ["Define total surface area using the three different face pairs l, b, and h."], { fontSize: 18, color: `#${text}`, lineHeight: 1.3 })}
  <rect x="540" y="384" width="330" height="176" rx="24" fill="#FFF7ED" stroke="#${accent}" stroke-width="4"/>
  <text x="570" y="428" font-family="Arial, sans-serif" font-size="22" font-weight="700" fill="#${accent}">Teaching Focus</text>
  ${buildSvgWrappedTextBlock(570, 450, 270, 88, ["Group equal opposite faces first, then build the TSA or LSA formula step by step."], { fontSize: 17, color: `#${text}`, lineHeight: 1.28 })}
</svg>`;
  }

  if (/\bcone\b/.test(normalized) || /\bsphere\b/.test(normalized)) {
    const shapeLabel = /\bcone\b/.test(normalized) ? "Cone" : "Sphere";
    return `<?xml version="1.0" encoding="UTF-8"?>
<svg xmlns="http://www.w3.org/2000/svg" width="960" height="720" viewBox="0 0 960 720" role="img" aria-label="${title}">
  <rect width="960" height="720" fill="#F8FBFD"/>
  <rect x="60" y="52" width="840" height="90" rx="24" fill="#${primary}"/>
  <text x="90" y="108" font-family="Arial, sans-serif" font-weight="700" font-size="34" fill="#FFFFFF">${title}</text>
  <text x="180" y="360" font-family="Arial, sans-serif" font-size="46" font-weight="700" fill="#${primary}">${shapeLabel}</text>
  <text x="180" y="410" font-family="Arial, sans-serif" font-size="24" fill="#${text}">Use a labeled board-style figure here.</text>
  <rect x="520" y="178" width="300" height="170" rx="24" fill="#${surface}" stroke="#${primary}" stroke-width="4"/>
  <text x="552" y="220" font-family="Arial, sans-serif" font-size="26" font-weight="700" fill="#${primary}">${shapeLabel} Visual Guide</text>
  ${annotationText || buildSvgWrappedTextBlock(552, 248, 228, 92, ["Keep the figure uncluttered and exact."], { fontSize: 20, color: `#${text}`, lineHeight: 1.35 })}
</svg>`;
  }

  return "";
}

