app.post("/api/analyze-curriculum", async (req, res) => {
  const {
    text,
    fileName = "",
    schemaVersion: requestedSchemaVersion,
    selectedClasses = [],
    persist = false,
    supportingDocuments = [],
  } = req.body;
  if (!text || text.trim().length === 0) {
    return res.status(400).json({ error: "No curriculum text provided." });
  }
  const requestIdHeader = req.headers["x-debug-request-id"];
  const requestId = typeof requestIdHeader === "string" && requestIdHeader.trim()
    ? requestIdHeader
    : makeRequestId("analyze-curriculum");
  const debugDir = await ensureDebugDir(requestId);
  const requestedSelectedClasses = Array.isArray(selectedClasses)
    ? selectedClasses.map((item) => String(item || "").trim()).filter(Boolean)
    : [];
  const primarySourceText = String(text);
  const primaryDetectedSubject = detectCurriculumSubjectFromInput(primarySourceText, String(fileName || ""));
  const normalizedSupportingDocuments = normalizeSupportingCurriculumDocuments(supportingDocuments);
  const activeSupportingDocuments = isTamilCurriculumSubject(primaryDetectedSubject)
    ? normalizedSupportingDocuments
    : [];
  const hasTamilIndexDocument = activeSupportingDocuments.some((document) => document.role === "textbook_index");
  if (isTamilCurriculumSubject(primaryDetectedSubject) && !hasTamilIndexDocument) {
    return res.status(400).json({ error: "Tamil curriculum parsing requires a Textbook Index upload before analysis." });
  }
  const sourceFilter = filterSourceTextToSelectedClasses(primarySourceText, requestedSelectedClasses);
  if (requestedSelectedClasses.length > 0 && sourceFilter.selectedClassNames.length === 0) {
    return res.status(400).json({ error: "Selected classes were not found in the uploaded curriculum text." });
  }
  const filteredPrimarySourceText = String(sourceFilter.sourceText || primarySourceText);
  const primaryStageSourceText = filteredPrimarySourceText;
  const combinedSourceText = buildCombinedCurriculumSourceText(
    filteredPrimarySourceText,
    String(fileName || ""),
    activeSupportingDocuments
  );
  const schemaVersion = normalizeSchemaVersion(requestedSchemaVersion);
  const sourceText = primaryStageSourceText;
  const detectedProfile = detectCurriculumProfile(sourceText, fileName);
  const profileConfig = getCurriculumProfileConfig(detectedProfile.profile);
  const earlyEnglishMode = shouldUseEnglishIntelligence({
    subject: primaryDetectedSubject,
    sourceText: filteredPrimarySourceText,
    fileName,
  });
  const earlyTamilMode = isTamilCurriculumSubject(primaryDetectedSubject);
  const earlyCurriculumExtractionOllamaOverrides = getCurriculumExtractionOllamaOverrides({
    subject: primaryDetectedSubject,
    sourceText: filteredPrimarySourceText,
    fileName,
  });
  const isPdfUpload = String(fileName).toLowerCase().endsWith(".pdf");
  const looksLikeMarkdown =
    /^\s*#\s+Page\s+\d+/m.test(filteredPrimarySourceText) ||
    /^\s*##\s+/m.test(filteredPrimarySourceText) ||
    /^\s*-\s+/m.test(filteredPrimarySourceText);
  console.log(`[Request][${requestId}] /api/analyze-curriculum started`);
  console.log(`[Request][${requestId}] File name: ${fileName || "(none)"}`);
  console.log(`[Request][${requestId}] Detected subject: ${primaryDetectedSubject || "(unknown)"}`);
  console.log(`[Request][${requestId}] Source text length: ${sourceText.length}`);
  console.log(`[Request][${requestId}] Combined source text length: ${combinedSourceText.length}`);
  console.log(`[Request][${requestId}] Supporting documents: ${activeSupportingDocuments.length}`);
  console.log(`[Request][${requestId}] Selected classes: ${requestedSelectedClasses.join(", ") || "(all detected classes)"}`);
  console.log(`[Request][${requestId}] Source text filtered to selected classes: ${sourceFilter.filtered ? "yes" : "no"}`);
  console.log(`[Request][${requestId}] Schema version: ${schemaVersion}`);
  console.log(`[Request][${requestId}] Curriculum profile: ${detectedProfile.profile} (${detectedProfile.confidence})`);
  console.log(`[Request][${requestId}] Indic curriculum extraction model active: ${earlyCurriculumExtractionOllamaOverrides.model ? "yes" : "no"}`);
  console.log(`[Request][${requestId}] PDF upload detected: ${isPdfUpload ? "yes" : "no"}`);
  console.log(`[Request][${requestId}] Source text looks like markdown: ${looksLikeMarkdown ? "yes" : "no"}`);
  if (isPdfUpload && looksLikeMarkdown) {
    console.log(`[Request][${requestId}] Using PDF->Markdown converted source text for curriculum extraction.`);
  }
  console.log(`[Request][${requestId}] Source text preview (first 2000 chars):\n${sourceText.slice(0, 2000)}`);
  await writeDebugFile(debugDir, "request-body.json", req.body);
  await writeDebugFile(debugDir, "supporting-documents.json", activeSupportingDocuments);
  await writeDebugFile(debugDir, "class-selection.json", sourceFilter);
  await writeDebugFile(debugDir, "primary-source-text.txt", filteredPrimarySourceText);
  await writeDebugFile(debugDir, "source-text.txt", combinedSourceText);
  await writeDebugFile(debugDir, "stage-source-text.txt", sourceText);
  await writeDebugFile(debugDir, "detected-profile.json", {
    schema_version: schemaVersion,
    curriculum_profile: detectedProfile.profile,
    profile_confidence: detectedProfile.confidence,
    profile_reasons: detectedProfile.reasons,
    expected_structure_type: profileConfig.expectedStructureType,
    detected_subject: primaryDetectedSubject,
    requires_tamil_index: earlyTamilMode,
  });
  if (isPdfUpload && looksLikeMarkdown) {
    await writeDebugFile(debugDir, "source-text.md", filteredPrimarySourceText);
  }
  try {
    const stage1FactsSchema = {
      document_metadata: {
        board: "",
        subject: "",
        class: "",
        grade: "",
        stream: "",
        academic_year: "",
        total_pages: "",
      },
      classes: [{
        class_name: "",
        subject: "",
        part_or_section: "",
      }],
      units: [{
        class_name: "",
        subject: "",
        part_or_section: "",
        unit_id: "U1",
        unit_name: "Unit heading from source",
        marks: null,
        topics: [""],
        subtopics: [""],
        key_concepts: [""],
      }],
      chapters: [{
        class_name: "",
        subject: "",
        part_or_section: "",
        unit_id: "U1",
        unit_name: "Unit heading from source",
        chapter_name: "",
        marks: null,
        topics: [""],
        subtopics: [""],
        key_concepts: [""],
      }],
      ...profileConfig.stage1SchemaExtension,
    };

    const extractionRules = `Extraction-first architecture is mandatory.
Complete stages strictly in this order:
${STAGE_ORDER.join("\n")}

Rules:
- explicit curriculum structure is the source of truth
- do not invent unit names or chapter names
- do not perform analysis during extraction stages
- no recommendations outside Stage 6
- return JSON only`;
    const profileSpecificRules = [
      `- Detected curriculum profile: ${detectedProfile.profile}`,
      `- Expected structure type: ${profileConfig.expectedStructureType}`,
      ...profileConfig.extraRules,
    ].join("\n");
    const buildStage1Prompt = (sourceText: string, chunkLabel?: string) => renderStage1PromptWithCurriculumIntelligence(CURRICULUM_PROMPT_FILES.faithfulExtraction, {
      STAGE_NAME: STAGE_ORDER[0],
      EXTRACTION_RULES: `${extractionRules}\n${profileSpecificRules}`,
      CHUNK_RULE: chunkLabel ? `- This is partial curriculum input for ${chunkLabel}; extract only what is present in this chunk` : "",
      SOURCE_TEXT: sourceText,
    }, {
      englishMode: earlyEnglishMode,
      tamilMode: earlyTamilMode,
      stageLabel: STAGE_ORDER[0],
    });
    const estimateStage1PromptLength = (inputSourceText: string, chunkLabel?: string) =>
      buildStage1Prompt(inputSourceText, chunkLabel).length;
    let stage1Facts: any;
    let initialStage1ChunkCount = 1;
    const tamilFastStage1Facts = earlyTamilMode
      ? buildTamilFastStage1Facts(sourceText, String(fileName || ""), {
          selectedClassNames: sourceFilter.selectedClassNames,
          supportingDocuments: activeSupportingDocuments,
        })
      : null;
    const canUseTamilFastPath = Boolean(
      tamilFastStage1Facts &&
      (((tamilFastStage1Facts?.units || []).length > 0) || ((tamilFastStage1Facts?.chapters || []).length > 0))
    );

    if (canUseTamilFastPath) {
      stage1Facts = tamilFastStage1Facts;
      console.log(`[Pipeline][${requestId}] ${STAGE_ORDER[0]} using Tamil fast path without Ollama chunking.`);
      await writeDebugFile(debugDir, "stage-1-plan.json", {
        sourceLength: sourceText.length,
        renderedPromptLength: 0,
        promptBudget: STAGE1_PROMPT_SAFE_BUDGET,
        initialRequestedChunkCount: 1,
        chunkCount: 0,
        fastPath: "tamil_deterministic_stage1",
      });
      await writeDebugFile(debugDir, `${safeStageName(STAGE_ORDER[0])}.facts.parsed.json`, stage1Facts);
    } else {
      const fullStage1PromptLength = estimateStage1PromptLength(sourceText);
      initialStage1ChunkCount = getAdaptiveStage1ChunkCount(sourceText.length, {
        estimatedPromptLength: fullStage1PromptLength,
        promptBudget: STAGE1_PROMPT_SAFE_BUDGET,
      });
      const plannedStage1Chunks = buildAdaptiveStage1Chunks(sourceText, {
        requestedChunkCount: initialStage1ChunkCount,
        estimatePromptLength: (chunkText) => estimateStage1PromptLength(chunkText),
        promptBudget: STAGE1_PROMPT_SAFE_BUDGET,
      });
      console.log(`[Pipeline][${requestId}] ${STAGE_ORDER[0]} source length=${sourceText.length} rendered prompt length=${fullStage1PromptLength} prompt budget=${STAGE1_PROMPT_SAFE_BUDGET}`);
      console.log(`[Pipeline][${requestId}] ${STAGE_ORDER[0]} planned chunk count: ${plannedStage1Chunks.length}`);
      await writeDebugFile(debugDir, "stage-1-chunks.json", {
        chunkCount: plannedStage1Chunks.length,
        chunkLengths: plannedStage1Chunks.map((chunk, index) => ({
          index: index + 1,
          length: chunk.length,
          renderedPromptLength: estimateStage1PromptLength(chunk, `chunk ${index + 1} of ${plannedStage1Chunks.length}`),
        })),
      });
      await writeDebugFile(debugDir, "stage-1-plan.json", {
        sourceLength: sourceText.length,
        renderedPromptLength: fullStage1PromptLength,
        promptBudget: STAGE1_PROMPT_SAFE_BUDGET,
        initialRequestedChunkCount: initialStage1ChunkCount,
        chunkCount: plannedStage1Chunks.length,
        chunks: plannedStage1Chunks.map((chunk, index) => ({
          index: index + 1,
          length: chunk.length,
          renderedPromptLength: estimateStage1PromptLength(chunk, `chunk ${index + 1} of ${plannedStage1Chunks.length}`),
        })),
      });

      if (plannedStage1Chunks.length === 1) {
        try {
          const stage1Prompt = buildStage1Prompt(sourceText);
          stage1Facts = await runStage(
            requestId,
            debugDir,
            STAGE_ORDER[0],
            stage1Prompt,
            stage1FactsSchema,
            {
              numPredict: OLLAMA_STAGE1_NUM_PREDICT,
              timeoutMs: OLLAMA_TIMEOUT_MS,
              retries: 2,
              ...earlyCurriculumExtractionOllamaOverrides,
            }
          );
        } catch (error: any) {
          if (!shouldUseChunkedStage1Fallback(error, sourceText)) {
            throw error;
          }

          const fallbackReason =
            String(error?.code || "") === "OLLAMA_EMPTY_RESPONSE"
              ? "empty response"
              : String(error?.code || "") === "OLLAMA_OUTPUT_TRUNCATED"
                ? "output truncation"
                : "retryable transport or timeout failure";
          console.warn(`[Pipeline][${requestId}] ${STAGE_ORDER[0]} switching to chunked fallback after ${fallbackReason}.`);
          const chunks = buildAdaptiveStage1Chunks(sourceText, {
            requestedChunkCount: Math.max(2, initialStage1ChunkCount),
            estimatePromptLength: (chunkText) => estimateStage1PromptLength(chunkText),
            promptBudget: STAGE1_PROMPT_SAFE_BUDGET,
          });
          console.warn(`[Pipeline][${requestId}] ${STAGE_ORDER[0]} chunk count: ${chunks.length}`);
          await writeDebugFile(debugDir, "stage-1-chunks.json", {
            chunkCount: chunks.length,
            chunkLengths: chunks.map((chunk, index) => ({
              index: index + 1,
              length: chunk.length,
              renderedPromptLength: estimateStage1PromptLength(chunk, `chunk ${index + 1} of ${chunks.length}`),
            })),
          });

          const chunkExtractions: any[] = [];
          for (let chunkIndex = 0; chunkIndex < chunks.length; chunkIndex += 1) {
            const chunkStageName = `${STAGE_ORDER[0]} - Chunk ${chunkIndex + 1}/${chunks.length}`;
            const chunkExtraction = await runStage1ChunkWithAdaptiveRetry(
              requestId,
              debugDir,
              chunkStageName,
              buildStage1Prompt,
              stage1FactsSchema,
              chunks[chunkIndex],
              `chunk ${chunkIndex + 1} of ${chunks.length}`,
              0,
              earlyCurriculumExtractionOllamaOverrides,
              {
                estimatePromptLength: estimateStage1PromptLength,
                promptBudget: STAGE1_PROMPT_SAFE_BUDGET,
              }
            );
            chunkExtractions.push(chunkExtraction);
          }

          stage1Facts = mergeStage1FactExtractions(chunkExtractions);
          await writeDebugFile(debugDir, `${safeStageName(STAGE_ORDER[0])}.chunked-merged.parsed.json`, stage1Facts);
        }
      } else {
        console.warn(`[Pipeline][${requestId}] ${STAGE_ORDER[0]} pre-chunking due to rendered prompt budget.`);
        console.warn(`[Pipeline][${requestId}] ${STAGE_ORDER[0]} chunk count: ${plannedStage1Chunks.length}`);

        const chunkExtractions: any[] = [];
        for (let chunkIndex = 0; chunkIndex < plannedStage1Chunks.length; chunkIndex += 1) {
          const chunkStageName = `${STAGE_ORDER[0]} - Chunk ${chunkIndex + 1}/${plannedStage1Chunks.length}`;
          const chunkExtraction = await runStage1ChunkWithAdaptiveRetry(
            requestId,
            debugDir,
            chunkStageName,
            buildStage1Prompt,
            stage1FactsSchema,
            plannedStage1Chunks[chunkIndex],
            `chunk ${chunkIndex + 1} of ${plannedStage1Chunks.length}`,
            0,
            earlyCurriculumExtractionOllamaOverrides,
            {
              estimatePromptLength: estimateStage1PromptLength,
              promptBudget: STAGE1_PROMPT_SAFE_BUDGET,
            }
          );
          chunkExtractions.push(chunkExtraction);
        }

        stage1Facts = mergeStage1FactExtractions(chunkExtractions);
        await writeDebugFile(debugDir, `${safeStageName(STAGE_ORDER[0])}.chunked-merged.parsed.json`, stage1Facts);
      }
    }

    const mergedStage1UnitCount = (stage1Facts?.units || []).length;
    const mergedStage1ChapterCount = (stage1Facts?.chapters || []).length;
    const mergedStage1ClassCount = (stage1Facts?.classes || []).length;
    const detectedSubject = canonicalizeSubjectName(stage1Facts?.document_metadata?.subject || stage1Facts?.classes?.[0]?.subject || "");
    const englishCurriculumMode = shouldUseEnglishIntelligence({
      subject: detectedSubject,
      sourceText,
      fileName,
    });
    const curriculumExtractionOllamaOverrides = getCurriculumExtractionOllamaOverrides({
      subject: detectedSubject,
      sourceText,
      fileName,
    });
    const initialChunkCount = initialStage1ChunkCount;
    if (mergedStage1UnitCount === 0 && mergedStage1ChapterCount === 0) {
      console.warn(
        `[Pipeline][${requestId}] Stage 1 merge returned empty extraction | subject="${detectedSubject}" | class="${stage1Facts?.document_metadata?.class || ""}" | sourceLength=${sourceText.length} | chunkCount=${initialChunkCount}`
      );
      if (isLanguageSubject(detectedSubject)) {
        const languageFallback = buildLanguageFallbackStage1Facts(sourceText, stage1Facts, { fileName });
        if (languageFallback.fallbackApplied) {
          console.warn(
            `[Pipeline][${requestId}] Language fallback applied | subject="${detectedSubject}" | recoveredUnits=${languageFallback.fallbackUnitsCount}`
          );
          stage1Facts = {
            ...stage1Facts,
            classes: languageFallback.classes,
            units: languageFallback.units,
            chapters: languageFallback.chapters,
          };
        } else {
          throw new Error(
            `Stage 1 extraction returned no units or chapters, and language fallback could not recover structure. Subject="${detectedSubject}" class="${stage1Facts?.document_metadata?.class || ""}" sourceLength=${sourceText.length} chunkCount=${initialChunkCount}.`
          );
        }
      } else {
        const structuredFallback = buildUnitChapterFallbackStage1Facts(sourceText, stage1Facts, {
          fileName: String(fileName || ""),
          detectedProfile: detectedProfile.profile,
        });
        if (structuredFallback.fallbackApplied) {
          console.warn(
            `[Pipeline][${requestId}] Structured Stage 1 fallback applied | subject="${structuredFallback.document_metadata?.subject || detectedSubject}" | recoveredUnits=${structuredFallback.fallbackUnitsCount} | recoveredChapters=${structuredFallback.fallbackChaptersCount}`
          );
          stage1Facts = {
            ...stage1Facts,
            document_metadata: {
              ...(stage1Facts?.document_metadata || {}),
              ...(structuredFallback.document_metadata || {}),
            },
            classes: structuredFallback.classes,
            units: structuredFallback.units,
            chapters: structuredFallback.chapters,
          };
        } else {
          throw new Error(
            `Stage 1 extraction returned no units or chapters. Empty LLM extraction for subject="${detectedSubject}" class="${stage1Facts?.document_metadata?.class || ""}" sourceLength=${sourceText.length} chunkCount=${initialChunkCount}.`
          );
        }
      }
    }

    let tamilNormalizationMetadata: Record<string, any> | null = null;
    if (isTamilCurriculumSubject(detectedSubject)) {
      const hardenedTamilFacts = hardenTamilStage1Facts(stage1Facts, {
        primarySourceText: filteredPrimarySourceText,
        selectedClassNames: sourceFilter.selectedClassNames,
        supportingDocuments: activeSupportingDocuments,
      });
      stage1Facts = hardenedTamilFacts.stage1Facts;
      tamilNormalizationMetadata = hardenedTamilFacts.metadata;
      await writeDebugFile(debugDir, "tamil-stage1-hardening.json", tamilNormalizationMetadata);
    }

    stage1Facts = backfillStage1MarksFromSource(stage1Facts, sourceText);

    await writeDebugFile(debugDir, `${safeStageName(STAGE_ORDER[0])}.facts.parsed.json`, stage1Facts);
    const rawExtraction = expandStage1FactsToRawExtraction(stage1Facts);
    let faithfulStructure = buildFaithfulStructureFromRawExtraction(rawExtraction);
    if (detectedProfile.profile === "cbse_unit_topic" || detectedProfile.profile === "cbse_unit_chapter_topic") {
      faithfulStructure = cleanupCbseStructure(faithfulStructure);
    }
    await writeDebugFile(debugDir, "faithful-structure.parsed.json", faithfulStructure);
    const faithfulWarnings = collectFaithfulStructureWarnings(faithfulStructure);
    await writeDebugFile(debugDir, "faithful-structure-warnings.json", faithfulWarnings);
    if (faithfulWarnings.length) {
      console.warn(`[Pipeline][${requestId}] Faithful structure warnings: ${JSON.stringify(faithfulWarnings)}`);
    }
    const rawClasses = rawExtraction.classes || [];
    const documentHierarchy = buildDocumentStructureHierarchy(rawExtraction);
    await writeDebugFile(debugDir, `${safeStageName(STAGE_ORDER[1])}.parsed.json`, documentHierarchy);
    const approvedHierarchy = buildApprovedTheoryHierarchy(rawExtraction, documentHierarchy);
    await writeDebugFile(debugDir, "approved-hierarchy.parsed.json", approvedHierarchy);
    console.log(`[Pipeline][${requestId}] raw extracted units count: ${rawClasses.reduce((sum: number, cls: any) => sum + ((cls?.units || []).length), 0)}`);
    console.log(`[Pipeline][${requestId}] approved theory units count: ${(approvedHierarchy?.classes || []).reduce((sum: number, cls: any) => sum + ((cls?.units || []).length), 0)}`);
    console.log(`[Pipeline][${requestId}] practical items count: ${(approvedHierarchy?.practicals || []).length}`);
    console.log(`[Pipeline][${requestId}] formative refs count: ${(approvedHierarchy?.formative_content_refs || []).length}`);
    console.log(`[Pipeline][${requestId}] ignored appendix items count: ${(approvedHierarchy?.ignored_items || []).length}`);

    const hierarchyClasses = approvedHierarchy.classes || [];
    const enrichedClasses: any[] = [];
    const enrichedClassMap = new Map<string, any>();

    for (let classIndex = 0; classIndex < hierarchyClasses.length; classIndex += 1) {
      const enrichmentResult = await normalizeClassTheory(
        requestId,
        debugDir,
        classIndex,
        hierarchyClasses[classIndex] || {},
        sourceText,
        englishCurriculumMode,
        curriculumExtractionOllamaOverrides
      );
      const rawClass = (hierarchyClasses[classIndex] || {}) as any;
      const classKey = buildCanonicalClassKey(rawClass?.class_name || "");
      const enrichedClass = {
        class_name: canonicalizeClassName(rawClass?.class_name || ""),
        subject: canonicalizeSubjectName(rawClass?.subject || ""),
        part_or_section: rawClass?.part_or_section || "",
        canonical_class_key: classKey,
        units: enrichmentResult?.units || [],
        formative_content_refs: enrichmentResult?.formative_content_refs || [],
        validation_report: enrichmentResult?.validation_report || {},
      };
      enrichedClasses.push(enrichedClass);
      enrichedClassMap.set(classKey, enrichedClass);
    }

    const nodeEnrichment = {
      classes: enrichedClasses,
      formative_content: approvedHierarchy.formative_content_refs || rawExtraction.formative_only_content || [],
      excluded_content: rawExtraction.assessment_information?.excluded_or_non_assessed_content || [],
      teacher_notes: rawExtraction.assessment_information?.teacher_notes || [],
    };
    await writeDebugFile(debugDir, `${safeStageName(STAGE_ORDER[2])}.parsed.json`, nodeEnrichment);

    const enforcedNormalizedClasses = buildNormalizedTeachingBlocks(
      hierarchyClasses,
      hierarchyClasses,
      enrichedClassMap,
      stage1Facts.units || [],
      stage1Facts.chapters || []
    );

    let normalizedStructure: any = {
      document_metadata: rawExtraction.document_metadata || {},
      source_hierarchy: documentHierarchy,
      classes: enforcedNormalizedClasses,
      practicals: approvedHierarchy.practicals || rawExtraction.practicals || [],
      activities: rawExtraction.activities || [],
      projects: rawExtraction.projects || [],
      assessment_information: rawExtraction.assessment_information || {},
      teacher_notes: nodeEnrichment.teacher_notes || rawExtraction.assessment_information?.teacher_notes || [],
      excluded_content: nodeEnrichment.excluded_content || rawExtraction.assessment_information?.excluded_or_non_assessed_content || [],
      validation_report: {
        structural_source_of_truth_enforced: true,
        suspicious_chapter_names: uniqueStrings(enforcedNormalizedClasses.flatMap((cls: any) => cls?.validation_report?.suspicious_chapter_names || [])),
        long_chapter_names_reclassified: uniqueStrings(enforcedNormalizedClasses.flatMap((cls: any) => cls?.validation_report?.long_chapter_names_reclassified || [])),
      },
    };
    if (detectedProfile.profile === "cbse_unit_topic" || detectedProfile.profile === "cbse_unit_chapter_topic") {
      normalizedStructure = cleanupCbseStructure(normalizedStructure);
    }
    await writeDebugFile(debugDir, `${safeStageName(STAGE_ORDER[3])}.parsed.json`, normalizedStructure);
    const hierarchyComparison = buildHierarchyComparisonReport(faithfulStructure, normalizedStructure);
    await writeDebugFile(debugDir, "hierarchy-comparison.parsed.json", hierarchyComparison);
    console.log(`[Pipeline][${requestId}] Faithful/planning hierarchy comparison: ${JSON.stringify(hierarchyComparison.totals)}`);
    const validationReport = await validateNormalizedStructure(requestId, debugDir, sourceText, normalizedStructure, rawExtraction);
    const profileWarnings = [...faithfulWarnings];
    if (detectedProfile.profile === "cbse_unit_topic") {
      const suspiciousFallbacks = (normalizedStructure.classes || []).flatMap((cls: any) =>
        (cls.units || []).flatMap((unit: any) =>
          (unit.chapters || []).filter((chapter: any) => chapter?.source_type === "unit_fallback").map((chapter: any) => `${cls.class_name}::${unit.unit_name}::${chapter.chapter_name}`)
        )
      );
      if (suspiciousFallbacks.length) {
        profileWarnings.push("Some units were reconstructed because explicit chapter headings were unavailable in the uploaded document.");
      }
    }
    if (detectedProfile.profile === "multi_class_board_syllabus" && (faithfulStructure.classes || []).length < 2) {
      profileWarnings.push("multi_class_board_syllabus detected but fewer than two classes were preserved");
    }
    if (detectedProfile.profile === "term_semester_curriculum" && !/\bsemester\b|\bterm\b/.test(normalizeSourceText(JSON.stringify(stage1Facts || {})))) {
      profileWarnings.push("term_semester_curriculum detected but term/semester entities were not preserved in Stage 1 facts");
    }
    const structureConfidence = Math.max(
      0.35,
      Math.min(
        0.99,
        detectedProfile.confidence - (profileWarnings.length * 0.06) - ((validationReport.invalid_chapters || []).length * 0.04)
      )
    );
    const fallbacksUsed = uniqueStrings([
      ...(isPdfUpload && looksLikeMarkdown ? ["pdf_to_markdown"] : []),
      ...((normalizedStructure.classes || []).flatMap((cls: any) =>
        (cls.units || []).flatMap((unit: any) =>
          (unit.chapters || []).some((chapter: any) => chapter?.source_type === "unit_fallback") ? ["reconstructed_chapter_headings"] : []
        )
      )),
    ]);
    await writeDebugFile(debugDir, "profile-validation.json", {
      curriculum_profile: detectedProfile.profile,
      profile_confidence: detectedProfile.confidence,
      structure_confidence: structureConfidence,
      warnings: uniqueStrings(profileWarnings.map(buildPublicWarningMessage).filter(Boolean)),
      fallbacks_used: uniqueStrings(fallbacksUsed.map(buildPublicFallbackLabel).filter(Boolean)),
    });
    const mergedNormalizedClasses = normalizedStructure.classes || [];
    const stage1UnitCount = mergedNormalizedClasses.reduce((acc: number, cls: any) => acc + (cls.units?.length || 0), 0);
    const stage1ChapterCount = mergedNormalizedClasses.reduce(
      (acc: number, cls: any) => acc + (cls.units || []).reduce((inner: number, unit: any) => inner + (unit.chapters?.length || 0), 0),
      0
    );
    console.log(`[Pipeline][${requestId}] Normalized unit count: ${stage1UnitCount}`);
    console.log(`[Pipeline][${requestId}] Normalized chapter count: ${stage1ChapterCount}`);
    if (stage1UnitCount === 0 || stage1ChapterCount === 0) {
      throw new Error(
          `Normalized structure is insufficient. Units: ${stage1UnitCount}, Chapters: ${stage1ChapterCount}, Subject: "${detectedSubject}", Class: "${stage1Facts?.document_metadata?.class || ""}", SourceLength: ${sourceText.length}, ChunkCount: ${initialChunkCount}.`
      );
    }

    const competencySchema = {
      competency_groups: [{
        code: "",
        title: "",
        description: "",
        competencies: [""],
        unit_name: "",
        chapter_name: "",
      }],
    };

    const structurePayload = buildSlimStructurePayload(normalizedStructure.classes || []);

    const competencies = await runStage6CompetencyExtractionWithFallback(
      requestId,
      debugDir,
      extractionRules,
      structurePayload,
      sourceText,
      competencySchema,
      englishCurriculumMode,
      curriculumExtractionOllamaOverrides
    );

    const assessmentSchema = {
      assessment_framework: {
        marks_distribution: [""],
        question_paper_design: [""],
        competency_weightage: [""],
        bloom_levels: [""],
        internal_assessment: [""],
        practical_assessment: [""],
        project_assessment: [""],
      },
    };

    const stage7Prompt = renderPromptWithEnglishIntelligence(CURRICULUM_PROMPT_FILES.assessmentExtraction, {
      EXTRACTION_RULES: extractionRules,
      STAGE_NAME: STAGE_ORDER[6],
      STAGE_PAYLOAD_JSON: serializeJson(structurePayload),
      SOURCE_TEXT: sourceText,
    }, {
      englishMode: englishCurriculumMode,
      stageLabel: STAGE_ORDER[6],
    });

    const assessment = await runStage(requestId, debugDir, STAGE_ORDER[6], stage7Prompt, assessmentSchema, curriculumExtractionOllamaOverrides);
    normalizedStructure.assessment_information = assessment.assessment_framework || {};

    const outcomesSchema = {
      learning_outcomes: [{
        unit_name: "",
        chapter_name: "",
        topic: "",
        outcomes: [""],
      }],
    };

    const stage8Payloads = (normalizedStructure.classes || [])
      .map((cls: any, index: number) => {
        const normalizedClassName = canonicalizeClassName(cls?.class_name || "");
        if (!normalizedClassName) return null;
        return {
          stageName: `${STAGE_ORDER[7]} - ${normalizedClassName || `Class ${index + 1}`}`,
          payload: buildStage8PayloadForClass(normalizedClassName, normalizedStructure.classes || [], competencies.competency_groups || []),
        };
      })
      .filter((entry: any): entry is { stageName: string; payload: any } => Boolean(entry?.payload));

    const stage8Results: any[] = [];
    for (const entry of stage8Payloads) {
      const payload = entry.payload as any;
      const payloadText = serializeJson(payload);
      const unitsCount = (payload?.units || []).length;
      const chaptersCount = (payload?.chapters || []).length;
      const competenciesCount = (payload?.competencies || []).length;
      console.log(`[Pipeline][${requestId}] ${entry.stageName} payload size before request: ${payloadText.length} characters`);
      console.log(`[Pipeline][${requestId}] ${entry.stageName} units count: ${unitsCount}`);
      console.log(`[Pipeline][${requestId}] ${entry.stageName} chapters count: ${chaptersCount}`);
      console.log(`[Pipeline][${requestId}] ${entry.stageName} competencies count: ${competenciesCount}`);

      const stage8Prompt = renderPromptWithEnglishIntelligence(CURRICULUM_PROMPT_FILES.learningOutcomesExtraction, {
        EXTRACTION_RULES: extractionRules,
        STAGE_NAME: entry.stageName,
        STAGE_PAYLOAD_JSON: payloadText,
      }, {
        englishMode: englishCurriculumMode,
        stageLabel: entry.stageName,
      });
      const stage8Result = await runStage(requestId, debugDir, entry.stageName, stage8Prompt, outcomesSchema, curriculumExtractionOllamaOverrides);
      stage8Results.push({
        class_name: payload?.class_name || "",
        learning_outcomes: (stage8Result as any)?.learning_outcomes || [],
      });
    }

    const outcomes = {
      learning_outcomes: stage8Results.flatMap((result: any) =>
        (result?.learning_outcomes || []).map((entry: any) => ({
          ...entry,
          class_name: entry?.class_name || result?.class_name || "",
        }))
      ),
    };
    await writeDebugFile(debugDir, `${safeStageName(STAGE_ORDER[7])}.parsed.json`, outcomes);

    const statistics = computeCurriculumStatistics(normalizedStructure, outcomes.learning_outcomes || []);
    await writeDebugFile(debugDir, "statistics.parsed.json", statistics);

    const activitySchema = {
      activities: [{
        type: "activity",
        title: "",
        unit_name: "",
        chapter_name: "",
        details: "",
      }],
      projects: [{
        title: "",
        unit_name: "",
        chapter_name: "",
        details: "",
      }],
      practicals: [{
        title: "",
        unit_name: "",
        chapter_name: "",
        details: "",
      }],
    };

    const stage9Prompt = renderPromptWithEnglishIntelligence(CURRICULUM_PROMPT_FILES.activitiesProjectsPracticalsExtraction, {
      EXTRACTION_RULES: extractionRules,
      STAGE_NAME: STAGE_ORDER[8],
      STAGE_PAYLOAD_JSON: serializeJson(structurePayload),
      SOURCE_TEXT: sourceText,
    }, {
      englishMode: englishCurriculumMode,
      stageLabel: STAGE_ORDER[8],
    });

    const activities = await runStage(requestId, debugDir, STAGE_ORDER[8], stage9Prompt, activitySchema, curriculumExtractionOllamaOverrides);
    normalizedStructure.activities = activities.activities || [];
    normalizedStructure.projects = activities.projects || [];
    normalizedStructure.practicals = activities.practicals || [];

    const intelligenceSchema = {
      dependency_graph: [{
        topic: "",
        prerequisites: [""],
        dependent_topics: [""],
      }],
      lesson_planning_intelligence: [{
        unit_name: "",
        chapter_name: "",
        difficulty_level: "",
        concept_density: "",
        estimated_teaching_hours: "",
        estimated_sessions: "",
        practical_requirement: "",
        assessment_requirement: "",
      }],
      validation_report: {
        structural_source_of_truth_enforced: true,
        invalid_unit_names: [""],
        invalid_chapter_names: [""],
      },
    };

    const stage10Prompt = renderPromptWithEnglishIntelligence(CURRICULUM_PROMPT_FILES.pedagogicalEnrichment, {
      EXTRACTION_RULES: extractionRules,
      STAGE_NAME: STAGE_ORDER[9],
      NORMALIZED_STRUCTURE_JSON: serializeJson(structurePayload),
      COMPETENCIES_JSON: serializeJson(competencies),
      ASSESSMENT_JSON: serializeJson(assessment),
      OUTCOMES_JSON: serializeJson(outcomes),
      ACTIVITIES_JSON: serializeJson(activities),
    }, {
      englishMode: englishCurriculumMode,
      stageLabel: STAGE_ORDER[9],
    });

    const intelligence = await runStage(requestId, debugDir, STAGE_ORDER[9], stage10Prompt, intelligenceSchema, curriculumExtractionOllamaOverrides);

    const flattenedOutcomes = uniqueStrings(
      (outcomes.learning_outcomes || []).flatMap((item: any) => item.outcomes || [])
    );

    const classNames = uniqueStrings(
      mergedNormalizedClasses.map((cls: any) => canonicalizeClassName(cls?.class_name || "")).filter(Boolean)
    );

    const normalizedMetadata = (normalizedStructure.document_metadata || {}) as Record<string, any>;
    const rawMetadata = (rawExtraction.document_metadata || {}) as Record<string, any>;
    const subject = normalizedMetadata.subject || rawMetadata.subject || "";
    const derivedPageCount = deriveDocumentPageCount(sourceText);
    const resolvedDocumentMetadata = {
      ...normalizedStructure.document_metadata,
      class: classNames.length > 1
        ? classNames.join(", ")
        : classNames[0] || normalizedMetadata.class || rawMetadata.class || "",
      grade: classNames.length > 1 ? "" : (normalizedMetadata.grade || rawMetadata.grade || ""),
      total_pages: String(
        Math.max(
          Number(normalizedMetadata.total_pages || rawMetadata.total_pages || 0),
          Number(derivedPageCount || 0)
        ) || normalizedMetadata.total_pages || rawMetadata.total_pages || derivedPageCount || ""
      ),
    };
    normalizedStructure.document_metadata = resolvedDocumentMetadata;
    faithfulStructure.document_metadata = resolvedDocumentMetadata;
    rawExtraction.document_metadata = resolvedDocumentMetadata;
    const sourceManifest = buildCurriculumSourceManifest({
      fileName,
      sourceText,
      detectedSubject: primaryDetectedSubject,
      selectedClassNames: sourceFilter.selectedClassNames.length ? sourceFilter.selectedClassNames : classNames,
      supportingDocuments: activeSupportingDocuments,
    });
    faithfulStructure = withEvidenceMetadataOnStructure(faithfulStructure, sourceManifest);
    normalizedStructure = withEvidenceMetadataOnStructure(normalizedStructure, sourceManifest);
    const units = buildCurriculumUnitsSummary([faithfulStructure, normalizedStructure]);
    const gradeLevel = [
      classNames.length > 1 ? classNames.join(" / ") : classNames[0],
      normalizedMetadata.grade,
      normalizedMetadata.stream,
    ].filter(Boolean).join(" / ") || "";

    const overallDescription = `${statistics.total_units} units, ${statistics.total_chapters} chapters, ${statistics.total_topics} topics, ${statistics.total_subtopics || 0} subtopics, and ${statistics.total_learning_outcomes || 0} learning outcomes extracted through raw extraction, document-structure hierarchy building, node enrichment, normalized teaching blocks, validation, and statistics generation.`;
    const basePayload = {
      schema_version: schemaVersion,
      curriculum_profile: detectedProfile.profile,
      curriculum_system_profile: {
        board_or_system: /cbse/i.test(primaryDetectedSubject) || /cbse/i.test(String(fileName || "")) || detectedProfile.profile.startsWith("cbse_")
          ? "CBSE"
          : "Generic K-12",
        extraction_model: "schema_first_evidence_backed_pipeline",
        extraction_stages: [
          "source_ingestion",
          "ocr_text_layer_selection",
          "layout_segmentation",
          "document_profile_classification",
          "faithful_curriculum_extraction",
          "structural_normalization",
          "validation_and_bounded_repair",
          "pedagogical_enrichment",
          "search_index_packaging",
        ],
      },
      profile_confidence: detectedProfile.confidence,
      structure_confidence: structureConfidence,
      warnings: uniqueStrings(profileWarnings.map(buildPublicWarningMessage).filter(Boolean)),
      fallbacks_used: uniqueStrings(fallbacksUsed.map(buildPublicFallbackLabel).filter(Boolean)),
      subject,
      gradeLevel,
      overallDescription,
      coreObjectives: flattenedOutcomes.slice(0, 12),
      units,
      faithful_structure: faithfulStructure,
      normalized_structure: normalizedStructure,
      planning_structure: normalizedStructure,
      normalizedStructure,
      classes: normalizedStructure.classes || [],
      document_metadata: resolvedDocumentMetadata,
      source_manifest: sourceManifest,
      search_indexes: buildCurriculumSearchIndexes({
        faithfulStructure,
        normalizedStructure,
        activities,
        outcomes,
        competencies,
      }),
      derived_intelligence: {
        competencies,
        assessment,
        learning_outcomes: outcomes,
        activities,
        intelligence,
        statistics,
      },
      stagedExtraction: {
        rawExtraction,
        faithfulStructure,
        documentHierarchy,
        nodeEnrichment,
        normalizedStructure,
        hierarchyComparison,
        structuralValidation: validationReport,
        statistics,
        competencies,
        assessment,
        learningOutcomes: outcomes,
        activities,
        intelligence,
      },
    };
    const finalPayload = buildVersionedCurriculumPayload(schemaVersion, basePayload, {
      structureType: profileConfig.expectedStructureType,
      terms: (stage1Facts as any)?.terms || [],
      competenciesCatalog: (stage1Facts as any)?.competencies || [],
    });
    const finalFilteredPayload = requestedSelectedClasses.length > 0
      ? filterCurriculumToSelectedClasses(finalPayload, requestedSelectedClasses).curriculum
      : finalPayload;
    assertSelectedClassIsolation(
      finalFilteredPayload,
      requestedSelectedClasses,
      "analysis response curriculum"
    );
    const detectedClasses = summarizeCurriculumClasses(finalFilteredPayload);
    const responsePayload: any = {
      success: true,
      curriculum: finalFilteredPayload,
      detectedClasses,
      requiresClassSelection: detectedClasses.length > 1,
      detectedSubject: primaryDetectedSubject,
      requiresTamilIndex: earlyTamilMode,
      requestId,
    };
    if (persist) {
      const { curriculum: savedCurriculum, planningWorkspace } = await persistCurriculumRecord({
        fileName,
        sourceText,
        extractedCurriculum: finalFilteredPayload,
        extractionMetadata: {
          requestId,
          sourceTextLength: sourceText.length,
          stage1UnitCount,
          stage1ChapterCount,
          selectedClassNames: sourceFilter.selectedClassNames,
          detectedSubject: primaryDetectedSubject,
          tamilNormalizationMetadata,
          sourceDocuments: [
            {
              role: "primary_curriculum",
              fileName: String(fileName || ""),
              filteredBySelectedClasses: sourceFilter.filtered,
            },
            ...activeSupportingDocuments.map((document) => ({
              role: document.role,
              fileName: document.fileName,
            })),
          ],
        },
      });
      responsePayload.curriculumId = String(savedCurriculum._id);
      responsePayload.workspaceId = String(planningWorkspace._id);
      responsePayload.workspace = planningWorkspace;
    }
    await writeDebugFile(debugDir, "final-response.json", responsePayload);
    console.log(`[Request][${requestId}] Final response JSON length: ${JSON.stringify(responsePayload).length}`);
    res.json(responsePayload);
  } catch (error: any) {
    console.error(`[Request][${requestId}] Curriculum extraction failed:`, error);
    const userFriendlyMessage =
      error instanceof OllamaRequestError
        ? error.message
        : error?.message || "Curriculum extraction failed.";
    await writeDebugFile(debugDir, "error.json", {
      message: userFriendlyMessage,
      stack: error?.stack || "",
      code: error?.code || "",
    });
    res.status(500).json({ error: userFriendlyMessage });
  }
});

app.post("/api/divide-terms", async (req, res) => {
  const { curriculum, termCount, preferred_term_count } = req.body;
  if (!curriculum) {
    return res.status(400).json({ error: "No curriculum structure provided." });
  }
  const requestId = makeRequestId("divide-terms");
  const debugDir = await ensureDebugDir(requestId);
  await writeDebugFile(debugDir, "request-body.json", req.body);
  try {
    assertCurriculumReadyForPlanning(curriculum);
    const normalizedStructure = getNormalizedStructureFromCurriculum(curriculum);
    const normalizedClasses = normalizedStructure?.classes || [];
    const classTermPlans = normalizedClasses.length > 1
      ? normalizedClasses.map((cls: any) => {
          const classNormalizedStructure = {
            ...normalizedStructure,
            classes: [cls],
          };
          const classPlan = buildTermDivision(
            classNormalizedStructure,
            preferred_term_count ?? termCount
          );
          return {
            class_name: cls?.class_name || "",
            ...classPlan,
          };
        })
      : [{
          class_name: normalizedClasses[0]?.class_name || "",
          ...buildTermDivision(
            normalizedStructure,
            preferred_term_count ?? termCount
          ),
        }];
    await writeDebugFile(debugDir, "term-division.json", classTermPlans);
    const invalidClassPlans = classTermPlans.filter((plan: any) => !plan.validation.valid);
    if (invalidClassPlans.length) {
      const allErrors = invalidClassPlans.flatMap((plan: any) =>
        (plan.validation.errors || []).map((error: string) => `${plan.class_name || "Unknown Class"}: ${error}`)
      );
      throw new Error(`Term division validation failed: ${allErrors.join(" | ")}`);
    }
    const legacyRows = classTermPlans.flatMap((plan: any) => flattenTermDivisionToRows(plan));
    const totalMarks = classTermPlans.reduce((sum: number, plan: any) => sum + toNumberOrZero(plan?.statistics?.total_marks), 0);
    const responsePayload = {
      class_term_plans: classTermPlans,
      term_count: classTermPlans.length === 1 ? classTermPlans[0].term_count : undefined,
      statistics: {
        total_marks: Number(totalMarks.toFixed(2)),
      },
      rows: legacyRows,
    };
    await writeDebugFile(debugDir, "final-response.json", responsePayload);
    res.json(responsePayload);
  } catch (error: any) {
    console.error(`[Request][${requestId}] Term division failed:`, error);
    res.status(500).json({ error: error?.message || "Term division failed." });
  }
});

