app.get("/api/student/notes", async (req, res) => {
  try {
    res.set({
      "Cache-Control": "no-store, no-cache, must-revalidate, proxy-revalidate",
      Pragma: "no-cache",
      Expires: "0",
      "Surrogate-Control": "no-store",
    });

    await connectToMongo();
    const userId = String(req.query.userId || "").trim();
    const schoolId = String(req.query.schoolId || "").trim();

    if (!userId || !schoolId) {
      res.status(400).json({ error: "userId and schoolId are required." });
      return;
    }

    const student = await UserModel.findOne({ _id: userId, schoolId, role: "student" }).lean();
    if (!student) {
      res.status(404).json({ error: "Student not found." });
      return;
    }

    const classAliases = buildStudentWorkspaceClassAliases(student);
    const sectionKey = normalizeSectionKey(student.section || "");

    const workspaces = await PlanningWorkspaceModel.find({ schoolId }).lean();
    const items = workspaces.flatMap((workspace: any) => {
      const workspaceClassAliases = [
        workspace.classId,
        workspace.academicConfig?.className,
        workspace.curriculumSnapshot?.gradeLevel,
        workspace.academicConfig?.section && workspace.academicConfig?.className
          ? `${workspace.academicConfig.className} - Section ${workspace.academicConfig.section}`
          : "",
      ].filter(Boolean);

      const classMatches =
        workspaceClassAliases.length === 0 ||
        workspaceClassAliases.some((value) => matchesAnyClassAlias(value, classAliases));
      const workspaceSectionKey = normalizeSectionKey(workspace?.academicConfig?.section || workspace?.sectionId || "");
      const sectionMatches = !sectionKey || !workspaceSectionKey || workspaceSectionKey === sectionKey;

      if (!classMatches || !sectionMatches) {
        return [];
      }

      const generatedSessions =
        workspace.generationScope?.generatedSessions &&
        typeof workspace.generationScope.generatedSessions === "object"
          ? workspace.generationScope.generatedSessions as Record<string, any>
          : {};
      const studentPublications =
        workspace.generationScope?.studentPublications &&
        typeof workspace.generationScope.studentPublications === "object"
          ? workspace.generationScope.studentPublications as Record<string, Record<string, any>>
          : {};

      return Object.entries(studentPublications).flatMap(([publicationSessionKey, publicationEntry]: [string, any]) => {
        const generatedSessionKey = String(publicationSessionKey || "").trim();
        if (!generatedSessionKey) {
          return [];
        }

        const session =
          generatedSessions[generatedSessionKey] ||
          generatedSessions[String((publicationEntry as any)?.notes?.generatedSessionKey || "").trim()] ||
          null;
        if (!session || !session.studentLessonNotes) {
          return [];
        }

        const item = buildCanonicalPublicationItem({
          workspace,
          generatedSessionKey,
          session,
          student,
          publicationValue: publicationEntry?.notes,
          kind: "notes",
          schoolId,
        });

        return item ? [item] : [];
      });
    });

    const dedupedItems = Array.from(
      new Map(
        items.map((item: any) => [
          `${String(item?.kind || "").toLowerCase()}::${String(item?.workspaceId || "").toLowerCase()}::${String(item?.generatedSessionKey || "").toLowerCase()}::${String(item?.classId || "").toLowerCase()}::${String(item?.section || "").toLowerCase()}`,
          item,
        ]),
      ).values(),
    ).sort((left: any, right: any) => Number(left?.sessionNumber || 0) - Number(right?.sessionNumber || 0));

    res.json({ success: true, items: dedupedItems });
  } catch (error: any) {
    console.error("[Student] Notes fetch failed:", error);
    res.status(500).json({ error: error?.message || "Failed to load student notes." });
  }
});

app.get("/api/student/published-content", async (req, res) => {
  try {
    await connectToMongo();
    const userId = String(req.query.userId || "").trim();
    const schoolId = String(req.query.schoolId || "").trim();
    const kind = String(req.query.kind || "").trim().toLowerCase();

    if (!userId || !schoolId) {
      res.status(400).json({ error: "userId and schoolId are required." });
      return;
    }

    if (kind && !["homework", "assessments", "quizzes", "notes"].includes(kind)) {
      res.status(400).json({ error: "kind must be homework, assessments, quizzes, or notes." });
      return;
    }

    const student = await UserModel.findOne({ _id: userId, schoolId, role: "student" }).lean();
    if (!student) {
      res.status(404).json({ error: "Student not found." });
      return;
    }

    const classAliases = buildStudentWorkspaceClassAliases(student);
    const sectionKey = normalizeSectionKey(student.section || "");

    const workspaces = await PlanningWorkspaceModel.find({ schoolId }).lean();
    const items = workspaces.flatMap((workspace: any) => {
      const workspaceClassAliases = [
        workspace.classId,
        workspace.academicConfig?.className,
        workspace.curriculumSnapshot?.gradeLevel,
        workspace.academicConfig?.section && workspace.academicConfig?.className
          ? `${workspace.academicConfig.className} - Section ${workspace.academicConfig.section}`
          : "",
      ].filter(Boolean);

      const classMatches =
        workspaceClassAliases.length === 0 ||
        workspaceClassAliases.some((value) => matchesAnyClassAlias(value, classAliases));
      const workspaceSectionKey = normalizeSectionKey(workspace?.academicConfig?.section || workspace?.sectionId || "");
      const sectionMatches = !sectionKey || !workspaceSectionKey || workspaceSectionKey === sectionKey;

      if (!classMatches || !sectionMatches) {
        return [];
      }

      const generatedSessions =
        workspace.generationScope?.generatedSessions &&
        typeof workspace.generationScope.generatedSessions === "object"
          ? workspace.generationScope.generatedSessions as Record<string, any>
          : {};
      const studentPublications =
        workspace.generationScope?.studentPublications &&
        typeof workspace.generationScope.studentPublications === "object"
          ? workspace.generationScope.studentPublications as Record<string, Record<string, any>>
          : {};

      return Object.entries(studentPublications).flatMap(([publicationSessionKey, publicationEntry]: [string, any]): any[] => {
        const generatedSessionKey = String(publicationSessionKey || "").trim();
        if (!generatedSessionKey) {
          return [];
        }

        const targetKinds = kind
          ? [kind]
          : (["homework", "assessments", "quizzes", "notes"] as const);

        return targetKinds.flatMap((targetKind) => {
          const publicationValue = (publicationEntry as any)?.[targetKind];
          const session =
            generatedSessions[generatedSessionKey] ||
            generatedSessions[String(publicationValue?.generatedSessionKey || "").trim()] ||
            null;
          if (!session) {
            return [];
          }

          const item = buildCanonicalPublicationItem({
            workspace,
            generatedSessionKey,
            session,
            student,
            publicationValue,
            kind: targetKind,
            schoolId,
          });

          return item ? [item] : [];
        });
      });
    });

    const dedupedItems = Array.from(
      new Map(
        items.map((item: any) => [
          [
            String(item?.kind || "").trim().toLowerCase(),
            String(item?.teacherId || "").trim().toLowerCase(),
            String(item?.workspaceId || "").trim().toLowerCase(),
            String(item?.section || "").trim().toLowerCase(),
            String(item?.subject || "").trim().toLowerCase(),
            String(item?.generatedSessionKey || item?.sessionId || "").trim().toLowerCase() || `session-${Number(item?.sessionNumber || 0)}`,
            String(item?.sessionTitle || "").trim().toLowerCase(),
          ].join("::"),
          item,
        ]),
      ).values(),
    ).sort((left: any, right: any) => {
      const sessionDelta = Number(left?.sessionNumber || 0) - Number(right?.sessionNumber || 0);
      if (sessionDelta !== 0) {
        return sessionDelta;
      }
      return String(left?.sessionTitle || "").localeCompare(String(right?.sessionTitle || ""));
    });

    res.json({ success: true, items: dedupedItems });
  } catch (error: any) {
    console.error("[Student] Published content fetch failed:", error);
    res.status(500).json({ error: error?.message || "Failed to load published student content." });
  }
});

app.patch("/api/planning-workspaces/:id/student-publications", async (req, res) => {
  try {
    const workspace = await loadPlanningWorkspaceById(req.params.id);
    if (!workspace) {
      return res.status(404).json({ error: "Planning workspace not found." });
    }

    const sessionKey = String(req.body?.sessionKey || "").trim();
    const kind = String(req.body?.kind || "").trim();
    const published = Boolean(req.body?.published);
    if (!sessionKey || !["homework", "assessments", "quizzes", "notes"].includes(kind)) {
      return res.status(400).json({ error: "sessionKey and valid kind are required." });
    }

    const generatedSessions =
      workspace.generationScope?.generatedSessions &&
      typeof workspace.generationScope.generatedSessions === "object"
        ? workspace.generationScope.generatedSessions as Record<string, any>
        : {};
    const requestedSessionNumber = Number(req.body?.sessionNumber || 0);
    const resolvedSessionNumber = Number.isFinite(requestedSessionNumber) && requestedSessionNumber > 0
      ? requestedSessionNumber
      : 0;
    const fallbackKeys = [
      sessionKey,
      String(req.body?.generatedSessionKey || "").trim(),
      String(req.body?.sessionId || "").trim(),
      String(resolvedSessionNumber || ""),
      resolvedSessionNumber > 0 ? `session-number:${resolvedSessionNumber}` : "",
    ].filter(Boolean);

    let resolvedGeneratedSessionKey = "";
    let session = null as any;

    for (const candidateKey of fallbackKeys) {
      if (generatedSessions[candidateKey]) {
        resolvedGeneratedSessionKey = candidateKey;
        session = generatedSessions[candidateKey];
        break;
      }
    }

    if (!session && resolvedSessionNumber > 0) {
      for (const [savedKey, savedSession] of Object.entries(generatedSessions)) {
        if (!savedSession || typeof savedSession !== "object") {
          continue;
        }

        if (
          String(savedSession?.sessionKey || "").trim() === sessionKey ||
          String(savedSession?.id || "").trim() === sessionKey ||
          Number(savedSession?.sessionNumber || 0) === resolvedSessionNumber
        ) {
          resolvedGeneratedSessionKey = savedKey;
          session = savedSession;
          break;
        }
      }
    }

    if (!session) {
      const matchedEntry = findMatchingGeneratedSessionEntry(generatedSessions, {
        requestedSessionKey: sessionKey,
        roadmapSessionNumber: resolvedSessionNumber,
        chapterName: String(req.body?.chapterName || "").trim(),
        sessionTitle: String(req.body?.sessionTitle || "").trim(),
        subject: String(req.body?.subjectName || workspace.academicConfig?.subject || workspace.curriculumSnapshot?.subject || "").trim(),
        gradeLevel: String(req.body?.grade || workspace.academicConfig?.className || workspace.curriculumSnapshot?.gradeLevel || "").trim(),
        sessionNumber: resolvedSessionNumber,
      });

      if (matchedEntry?.sessionPlan) {
        resolvedGeneratedSessionKey = matchedEntry.key;
        session = matchedEntry.sessionPlan;
      }
    }

    if (!session) {
      return res.status(404).json({ error: "Generated session not found for the provided sessionKey." });
    }
    if (!resolvedGeneratedSessionKey) {
      resolvedGeneratedSessionKey = sessionKey;
    }

    const nextGenerationScope =
      workspace.generationScope && typeof workspace.generationScope === "object"
        ? { ...workspace.generationScope }
        : {};
    const nextStudentPublications =
      nextGenerationScope.studentPublications && typeof nextGenerationScope.studentPublications === "object"
        ? { ...nextGenerationScope.studentPublications }
        : {};
    const currentFlags =
      nextStudentPublications[resolvedGeneratedSessionKey] && typeof nextStudentPublications[resolvedGeneratedSessionKey] === "object"
        ? { ...nextStudentPublications[resolvedGeneratedSessionKey] }
        : {};

    const currentPublicationValue = currentFlags[kind];
    const previousPublishedAt =
      currentPublicationValue && typeof currentPublicationValue === "object"
        ? String((currentPublicationValue as { publishedAt?: string | null }).publishedAt || "").trim()
        : "";
    const sessionNumber =
      resolvedSessionNumber ||
      resolvePublishedSessionNumber(session, resolvedGeneratedSessionKey);

    currentFlags[kind] = {
      published,
      publishedAt: published
        ? previousPublishedAt || new Date().toISOString()
        : null,
      workspaceId: String(workspace._id || "").trim(),
      generatedSessionKey: resolvedGeneratedSessionKey,
      sessionNumber,
      sessionTitle: String(req.body?.sessionTitle || session?.title || session?.sessionTitle || "").trim(),
      subjectId: String(req.body?.subjectId || workspace.subjectId || "").trim(),
      subjectName: String(req.body?.subjectName || workspace.academicConfig?.subject || workspace.curriculumSnapshot?.subject || "").trim(),
      classId: String(req.body?.classId || workspace.classId || workspace.academicConfig?.className || workspace.curriculumSnapshot?.gradeLevel || "").trim(),
      grade: String(req.body?.grade || workspace.academicConfig?.className || workspace.curriculumSnapshot?.gradeLevel || "").trim(),
      section: String(req.body?.section || workspace.academicConfig?.section || workspace.sectionId || "").trim(),
      termNumber: Number(req.body?.termNumber || workspace.sessionAllocation?.selectedTermSummary?.termNumber || 0) || null,
      contentType: kind,
    };

    if (resolvedGeneratedSessionKey !== sessionKey && nextStudentPublications[sessionKey] && nextStudentPublications[sessionKey] !== currentFlags) {
      delete nextStudentPublications[sessionKey];
    }
    nextStudentPublications[resolvedGeneratedSessionKey] = currentFlags;
    nextGenerationScope.studentPublications = nextStudentPublications;
    workspace.generationScope = nextGenerationScope;

    await workspace.save();
    res.json({ success: true, studentPublications: nextStudentPublications });
  } catch (error: any) {
    console.error("[PlanningWorkspaces] Student publication update failed:", error);
    res.status(500).json({ error: error?.message || "Failed to update student publication state." });
  }
});

// POST endpoint to upsert a published student artifact
app.post("/api/student/published-content", async (req, res) => {
  try {
    await connectToMongo();
    const schoolId = String(req.body?.schoolId || "").trim();
    const artifact = req.body?.artifact;

    if (!schoolId || !artifact) {
      return res.status(400).json({ error: "schoolId and artifact are required." });
    }

    // Find the workspace that contains this session
    const sessionId = String(artifact?.sessionId || "").trim();
    const sessionNumber = Number(artifact?.sessionNumber || 0);
    const kind = String(artifact?.kind || "").trim();

    if (!sessionId && !sessionNumber) {
      return res.status(400).json({ error: "sessionId or sessionNumber is required." });
    }

    // Search for the workspace containing this session
    const workspaces = await PlanningWorkspaceModel.find({ schoolId }).lean();
    let targetWorkspace: any = null;
    let targetSessionKey = "";

    for (const workspace of workspaces) {
      const generatedSessions = workspace.generationScope?.generatedSessions;
      if (!generatedSessions || typeof generatedSessions !== "object") continue;

      for (const [key, session] of Object.entries(generatedSessions as Record<string, any>)) {
        const matchesSessionId = sessionId && String(session?.id || "").trim() === sessionId;
        const matchesSessionNumber = sessionNumber > 0 && Number(session?.sessionNumber || 0) === sessionNumber;
        const matchesKey = sessionId && key === sessionId;

        if (matchesSessionId || matchesSessionNumber || matchesKey) {
          targetWorkspace = await PlanningWorkspaceModel.findOne({ _id: workspace._id });
          targetSessionKey = key;
          break;
        }
      }
      if (targetWorkspace) break;
    }

    if (!targetWorkspace || !targetSessionKey) {
      return res.status(404).json({ error: "Session not found in any workspace." });
    }

    // Update the publication flags
    const nextGenerationScope = targetWorkspace.generationScope && typeof targetWorkspace.generationScope === "object"
      ? { ...targetWorkspace.generationScope }
      : {};
    const nextStudentPublications = nextGenerationScope.studentPublications && typeof nextGenerationScope.studentPublications === "object"
      ? { ...nextGenerationScope.studentPublications }
      : {};
    const currentFlags = nextStudentPublications[targetSessionKey] && typeof nextStudentPublications[targetSessionKey] === "object"
      ? { ...nextStudentPublications[targetSessionKey] }
      : {};

    currentFlags[kind] = { published: true, publishedAt: new Date().toISOString() };
    nextStudentPublications[targetSessionKey] = currentFlags;
    nextGenerationScope.studentPublications = nextStudentPublications;
    targetWorkspace.generationScope = nextGenerationScope;

    await targetWorkspace.save();
    res.json({ success: true, studentPublications: nextStudentPublications });
  } catch (error: any) {
    console.error("[Student] Published content upsert failed:", error);
    res.status(500).json({ error: error?.message || "Failed to upsert published content." });
  }
});

